export function localizedAgentGuidesPartO(en: Guides): Partial<Record<LandingLocaleCode, Guides>> {
  return {
    'uk': {
      'claude-code': {
        ...en['claude-code']!,
        title: "Claude Code для дизайну — Open Design",
        description: "Як дизайнери використовують Claude Code для UI та вебдизайну, і як Open Design перетворює його на справжнього дизайн-агента — local-first, BYOK, із кураторською бібліотекою skill-ів і дизайн-систем.",
        breadcrumb: "Claude Code",
        label: "Агент · Claude Code",
        heading: "Claude Code для дизайну.",
        lead: "Claude Code — це термінальний агент для кодування від Anthropic. Люди вже використовують його для створення UI, дизайн-систем і лендингів. Open Design вбудовує його в повноцінний дизайн-процес — підключіть свій ключ Anthropic або підписку Claude, тримайте кожен файл локально.",
        rich: {"heroCtaLead": "Open Design перетворює Claude Code на local-first дизайн-агента з відкритим кодом — ваш ключ Anthropic або підписка Claude, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Claude Code широко вважають агентом для кодування з найкращим смаком до фронтенду — він міркує про інтерфейси з незвичною точністю, називаючи конкретні значення hex, відступи й типографічні шкали, і рефакторить UI у великій кодовій базі, не втрачаючи нитки. Але «з коробки» він усе ще тяжіє до загального вигляду, доки ви не дасте йому дизайн-систему, skill-и та реальні референси. Це практичний наскрізний посібник з використання Claude Code для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований процес разом з Open Design.", "Тут розглядається, чим насправді є Claude Code, чому він сильний у фронтенді, як налаштувати його з нуля, робочий процес із CLAUDE.md і Skills, офіційний двосторонній обмін із Figma, як він порівнюється з Codex і Cursor, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/claude-code-design/claude-code-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну Claude Code: термінальний агент, що ухвалює конкретні дизайн-рішення, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: Claude Code продумує конкретні UI-рішення в терміналі, рендерить і перевіряє їх у справжньому браузері та сходиться до ваших референсів."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-claude-code", "label": "Чим насправді є Claude Code"}, {"id": "why-design", "label": "Чому Claude Code добрий у дизайні"}, {"id": "setup", "label": "Налаштування Claude Code для дизайну (з нуля)"}, {"id": "skills-workflow", "label": "Робочий процес із CLAUDE.md і Skills"}, {"id": "figma", "label": "Двосторонній обмін Claude Code + Figma"}, {"id": "vs", "label": "Claude Code проти Codex проти Cursor"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Claude Code в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-claude-code", "heading": "Чим насправді є Claude Code", "blocks": [{"kind": "p", "text": "Claude Code — це агентний інструмент кодування від Anthropic. Він читає вашу кодову базу, редагує файли, виконує команди й інтегрується з вашими інструментами розробки — планує, пише та перевіряє роботу за завданнями природною мовою, а не просто автодоповнює рядки."}, {"kind": "p", "text": "Він постачається на кількох поверхнях, що мають один і той самий рушій: термінальний CLI, розширення IDE для VS Code, Cursor і JetBrains, десктопний застосунок з візуальним переглядом diff та вебдосвід для тривалих завдань. Ваші файли CLAUDE.md, налаштування та сервери MCP переносяться між усіма ними."}, {"kind": "steps", "items": [{"label": "Файл інструкцій", "body": "Claude Code читає файл CLAUDE.md у корені проєкту на початку кожної сесії — природне місце, щоб закодувати ваші дизайн-конвенції, tokens і чеклісти рев'ю."}, {"label": "Skills", "body": "Agent Skills упаковують повторювані інструкції, скрипти та ресурси, які Claude завантажує за потреби, включно з офіційним Frontend Design skill від Anthropic для смаку."}, {"label": "План і субагенти", "body": "Він може планувати перед дією та породжувати субагентів, що працюють над різними частинами завдання паралельно, завдяки чому великі рефактори UI лишаються узгодженими."}]}, {"kind": "ul", "items": ["Постачальник: Anthropic", "Облікові дані: API-ключ Anthropic (BYOK, через Console) або підписка Claude (Pro / Max)", "Поверхні: термінальний CLI, розширення VS Code / Cursor / JetBrains, десктопний застосунок, веб"]}]}, {"id": "why-design", "heading": "Чому Claude Code добрий у дизайні", "blocks": [{"kind": "p", "text": "Серед агентів для кодування Claude Code має репутацію смакового у фронтенд-роботі. Це пояснюється кількома речами."}, {"kind": "steps", "items": [{"label": "Конкретні, а не розпливчасті рішення", "body": "Claude Code схильний обирати конкретні варіанти — точні значення hex, шкали відступів, типографічні градації та ієрархію компонентів — замість відмахування, і саме це відрізняє справжній інтерфейс від заглушки."}, {"label": "Міркування з урахуванням кодової бази", "body": "Маючи великий робочий контекст, він рефакторить UI одразу в багатьох файлах, повторно використовуючи ваші наявні компоненти й tokens замість того, щоб винаходити одноразові стилі."}, {"label": "Офіційний frontend skill", "body": "Anthropic постачає Frontend Design skill, який змушує Claude спершу написати дизайн-напрямок і свідомо уникати загальних системних шрифтів та передбачуваних фіолетових градієнтів."}]}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок той самий, що його Anthropic робить про власні моделі: Claude не має смаку за замовчуванням — наданий сам собі, він сходиться до статистичного центру вебдизайну (Inter, фіолетові градієнти, м'які тіні). Він створює добрий дизайн, коли ви даєте йому обмеження. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Claude Code для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Claude Code, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Claude Code (native install, recommended)\ncurl -fsSL https://claude.ai/install.sh | bash\n# or: brew install --cask claude-code\n# Windows PowerShell: irm https://claude.ai/install.ps1 | iex\n\n# 2. Start it in your project and sign in on first run\ncd your-project\nclaude            # sign in with your Claude subscription or API key\n\n# 3. Generate project context\n/init             # creates a CLAUDE.md for this project\n\n# 4. Add the official Frontend Design skill\nclaude plugin install frontend-design@claude-plugins-official\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\nclaude plugin install figma@claude-plugins-official"}, {"kind": "image", "src": "/agents/claude-code-design/claude-code-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування CLAUDE.md, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування CLAUDE.md → додавання Frontend Design skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в CLAUDE.md і вкажіть на них Claude, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або Chrome MCP, щоб Claude рендерив у справжньому браузері та перевіряв свій вивід на різних брейкпойнтах, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "skills-workflow", "heading": "Робочий процес із CLAUDE.md і Skills", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Claude Code — це подавати йому реальні референси разом із вашим дизайн-контекстом, а потім ітерувати, доки UI не збіжиться — при цьому CLAUDE.md і Skills несуть обмеження, тож вам не доводиться пояснювати їх заново в кожному промпті."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI навіть із сильним агентом.", "Тримайте свою дизайн-систему й конвенції в CLAUDE.md і кажіть Claude, де живуть tokens і канонічні примітиви.", "Додайте Frontend Design skill, щоб Claude обрав реальний естетичний напрямок перед написанням коду.", "Підключіть перевірку в браузері, щоб Claude рендерив, змінював розмір під брейкпойнти й порівнював із референсами — а не лише підтверджував, що збірка проходить."]}, {"kind": "p", "text": "Перетягніть референсне зображення в сесію та задайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "claude \"Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse the design-system components and tokens described in CLAUDE.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser, verify it matches the references across\n  breakpoints, and iterate until it does.\""}, {"kind": "p", "text": "Запускайте dev-сервер поруч, тримайте промпти невеликими й сфокусованими та комітьте вдалі ітерації / відкочуйте невдалі (кажучи Claude, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі. Використовуйте режим планування для більших рефакторів, щоб переглянути підхід до будь-яких змін у файлах."}]}, {"id": "figma", "heading": "Claude Code + Figma: двосторонній обмін дизайн ↔ код", "blocks": [{"kind": "p", "text": "У лютому 2026 року Anthropic і Figma випустили першокласну двонапрямлену інтеграцію через сервер Figma MCP. Вона працює в обидва боки."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Виберіть фрейм у Figma або вставте посилання в Claude Code, підтягніть дизайн-контекст і попросіть реалізувати дизайн із вашою наявною бібліотекою компонентів. Code Connect тримає вивід узгодженим із вашими реальними компонентами."}, {"label": "Код → Дизайн", "body": "Зберіть і перегляньте функцію в браузері, а потім скажіть «Send this to Figma», щоб зафіксувати робочий UI як редаговані шари Figma — увесь екран або вибраний елемент."}]}, {"kind": "p", "text": "Встановіть її одного разу за допомогою claude plugin install figma@claude-plugins-official (Dev Mode MCP вимагає платного плану Figma). Той самий Figma MCP доступний для Claude Code, Codex, Cursor і VS Code — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Claude Code проти Codex проти Cursor для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX-міркування з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"], ["Codex", "Сильне візуальне опрацювання й розуміння зображень; асинхронні збірки в пісочниці", "Делеговані асинхронні збірки та переносні правила AGENTS.md"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Навіть із репутацією Claude Code за смак найпоширеніша скарга на дизайн, згенерований ШІ, — що він виглядає загальним: шрифти Inter, фіолетові градієнти на білому, м'які тіні, завеликі заокруглені кути, естетика, яка «кричить, що це зробив ШІ». Сама Anthropic пояснює це збіжністю розподілу: безпечні рішення домінують у тренувальних даних вебу. Серед інших повідомлених проблем — поламані мобільні розкладки та інструкції, що протікають у текст UI."}, {"kind": "steps", "items": [{"label": "Встановіть Frontend Design skill", "body": "Він змушує Claude обрати реальний напрямок і явно уникає шрифтів та градієнтів, надмірно вживаних ШІ."}, {"label": "Увімкніть перевірку в браузері", "body": "Змусьте Claude рендерити й самоперевірятися на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в CLAUDE.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Claude Code всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Claude Code як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Claude Code добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Claude Code як свого агента.", "Автентифікуйтеся своїм API-ключем Anthropic (BYOK) або підпискою Claude — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Claude Code, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи добрий Claude Code для дизайн-роботи?", "text": "Так — його широко вважають агентом для кодування з найкращим смаком до фронтенду, що ухвалює конкретні рішення з урахуванням кодової бази щодо значень hex, відступів і типографічних шкал. Зі skill-ом Frontend Design, дизайн-системою та реальними референсними зображеннями в контексті він створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Чи потрібна мені підписка Claude, щоб проєктувати з Claude Code?", "text": "Ви можете використовувати або API-ключ Anthropic (BYOK, через Console), або підписку Claude (Pro / Max). У будь-якому разі Open Design ніколи не проксіює ваші облікові дані — їх безпосередньо використовує ваш агент на вашій машині."}, {"name": "Claude Code чи Codex для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази та фронтенд-міркуваннями; Codex має сильне візуальне опрацювання й чудово справляється з делегованими збірками в пісочниці. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Claude Code до Figma?", "text": "Встановіть офіційний плагін Figma командою claude plugin install figma@claude-plugins-official. Тоді ви зможете реалізовувати фрейми Figma в коді, використовуючи дизайн-контекст, і відправляти робочий UI назад у редаговані фрейми Figma за допомогою «Send this to Figma». Dev Mode MCP вимагає платного плану Figma."}, {"name": "Що таке Skills і CLAUDE.md?", "text": "CLAUDE.md — це markdown-файл у корені проєкту, який Claude Code читає на початку кожної сесії — місце, щоб закодувати ваші дизайн-конвенції. Skills упаковують повторювані інструкції та ресурси, які Claude завантажує за потреби, включно з офіційним Frontend Design skill від Anthropic. Open Design постачає кураторську бібліотеку обох, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Встановіть Frontend Design skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в CLAUDE.md та увімкніть перевірку в браузері. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з Anthropic?", "text": "Ні. Claude Code — продукт Anthropic; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. Claude і Claude Code — торгові марки Anthropic."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first і Apache-2.0. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Anthropic використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Claude Code, відкрито.", "ctaBody": "Підключіть власний ключ Anthropic або підписку Claude, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Claude Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'codex': {
        ...en['codex']!,
        title: "Codex для дизайну — Open Design",
        description: "Як люди використовують OpenAI Codex для UI та вебдизайну — плагін Product Design, інтеграцію з Figma, фронтенд-skill-и — і як Open Design перетворює Codex на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "Codex",
        label: "Агент · Codex",
        heading: "Codex для дизайну.",
        lead: "Codex — це агент для кодування від OpenAI. Із плагіном Product Design та інтеграцією Figma він став серйозним дизайн-інструментом. Open Design вбудовує Codex у дизайн-процес з відкритим кодом — ваш ключ OpenAI або підписка ChatGPT, ваші файли, local-first.",
        rich: {"heroCtaLead": "Open Design перетворює Codex на local-first дизайн-агента з відкритим кодом — ваш ключ OpenAI, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenAI Codex починався як генератор коду, але у 2026 році став надійним інструментом для проєктування справжніх інтерфейсів — щойно ви даєте йому правильні референси, skill-и та цикл перевірки. Це практичний наскрізний посібник з використання Codex для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим є Codex сьогодні, чому він раптом став добрим у фронтенді, як налаштувати його з нуля, цикл «скриншот → UI», офіційний двосторонній обмін із Figma, як він порівнюється з Cursor і Claude Code, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/codex-design/codex-design-workflow-loop.webp", "alt": "Цикл зворотного зв'язку дизайну Codex: термінальний агент, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: Codex будує UI у терміналі, рендерить і перевіряє його у справжньому браузері та ітерує до ваших референсів."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-codex", "label": "Чим насправді є OpenAI Codex"}, {"id": "why-design", "label": "Чому Codex тепер добрий у дизайні"}, {"id": "setup", "label": "Налаштування Codex для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "figma", "label": "Двосторонній обмін Codex + Figma"}, {"id": "vs", "label": "Codex проти Cursor проти Claude Code"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Codex в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-codex", "heading": "Чим насправді є OpenAI Codex (і чим він не є)", "blocks": [{"kind": "p", "text": "Спершу — уточнення, яке збиває з пантелику майже всіх, хто шукає «Codex». Початковий OpenAI Codex був моделлю автодоповнення коду 2021 року, що живила ранній GitHub Copilot і була виведена з експлуатації у 2023 році. Ця сторінка не про неї. Сьогоднішній Codex — це агентний інструмент кодування від OpenAI: він планує, пише, виконує й перевіряє код за завданнями природною мовою."}, {"kind": "p", "text": "Сучасний Codex постачається на чотирьох поверхнях: термінальний CLI (переписаний на Rust, під ліцензією Apache-2.0), розширення IDE для VS Code, Cursor і Windsurf, хмарний/вебдосвід для делегованих асинхронних завдань і десктопний застосунок із вбудованим браузером та Computer Use."}, {"kind": "steps", "items": [{"label": "Модель за замовчуванням", "body": "Станом на середину 2026 року рекомендована модель — gpt-5.5, а gpt-5.4 — це модель, яку OpenAI явно тренувала для фронтенду й роботи з комп'ютером."}, {"label": "Файл інструкцій", "body": "Codex читає файл AGENTS.md у вашому проєкті (міжінструментальний стандарт) для правил проєкту — природне місце, щоб закодувати ваші дизайн-конвенції."}, {"label": "Пісочниця", "body": "Він працює в пісочниці рівня ядра (workspace-write за замовчуванням), тож агент, що редагує ваш UI, не може вийти за межі проєкту."}]}, {"kind": "ul", "items": ["Постачальник: OpenAI", "Облікові дані: API-ключ OpenAI (BYOK) або підписка ChatGPT (Free / Go / Plus / Pro / Business / Enterprise)", "Ліцензія CLI: Apache-2.0, відкритий код"]}]}, {"id": "why-design", "heading": "Чому Codex тепер добрий у дизайні", "blocks": [{"kind": "p", "text": "На початку 2026 року зійшлися три речі, що зробили Codex справжнім дизайн-інструментом, а не загальним генератором коду."}, {"kind": "steps", "items": [{"label": "Модель, натренована для фронтенду", "body": "OpenAI випустила GPT-5.4 — свою першу основну модель, натреновану для фронтенду й роботи з комп'ютером, із набагато кращим розумінням зображень у дизайн-процесі та сильнішою самоперевіркою. Вона навіть може генерувати mood-борди та візуальні варіанти перед тим, як обрати фінальні ассети."}, {"label": "Офіційний frontend skill", "body": "Каталог openai/skills постачає кураторський frontend-skill, що нав'язує реальний смак: розкладки без карток, повноширинні hero-блоки, ієрархія за брендом, стриманий рух, щонайбільше два шрифти й один акцентний колір — і змушує Codex написати візуальну тезу перед побудовою."}, {"label": "Перевірка в браузері", "body": "Зі skill-ом Playwright Codex відкриває справжній браузер, змінює розмір під брейкпойнти й порівнює свій вивід із референсом, а не лише перевіряє, що збірка проходить."}]}, {"kind": "image", "src": "/agents/codex-design/codex-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок за всіма трьома: Codex не має смаку за замовчуванням. Він створює добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Codex для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Codex, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Codex CLI\nnpm install -g @openai/codex\n# or: brew install --cask codex\n# or: curl -fsSL https://chatgpt.com/codex/install.sh | sh\n\n# 2. Authenticate (ChatGPT sign-in recommended for higher limits)\ncodex            # then choose “Sign in with ChatGPT”\n\n# 3. Generate project context\ncodex            # inside your project, run /init to create AGENTS.md\n\n# 4. Add the official frontend skill, then restart Codex\n# (in the Codex app) $skill-installer frontend-skill\n\n# 5. Wire the Figma MCP server (optional, for design handoff)\ncodex mcp add figma --url https://mcp.figma.com/mcp"}, {"kind": "image", "src": "/agents/codex-design/codex-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування, встановлення skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування AGENTS.md → встановлення frontend skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в AGENTS.md або DESIGN.md і вкажіть на них Codex, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Виберіть правильний рівень міркування", "body": "OpenAI зазначає, що низький-середній рівні міркування часто дають сильніші фронтенд-результати, ніж найвище налаштування."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Codex — перетворити референсне зображення на робочий, адаптивний UI та ітерувати, доки воно не збіжиться. Власні рекомендації OpenAI зводяться до п'яти кроків."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть Codex, де живуть tokens і канонічні примітиви.", "Увімкніть інтерактивний skill Playwright, щоб Codex рендерив у справжньому браузері й змінював розмір під брейкпойнти.", "Ітеруйте, змушуючи Codex порівнювати свою реалізацію зі скриншотами — а не лише підтверджувати, що збірка проходить."]}, {"kind": "p", "text": "Подавайте зображення, перетягуючи скриншот у термінал або через прапорець зображення, а потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "codex -i reference-desktop.png -i reference-mobile.png \\\n  \"Implement this design in React + Vite + Tailwind + TypeScript.\n   Reuse my existing design-system components and tokens.\n   Match spacing, layout, and hierarchy; make it responsive.\n   Use the Playwright skill to verify the UI matches the\n   references and iterate until it does.\""}, {"kind": "p", "text": "Запускайте dev-сервер у другому терміналі, тримайте промпти невеликими й сфокусованими та комітьте вдалі ітерації / відкочуйте невдалі (кажучи Codex, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "figma", "heading": "Codex + Figma: двосторонній обмін дизайн ↔ код", "blocks": [{"kind": "p", "text": "У лютому 2026 року OpenAI і Figma оголосили про офіційне партнерство, перетворивши попередню бета-версію Figma MCP на першокласну двонапрямлену інтеграцію. Вона працює в обидва боки."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопіюйте «link to selection» фрейму у Figma, вставте його в Codex із get_design_context і попросіть реалізувати дизайн із вашою наявною бібліотекою компонентів."}, {"label": "Код → Дизайн", "body": "Інструмент generate_figma_design («Code to Canvas») перетворює живий робочий UI назад на редаговані фрейми Figma — увесь екран, вибраний елемент або цілий файл."}]}, {"kind": "p", "text": "Figma MCP працює як віддалений сервер і звільнений від лімітів швидкості. Додайте його одного разу, і він стане доступним для Codex, Claude Code, Cursor, VS Code тощо — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Codex проти Cursor проти Claude Code для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Codex", "Сильне візуальне опрацювання після GPT-5.4 + frontend-skill; розуміння зображень", "Делеговані асинхронні збірки, запуски в пісочниці, переносні правила AGENTS.md"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований Codex, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — поламані мобільні розкладки, інструкції, що протікають у текст UI, та швидке досягнення лімітів використання."}, {"kind": "steps", "items": [{"label": "Встановіть frontend skill", "body": "Кураторський естетичний skill змушує Codex обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Увімкніть перевірку Playwright", "body": "Змусьте Codex рендерити й самоперевірятися на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в AGENTS.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Codex всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Codex як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Codex добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Codex як свого агента.", "Автентифікуйтеся своїм API-ключем OpenAI (BYOK) або підпискою ChatGPT — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Codex, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді OpenAI Codex може виконувати дизайн-роботу?", "text": "Так — із frontend skill, дизайн-системою та реальними референсними зображеннями в контексті Codex (особливо на GPT-5.4) створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Це плагін OpenAI Codex Product Design?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує Codex як агента. Він доповнює власний інструментарій OpenAI local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені підписка ChatGPT, щоб проєктувати з Codex?", "text": "Ви можете використовувати або API-ключ OpenAI (BYOK), або свою підписку ChatGPT. Вхід через ChatGPT зазвичай дає щедріші ліміти; у будь-якому разі Open Design ніколи не проксіює ваші облікові дані."}, {"name": "Codex чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; Codex має сильне візуальне опрацювання після GPT-5.4 й чудово справляється з делегованими збірками в пісочниці. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Codex до Figma?", "text": "Додайте офіційний сервер Figma MCP (codex mcp add figma --url https://mcp.figma.com/mcp). Тоді ви зможете реалізовувати фрейми Figma в коді за допомогою get_design_context і відправляти робочий UI назад у редаговані фрейми Figma за допомогою generate_figma_design."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Встановіть frontend skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в AGENTS.md та увімкніть перевірку Playwright. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з OpenAI?", "text": "Ні. Codex — продукт OpenAI; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. OpenAI і Codex — торгові марки OpenAI."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані OpenAI використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Codex, відкрито.", "ctaBody": "Підключіть власний ключ OpenAI, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Codex в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'cursor': {
        ...en['cursor']!,
        title: "Cursor для дизайнерів — Open Design",
        description: "Як дизайнери використовують Cursor для UI та вебдизайну — Design Mode, Figma-у-код, Figma MCP — і як Open Design перетворює Cursor на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "Cursor Agent",
        label: "Агент · Cursor",
        heading: "Cursor для дизайнерів.",
        lead: "Cursor — це AI-редактор коду, тепер із візуальним Design Mode. Дизайнери використовують його, щоб редагувати UI вказуванням і малюванням, і перетворювати Figma на код. Open Design вбудовує Cursor Agent у дизайн-процес з відкритим кодом, що тримає ваші файли локально.",
        rich: {"heroCtaLead": "Open Design перетворює Cursor на local-first дизайн-агента з відкритим кодом — ваш акаунт Cursor або ключі моделей, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Cursor — це AI-first редактор коду, який зробив «зроби й подивись, як воно рендериться» стандартним способом випускати UI. З режимом Agent, інлайн-правками, попереднім переглядом усередині редактора та Figma через MCP він став справжнім дизайн-інструментом — щойно ви даєте йому правильні референси, правила та цикл перевірки. Це практичний наскрізний посібник з використання Cursor для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим насправді є Cursor, чому його щільний цикл «ітеруй і спостерігай» добрий для дизайну, як налаштувати його з нуля, цикл «скриншот і попередній перегляд → UI», двосторонній обмін із Figma через MCP, як він порівнюється з Codex і Claude Code, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар."], "heroImage": {"src": "/agents/cursor-design/cursor-design-hero.webp", "alt": "Збіжність дизайну Cursor: редактор ліворуч, кураторський хаб skill-ів і дизайн-систем посередині зі знаком Cursor у центрі та відрендерений UI праворуч", "caption": "Основна ідея: Cursor редагує й рендерить UI в редакторі, а кураторський дизайн-хаб подає йому систему, skill-и та референси, що роблять вивід умисним."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-cursor", "label": "Чим насправді є Cursor"}, {"id": "why-design", "label": "Чому Cursor добрий у дизайні"}, {"id": "setup", "label": "Налаштування Cursor для дизайну (з нуля)"}, {"id": "preview-workflow", "label": "Робочий процес «попередній перегляд → UI»"}, {"id": "figma", "label": "Cursor + Figma через MCP"}, {"id": "vs", "label": "Cursor проти Codex проти Claude Code"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Cursor в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-cursor", "heading": "Чим насправді є Cursor", "blocks": [{"kind": "p", "text": "Cursor — це AI-first редактор коду, створений компанією Anysphere. Це форк VS Code, тож він зберігає звичний редактор, розширення та комбінації клавіш, але перебудовує робочий процес навколо AI-агента, який може читати весь ваш проєкт, редагувати кілька файлів, виконувати команди та ітерувати разом з вами в циклі."}, {"kind": "p", "text": "Для дизайн-роботи важливі поверхні — це режим Agent (ви описуєте результат, а Cursor планує й редагує між файлами), інлайн-правки та доповнення Tab для швидких налаштувань, попередній перегляд / браузер усередині редактора, щоб бачити робочий UI, не залишаючи вікно, і підтримка MCP, що дозволяє підтягувати зовнішній контекст, як-от живий файл Figma."}, {"kind": "steps", "items": [{"label": "Правила проєкту", "body": "Cursor читає файли інструкцій проєкту — версіоновані правила `.mdc` під `.cursor/rules` та звичайний `AGENTS.md` — тож ви можете закодувати свої дизайн-конвенції там, де агент читає їх щоразу."}, {"label": "Моделі", "body": "Cursor гнучкий до моделей: він постачається з передовими моделями через вашу підписку й також підтримує підключення власних ключів моделей, тож ви обираєте рушій за тим самим робочим процесом редактора."}, {"label": "MCP", "body": "Він розмовляє Model Context Protocol, тож зовнішні сервери — найрелевантніше, сервер Figma MCP — стають першокласним контекстом для агента."}]}, {"kind": "ul", "items": ["Постачальник: Anysphere", "Облікові дані: акаунт / підписка Cursor (Hobby / Pro / Business) або власні ключі моделей (BYOK)", "Форма: AI-first редактор коду (форк VS Code) з агентом і попереднім переглядом усередині редактора"]}]}, {"id": "why-design", "heading": "Чому Cursor добрий у дизайні", "blocks": [{"kind": "p", "text": "Дизайн-перевага Cursor — не окрема функція, а щільність циклу «зроби й подивись». Три речі роблять його схожим на дизайн-інструмент, а не на загальний генератор коду."}, {"kind": "steps", "items": [{"label": "Щільний цикл «ітеруй і спостерігай»", "body": "Ви задаєте промпт, Cursor редагує між файлами, а попередній перегляд усередині редактора рендерить результат миттєво — тож ви налаштовуєте відступи, ієрархію та рух за секунди замість того, щоб ходити кругом через окремий термінал і браузер."}, {"label": "Пряме візуальне редагування", "body": "Окрім чату, Cursor дозволяє вибирати елементи в попередньому перегляді й підправляти стилі, тож дрібні візуальні корекції відчуваються як дизайн-правки, а не археологія коду."}, {"label": "Правила проєкту та контекст MCP", "body": "З `.cursor/rules` (або `AGENTS.md`) і сервером Figma MCP агент працює з вашими tokens, компонентами та реальними дизайн-специфікаціями замість того, щоб вгадувати."}]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень."}, {"kind": "p", "text": "Урок той самий, що його вчить кожен агент: Cursor не має смаку за замовчуванням. Він створює добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте Cursor для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Cursor, який може будувати, переглядати й перевіряти UI відносно вашої дизайн-системи."}, {"kind": "ol", "items": ["Встановіть Cursor із cursor.com і увійдіть зі своїм акаунтом Cursor або налаштуйте власні ключі моделей (BYOK) у Settings.", "Відкрийте свій проєкт і виберіть модель у панелі чату / Agent.", "Додайте правила проєкту: створіть `.cursor/rules/*.mdc` для структурованих, обмежених glob-ами конвенцій, або звичайний `AGENTS.md` для простих, читабельних інструкцій.", "Підключіть сервер Figma MCP (опційно), щоб агент міг читати живий дизайн-контекст.", "Запустіть свій dev-сервер і використовуйте попередній перегляд усередині редактора, щоб бачити й перевіряти UI під час ітерацій."]}, {"kind": "image", "src": "/agents/cursor-design/cursor-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування правил, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування правил проєкту → додавання skill-а → увімкнення перевірки через попередній перегляд."}, {"kind": "p", "text": "Мінімальний файл правил проєкту змушує агента проєктувати під бренд замість звертання до загального вигляду. Помістіть його туди, де Cursor читає його щоразу:"}, {"kind": "code", "lang": "markdown", "code": "# .cursor/rules/design.mdc\n---\ndescription: Project design conventions\nalwaysApply: true\n---\n\n- Reuse existing design-system tokens and components; never hardcode hex or spacing.\n- At most two typefaces and one accent color.\n- Brand-first hierarchy; restrained motion. No hero cards, no oversized rounded corners.\n- Build responsive by default; verify desktop and mobile in the preview before finishing."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в `.cursor/rules` або `AGENTS.md` і вкажіть на них Cursor, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Тримайте промпти невеликими", "body": "Щільний цикл Cursor винагороджує сфокусовані запити — ітеруйте по одному компоненту чи стану за раз і спостерігайте попередній перегляд між проходами."}]}]}, {"id": "preview-workflow", "heading": "Робочий процес «попередній перегляд → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із Cursor — перетворити референс на робочий, адаптивний UI та ітерувати в редакторі, доки він не збіжиться — спостерігаючи живий попередній перегляд увесь час замість того, щоб вгадувати."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть Cursor, де живуть tokens і канонічні примітиви.", "Тримайте попередній перегляд усередині редактора відкритим, а dev-сервер запущеним, щоб кожна правка рендерилась миттєво на потрібних вам брейкпойнтах.", "Ітеруйте, порівнюючи відрендерений UI з референсами — і використовуйте прямий вибір елементів у попередньому перегляді для дрібних візуальних корекцій."]}, {"kind": "p", "text": "Подавайте референси, прикріплюючи зображення до чату, а потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "text", "code": "Implement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nKeep the preview open — verify desktop and mobile match the\nreferences and iterate until they do."}, {"kind": "p", "text": "Комітьте вдалі ітерації й відкочуйте невдалі (кажучи Cursor, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі — та сама дисципліна, що не дає будь-якому циклу агента зноситися."}]}, {"id": "figma", "heading": "Cursor + Figma: дизайн ↔ код через MCP", "blocks": [{"kind": "p", "text": "Cursor підключається до Figma через офіційний сервер Figma MCP, що дає агенту структурований доступ до живого файлу Figma замість плаского скриншота. Це усуває здогадки з передачі."}, {"kind": "steps", "items": [{"label": "Дизайн → Код", "body": "Скопіюйте посилання на фрейм у Figma, вставте його в Cursor і попросіть реалізувати дизайн. Сервер MCP надає реальний дизайн-контекст — компоненти, змінні, дані розкладки, tokens — тож згенерований код відповідає джерелу, а не наближає його."}, {"label": "Лишайтеся узгодженими", "body": "З дизайн-tokens, стилями та компонентами, що послідовно використовуються у Figma (і Code Connect, де доступно), вивід Cursor лишається прив'язаним до вашої реальної дизайн-системи, а не винаходить примітиви заново."}]}, {"kind": "p", "text": "Налаштуйте віддалений сервер Figma MCP одного разу, і він стане доступним для Cursor як першокласний контекст. Оскільки MCP — це відкритий стандарт, той самий сервер можна повторно використовувати в Cursor, Claude Code, Codex і VS Code — саме той тип переносної, мультиагентної можливості, яку Open Design створено оркеструвати."}]}, {"id": "vs", "heading": "Cursor проти Codex проти Claude Code для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом усередині редактора та прямим редагуванням елементів", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Codex", "Сильне візуальне опрацювання з frontend skill; розуміння зображень і запуски в пісочниці", "Делеговані асинхронні збірки та переносні правила AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі три за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований Cursor, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — розкладки, що ламаються на мобільному, та інструкції, що протікають у текст UI."}, {"kind": "steps", "items": [{"label": "Додайте дизайн-skill", "body": "Кураторський естетичний skill змушує Cursor обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Використовуйте попередній перегляд для перевірки", "body": "Рендерте й самоперевіряйтеся на різних брейкпойнтах у попередньому перегляді всередині редактора, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в `.cursor/rules`", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із Cursor всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує Cursor як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить Cursor добрим, був на місці з першого запуску, а не збирався вручну щоразу."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Cursor як свого агента.", "Автентифікуйтеся своїм акаунтом Cursor або власними ключами моделей (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент Cursor, той самий ключ — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді Cursor може виконувати дизайн-роботу?", "text": "Так — із дизайн-skill, дизайн-системою та реальними референсними зображеннями в контексті Cursor створює UI продакшн-якості, адаптивний, а його попередній перегляд усередині редактора дозволяє перевіряти й уточнювати його візуально. Без цього контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Це офіційний продукт Cursor?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує Cursor як агента. Він доповнює Cursor local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені підписка Cursor, щоб проєктувати з Cursor?", "text": "Ви можете використовувати акаунт / підписку Cursor або підключити власні ключі моделей (BYOK). У будь-якому разі Open Design ніколи не проксіює ваші облікові дані — їх безпосередньо використовує ваш агент."}, {"name": "Cursor чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Cursor — його щільний цикл «зроби й подивись» із живим попереднім переглядом усередині редактора. Багато команд використовують обидва — Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як підключити Cursor до Figma?", "text": "Додайте офіційний сервер Figma MCP у Cursor, потім вставте посилання на фрейм Figma в чат і попросіть Cursor реалізувати його. Сервер надає реальні компоненти, змінні та дані розкладки, тож згенерований код відповідає вихідному дизайну."}, {"name": "Як уникнути загальної естетики «AI slop»?", "text": "Додайте дизайн-skill, надайте реальні дизайн-tokens і референсні скриншоти, закодуйте правила бренду в `.cursor/rules` або `AGENTS.md` і перевіряйте на різних брейкпойнтах у попередньому перегляді. Open Design постачає це як кураторську бібліотеку, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з Cursor або Anysphere?", "text": "Ні. Cursor — продукт Anysphere; Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер. Cursor і Anysphere — торгові марки Anysphere, Inc."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Cursor чи моделі використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з Cursor, відкрито.", "ctaBody": "Підключіть власний акаунт Cursor або ключі моделей, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати Cursor в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'opencode': {
        ...en['opencode']!,
        title: "OpenCode для дизайну — Open Design",
        description: "Як люди використовують OpenCode для UI та вебдизайну — файли design.md, UI/UX skill-и, Figma MCP — і як Open Design перетворює OpenCode на local-first дизайн-агента з відкритим кодом.",
        breadcrumb: "OpenCode",
        label: "Агент · OpenCode",
        heading: "OpenCode для дизайну.",
        lead: "OpenCode — це термінальний AI-агент для кодування з відкритим кодом. Дизайнери прикручують до нього дизайн-skill-и та файли DESIGN.md, щоб генерувати справжній UI. Open Design робить це структурованим процесом з відкритим кодом — підключіть ключі своїх постачальників, тримайте все локально.",
        rich: {"heroCtaLead": "Open Design перетворює OpenCode на local-first дизайн-агента з відкритим кодом — будь-яка модель, яку ви обираєте, з вашим власним ключем постачальника, ваші файли та кураторська бібліотека skill-ів і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використати OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["OpenCode — це термінальний AI-агент для кодування з відкритим кодом, навмисно незалежний від моделей: ви підключаєте власний ключ постачальника й запускаєте будь-яку модель за тим самим робочим процесом. Така відкритість робить його природною базою для дизайн-роботи — але, як і кожен агент, він створює добрий UI лише тоді, коли ви даєте йому правильні референси, skill-и та цикл перевірки. Це практичний наскрізний посібник з використання OpenCode для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування в структурований дизайн-процес разом з Open Design.", "Тут розглядається, чим насправді є OpenCode, чому відкритий агент, незалежний від моделей, добре пасує дизайну, як налаштувати його з нуля, цикл «скриншот → UI», як AGENTS.md і MCP розширюють його, як він порівнюється з Codex, Claude Code та Cursor, пастки, через які вивід ШІ виглядає загальним, і як Open Design закриває цю прогалину як відкритий local-first дизайн-шар — природне поєднання, адже обидва проєкти з відкритим кодом і працюють на вашій власній машині."], "heroImage": {"src": "/agents/opencode-design/opencode-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну OpenCode: термінальний TUI-агент, браузер, що рендерить UI, і робочий простір зі стрілкою зворотного зв'язку", "caption": "Основний цикл: OpenCode будує UI у терміналі, рендерить і перевіряє його у справжньому браузері та ітерує до ваших референсів — на будь-якій моделі, яку ви оберете."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-opencode", "label": "Чим насправді є OpenCode"}, {"id": "why-design", "label": "Чому відкритий агент із будь-якою моделлю пасує дизайну"}, {"id": "setup", "label": "Налаштування OpenCode для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "extend", "label": "AGENTS.md, MCP та сесії, якими можна ділитися"}, {"id": "vs", "label": "OpenCode проти Codex проти Claude Code проти Cursor"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із OpenCode в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-opencode", "heading": "Чим насправді є OpenCode", "blocks": [{"kind": "p", "text": "OpenCode — це AI-агент для кодування з відкритим кодом, створений для терміналу й підтримуваний командою, що стоїть за SST (Anomaly Innovations). Він читає ваш репозиторій, виконує команди, редагує файли й спілкується з великою мовною моделлю — але, на відміну від прив'язаних до вендора агентів, він не постачає власну модель. Ви спрямовуєте його на будь-який постачальник і модель, які захочете, і підключаєте власний ключ."}, {"kind": "p", "text": "Він працює як термінальний UI (TUI), з десктопним застосунком та розширеннями IDE поверх того самого рушія. Під капотом він використовує клієнт-серверну архітектуру, тож агент, що виконує роботу, відокремлений від поверхні, з якої ви ним керуєте. Два вбудовані агенти — build і plan — перемикаються клавішею Tab."}, {"kind": "steps", "items": [{"label": "Незалежний від моделей", "body": "Моделі та постачальники беруться з models.dev, відкритого каталогу. Ви налаштовуєте їх в opencode.json рядком provider/model-id і можете вимкнути постачальників, яких не хочете завантажувати — тож той самий дизайн-процес працює на Anthropic, OpenAI, Google, OpenRouter, локальних моделях тощо."}, {"label": "Файл інструкцій", "body": "OpenCode читає файл AGENTS.md у вашому проєкті (міжінструментальний стандарт, також сумісний із CLAUDE.md) для правил проєкту — природне місце, щоб закодувати ваші дизайн-конвенції. Запустіть /init, щоб згенерувати його."}, {"label": "Розширюваний", "body": "Він підтримує інтеграцію LSP, сервери MCP, теми, комбінації клавіш і кастомні команди, а також посилання на сесії, якими можна ділитися, для співпраці."}]}, {"kind": "ul", "items": ["Супровід: SST / Anomaly Innovations (проєкт з відкритим кодом)", "Облікові дані: ваш(і) власний(і) API-ключ(і) постачальника моделей — BYOK, без прив'язки до вендора", "Ліцензія: MIT, відкритий код"]}]}, {"id": "why-design", "heading": "Чому відкритий агент із будь-якою моделлю пасує дизайн-роботі", "blocks": [{"kind": "p", "text": "OpenCode не має єдиної «дизайн-моделі», як її має вендорний агент — і в цьому суть. Оскільки він незалежний від моделей і відкритий, ви можете запускати той самий дизайн-процес на тій моделі, яка зараз найкраща у фронтенді, замінити її пізніше або відкотитися до локальної моделі — і все без зміни вашого налаштування."}, {"kind": "p", "text": "Але самого вибору моделі мало для смаку. Як і кожен агент для кодування, OpenCode створює загальний UI, доки ви не дасте йому обмежень. Добрий дизайн-вивід походить із трьох вхідних даних, які надаєте ви."}, {"kind": "steps", "items": [{"label": "Дизайн-система", "body": "Реальні tokens, примітиви та конвенції, які агент повторно використовує, щоб вивід відповідав бренду, а не звертався до загального вигляду."}, {"label": "Естетичний skill", "body": "Кураторський skill, що нав'язує реальний смак — стриманий рух, ієрархія за брендом, щонайбільше два шрифти й один акцентний колір — і змушує агента обрати напрямок перед побудовою."}, {"label": "Конкретні референси", "body": "Справжні референсні зображення та кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не один hero-кадр."}]}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-taste-triangle.webp", "alt": "Схема, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак з'являється з трьох вхідних даних, які надаєте ви: дизайн-системи, skill-а та реальних референсних зображень — незалежно від того, яку модель ви запускаєте."}, {"kind": "p", "text": "Урок: OpenCode дає вам свободу моделі, але смак усе одно походить із кураторського дизайн-контексту. Open Design упаковує саме ці вхідні дані, тому ці двоє пасують одне одному — обидва з відкритим кодом і local-first (далі — детальніше)."}]}, {"id": "setup", "heading": "Налаштуйте OpenCode для дизайну, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до OpenCode, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install OpenCode\ncurl -fsSL https://opencode.ai/install | bash\n# or: npm i -g opencode-ai@latest\n# or: brew install sst/tap/opencode\n\n# 2. Start the TUI in your project, then authenticate your provider\nopencode          # then run /login and pick your provider + paste your key\n\n# 3. Generate project context\nopencode          # inside your project, run /init to create AGENTS.md\n\n# 4. Pick your model (any provider, via models.dev)\n#    set \"provider/model-id\" in opencode.json or switch in the TUI\n\n# 5. Add an MCP server (optional, e.g. for design handoff)\n#    configure it under the \"mcp\" key in opencode.json"}, {"kind": "image", "src": "/agents/opencode-design/opencode-design-setup-flow.webp", "alt": "Процес налаштування з п'яти кроків: встановлення, автентифікація ключем постачальника, налаштування AGENTS.md, додавання skill-а, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація (ваш ключ постачальника) → налаштування AGENTS.md → додавання skill-а → перевірка у справжньому браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Помістіть свої tokens, примітиви та конвенції в AGENTS.md (або DESIGN.md, на який є посилання звідти), щоб вивід відповідав бренду, а не звертався до загального вигляду. Опція instructions в opencode.json може вказувати на додаткові файли правил через glob-и."}, {"label": "Виберіть здатну модель", "body": "Оскільки OpenCode незалежний від моделей, виберіть той постачальник/модель, що зараз найсильніший у фронтенді, для дизайн-проходу — і лишіть решту свого процесу незмінною."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найрезультативніший дизайн-цикл із будь-яким агентом — перетворити референсне зображення на робочий, адаптивний UI та ітерувати, доки воно не збіжиться. Та сама форма з п'яти кроків застосовна в OpenCode."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є, — і включайте кілька станів (десктоп і мобільний, hover, порожній, завантаження), а не лише один hero-кадр.", "Будьте конкретні в промпті; розпливчасті промпти дають загальний UI.", "Підготуйте дизайн-систему й скажіть OpenCode, де живуть tokens і канонічні примітиви (в AGENTS.md).", "Запустіть dev-сервер і змусьте агента рендерити у справжньому браузері, змінюючи розмір під брейкпойнти, щоб перевірити результат.", "Ітеруйте, змушуючи OpenCode порівнювати свою реалізацію зі скриншотами — а не лише підтверджувати, що збірка проходить."]}, {"kind": "p", "text": "Посилайтеся на файли через @ у TUI для нечіткого пошуку у вашій робочій директорії, виконуйте shell-команди інлайн із початковим !, і керуйте діями через команди /. Потім задавайте промпт із конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "opencode\n# in the TUI:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, open it in a browser, and iterate until the\n  UI matches the references across breakpoints."}, {"kind": "p", "text": "Тримайте промпти невеликими й сфокусованими, комітьте вдалі ітерації й відкочуйте невдалі (кажучи OpenCode, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "extend", "heading": "AGENTS.md, MCP та сесії, якими можна ділитися", "blocks": [{"kind": "p", "text": "Три точки розширення роблять OpenCode практичним для сталої дизайн-роботи, і всі три чисто лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Правила AGENTS.md", "body": "Правила проєкту живуть в AGENTS.md у корені репозиторію (або глобальні правила в ~/.config/opencode/AGENTS.md). Це довговічна домівка для ваших дизайн-конвенцій, що читається щоразу, і вона сумісна з файлами CLAUDE.md, які використовують інші агенти."}, {"label": "Сервери MCP", "body": "OpenCode підтримує як локальні (command), так і віддалені (URL) сервери MCP, налаштовані під ключем mcp — переносний спосіб привнести дизайн-контекст і зовнішні інструменти, що працюють між агентами, а не лише в OpenCode."}, {"label": "Сесії, якими можна ділитися", "body": "Команда /share створює публічне посилання на розмову для співпраці чи рев'ю, а /unshare відкликає його — корисно для отримання відгуку про дизайн-прохід."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме той тип речей, який Open Design створено оркеструвати, а не відтворювати для кожного проєкту."}]}, {"id": "vs", "heading": "OpenCode проти Codex проти Claude Code проти Cursor для дизайну", "blocks": [{"kind": "p", "text": "Єдиного переможця для дизайн-роботи немає — у кожного агента своя сильна сторона, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Сила в дизайні", "Найкраще для"], "rows": [["OpenCode", "Відкритий код і незалежність від моделей; запускайте будь-який постачальник за одним термінальним процесом", "Свобода BYOK, перемикання моделей, повністю відкриті та local-first налаштування"], ["Codex", "Сильне візуальне опрацювання з frontend skill; розуміння зображень", "Делеговані асинхронні, збірки в пісочниці, переносні правила AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з урахуванням кодової бази", "Фронтенд-міркування й рефактори з великим контекстом"], ["Cursor", "Цикл «зроби й подивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI у режимі «ітеруй і спостерігай» усередині IDE"]]}, {"kind": "p", "text": "Сталий вердикт спільноти такий: смак походить від людей — усі вони за замовчуванням тяжіють до загальної естетики без skill-ів, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструмента, а не моделі, і саме тому відкритий агент на кшталт OpenCode так добре поєднується з відкритим дизайн-шаром."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований ШІ, — що він виглядає загальним: м'які градієнти, плаваючі панелі, завеликі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив ШІ». Серед інших повідомлених проблем — поламані мобільні розкладки та інструкції, що протікають у текст UI. Жодна з них не унікальна для OpenCode; це те, що стається, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичний skill", "body": "Кураторський дизайн-skill змушує агента обрати реальний напрямок замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Рендерте й самоперевіряйтеся на різних брейкпойнтах, щоб розкладки не ламались на мобільному непомітно."}, {"label": "Надайте tokens і референси", "body": "Реальні дизайн-tokens і референсні скриншоти — найпотужніший важіль якості виводу."}, {"label": "Закодуйте правила в AGENTS.md", "body": "Помістіть правила штибу «без hero-карток, максимум два шрифти, ієрархія за брендом» туди, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожен спосіб пом'якшення зводиться до надання агенту кураторського дизайн-контексту — незалежно від того, яку модель ви запускаєте. Підтримувати цей контекст вручну для кожного проєкту — це рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн із OpenCode всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це той дизайн-шар з відкритим кодом, якого постійно потребує наведений вище процес. Він трактує OpenCode як власний адаптер і обгортає його кураторською бібліотекою skill-ів і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — щоб дизайн-контекст, який робить будь-якого агента добрим, був на місці з першого запуску, а не збирався вручну щоразу. Обидва проєкти з відкритим кодом і local-first, що робить поєднання природним."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть OpenCode як свого агента.", "Автентифікуйтеся своїм власним API-ключем постачальника моделі (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть будь-який постачальник і модель, а також дизайн-систему та skill, а потім генеруйте презентації, прототипи й лендинги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в розміщеній хмарі."]}, {"kind": "p", "text": "Той самий агент OpenCode, та сама свобода моделі — плюс реальний, переносний дизайн-процес з відкритим кодом навколо нього. Він local-first і Apache-2.0, тож ніщо у вашій роботі чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи справді OpenCode може виконувати дизайн-роботу?", "text": "Так — із естетичним skill, дизайн-системою та реальними референсними зображеннями в контексті OpenCode створює UI продакшн-якості, адаптивний, і може перевірити його в браузері. Оскільки він незалежний від моделей, ви запускаєте ту модель, яка зараз найкраща у фронтенді. Без цього кураторського контексту він тяжіє до загального вигляду — і саме цю прогалину закриває Open Design."}, {"name": "Яку модель слід використовувати з OpenCode для дизайну?", "text": "Будь-яку, що вам до вподоби — OpenCode незалежний від постачальників через models.dev, тож ви можете запускати Anthropic, OpenAI, Google, OpenRouter або локальні моделі за тим самим процесом і перемикатися будь-коли. Якість дизайн-виводу залежить набагато більше від вашого skill-а, дизайн-системи та референсів, ніж від самої моделі."}, {"name": "Чи зроблено Open Design командою OpenCode (SST)?", "text": "Ні. Open Design — незалежний проєкт з відкритим кодом, який інтегрує OpenCode як агента. Він доповнює OpenCode local-first відкритою бібліотекою skill-ів і дизайн-систем."}, {"name": "Чи потрібна мені особлива підписка, щоб проєктувати з OpenCode?", "text": "Ні — OpenCode працює за BYOK. Ви підключаєте власний API-ключ постачальника моделі, і Open Design ніколи не проксіює ваші облікові дані. Немає прив'язки до вендора."}, {"name": "OpenCode, Codex чи Claude Code для фронтенд-дизайну?", "text": "Усі сильні, і багато команд поєднують їх. Перевага OpenCode — бути повністю з відкритим кодом і незалежним від моделей; Codex чудовий у делегованих збірках у пісочниці; Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази. Open Design дозволяє перемикати агентів без зміни дизайн-процесу."}, {"name": "Як розширити OpenCode для дизайн-контексту?", "text": "Закодуйте правила в AGENTS.md, додайте сервери MCP під ключем mcp для переносних інструментів і дизайн-контексту та використовуйте сесії, якими можна ділитися, для рев'ю. Open Design постачає кураторську бібліотеку skill-ів і дизайн-систем, щоб ви пропустили налаштування для кожного проєкту."}, {"name": "Чи пов'язаний Open Design з OpenCode або SST?", "text": "Ні. OpenCode — проєкт з відкритим кодом, який підтримує SST (Anomaly Innovations); Open Design — незалежний проєкт з відкритим кодом, який підтримує його як власний адаптер."}, {"name": "Чи мої файли й облікові дані в безпеці?", "text": "Так — Open Design local-first. Ваші файли, артефакти й DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані постачальника моделі використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Проєктуйте з OpenCode, відкрито.", "ctaBody": "Підключіть власний ключ постачальника моделі, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо відкритого агента, яким ви вже користуєтесь.", "ctaActions": [{"label": "Використати OpenCode в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'gemini': {
        ...en['gemini']!,
        title: "Gemini CLI для дизайну — Open Design",
        description: "Як люди використовують Gemini CLI від Google для UI- та вебдизайну — його мультимодальне розуміння зображень, контекст на 1 млн токенів, GEMINI.md і MCP — і як Open Design перетворює Gemini CLI на локальний агент дизайну з відкритим кодом.",
        breadcrumb: "Gemini CLI",
        label: "Агент · Gemini CLI",
        heading: "Gemini CLI для дизайну.",
        lead: "Gemini CLI — це термінальний агент Google з відкритим кодом. Його мультимодальні моделі читають скриншоти, а контекст на 1 млн токенів вміщує цілу дизайн-систему, що робить його справжнім інструментом дизайну — щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його в робочий процес дизайну з відкритим кодом: ваш обліковий запис Google або ключ API, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Gemini CLI на локальний агент дизайну з відкритим кодом — ваш обліковий запис Google або ключ API Gemini, ваші файли, а навколо — підібрана бібліотека навичок і дизайн-систем.", "heroCtaActions": [{"label": "Використовуйте Gemini CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставте зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажте десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Gemini CLI — це AI-агент Google з відкритим кодом для термінала. Дві речі роблять його цікавим саме для дизайну: його моделі мають потужну мультимодальність, тож він читає скриншот і міркує про макет, відступи й ієрархію; а його контекстне вікно на 1 млн токенів вміщує цілу дизайн-систему й кодову базу одночасно. У парі з правильними референсами, конвенціями та циклом перевірки він створює справжній адаптивний UI — і його можна почати використовувати безкоштовно з обліковим записом Google. Це практичний наскрізний посібник із використання Gemini CLI для роботи з UI, фронтендом і дизайн-системами та з його вбудовуванням у структурований робочий процес дизайну за допомогою Open Design.", "Він охоплює те, чим насправді є Gemini CLI, чому його мультимодальні моделі та величезний контекст пасують дизайну, як налаштувати його з нуля, цикл «скриншот → UI», як GEMINI.md і MCP розширюють його, як він порівнюється з Codex, Claude Code й Cursor, пастки, через які вихід AI виглядає шаблонним, і як Open Design закриває цей розрив як відкритий локальний шар дизайну — природне поєднання, адже обидва мають відкритий код і працюють на вашій власній машині."], "heroImage": {"src": "/agents/gemini-design/gemini-design-hero.webp", "alt": "Цикл зворотного зв’язку дизайну Gemini CLI: термінальний агент читає референсне зображення, браузер рендерить UI, а робочий простір зі стрілкою зворотного зв’язку, що повертається назад", "caption": "Основний цикл: Gemini CLI читає ваші референси в терміналі, будує й перевіряє UI у справжньому браузері та ітерує відносно них — маючи цілу дизайн-систему в контексті."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-gemini-cli", "label": "Чим насправді є Gemini CLI"}, {"id": "why-design", "label": "Чому мультимодальність + величезний контекст пасують дизайну"}, {"id": "setup", "label": "Налаштування Gemini CLI для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "extend", "label": "GEMINI.md, MCP і розширення"}, {"id": "vs", "label": "Gemini CLI проти Codex, Claude Code й Cursor"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-халтури»"}, {"id": "open-design", "label": "Дизайн із Gemini CLI в Open Design"}, {"id": "faq", "label": "Поширені запитання"}], "sections": [{"id": "what-is-gemini-cli", "heading": "Чим насправді є Gemini CLI", "blocks": [{"kind": "p", "text": "Gemini CLI — це AI-агент з відкритим кодом (Apache-2.0), який Google постачає для термінала. Він читає ваш репозиторій, редагує файли, виконує команди оболонки, отримує дані з вебу та може підкріплювати відповіді Google Search — плануючи й перевіряючи роботу за завданнями природною мовою, а не просто доповнюючи рядки. Той самий рушій також живить агента Gemini Code Assist всередині VS Code."}, {"kind": "p", "text": "Для роботи з дизайном виділяються дві властивості. Його моделі нативно мультимодальні, тож ви можете передати йому скриншот, і він міркуватиме про реальний макет. А його контекстне вікно сягає до 1 млн токенів — достатньо, щоб вмістити цілу вашу дизайн-систему, бібліотеку компонентів і набір референсів одночасно, замість того щоб згортати їх у короткі описи."}, {"kind": "steps", "items": [{"label": "Файли контексту", "body": "Gemini CLI читає файл GEMINI.md для сталого контексту проєкту — природне місце, щоб закодувати ваші дизайн-конвенції, tokens і чеклисти перевірки. Особисті та командні налаштування накладаються згори."}, {"label": "Вбудовані інструменти + MCP", "body": "Він з коробки постачає інструменти для файлів, оболонки, отримання даних з вебу та Google Search і підтримує сервери MCP (налаштовані в ~/.gemini/settings.json), щоб додавати зовнішній контекст, як-от живий файл Figma."}, {"label": "Безкоштовний старт", "body": "Вхід з особистим обліковим записом Google дає щедрий безкоштовний рівень запитів Gemini; ви також можете принести свій ключ API Gemini або використати Vertex AI."}]}, {"kind": "ul", "items": ["Постачальник: Google", "Облікові дані: обліковий запис Google (безкоштовний рівень) або ключ API Gemini з AI Studio (BYOK) чи Vertex AI", "Ліцензія: Apache-2.0, відкритий код"]}]}, {"id": "why-design", "heading": "Чому мультимодальні моделі та величезний контекст пасують дизайну", "blocks": [{"kind": "p", "text": "Перевага Gemini CLI в дизайні походить від двох властивостей моделі — але, як і з кожним агентом, смак усе одно треба надати."}, {"kind": "steps", "items": [{"label": "Потужне мультимодальне розуміння", "body": "Оскільки моделі Gemini нативно мультимодальні, агент добре читає референсні скриншоти — порівнюючи свій відрендерений вихід із зображенням, а не вгадуючи з текстового опису."}, {"label": "Контекстне вікно на 1 млн токенів", "body": "Великий контекст означає, що ціла дизайн-система, tokens і багато референсних станів вміщуються одночасно, тож агент повторно використовує ваші справжні примітиви, а не вигадує разові стилі."}, {"label": "Конвенції в GEMINI.md", "body": "GEMINI.md (плюс сервер Figma MCP) спрямовує агента на ваші tokens, компоненти та реальні специфікації, тож він працює відповідно до бренду, а не до стандартного вигляду."}]}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться в якісний результат дизайну", "caption": "Смак походить із трьох вхідних даних, які надаєте ви: дизайн-системи, навички та реальних референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Gemini CLI не має смаку за замовчуванням. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє так добре поєднуються (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштування Gemini CLI для роботи з дизайном, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Gemini CLI, який може будувати й перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Gemini CLI (Node 20+)\nnpm install -g @google/gemini-cli\n# or run without installing: npx https://github.com/google-gemini/gemini-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngemini            # sign in with your Google account, or set GEMINI_API_KEY\n\n# 3. Generate project context\n/init             # scaffolds a GEMINI.md for this project\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it under \"mcpServers\" in ~/.gemini/settings.json"}, {"kind": "image", "src": "/agents/gemini-design/gemini-design-setup-flow.webp", "alt": "П’ятикроковий процес налаштування: встановлення, автентифікація, конфігурація GEMINI.md, додавання навички, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → конфігурація GEMINI.md → додавання навички → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Помістіть свої tokens, примітиви та конвенції в GEMINI.md і спрямуйте Gemini на них, щоб вихід відповідав бренду, а не за замовчуванням набував шаблонного вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Gemini рендерив у справжньому браузері та перевіряв свій вихід на різних брейкпойнтах, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найефективніший цикл дизайну з Gemini CLI — це перетворення референсного зображення на робочий адаптивний UI та ітерація, доки воно не збігатиметься — спираючись на мультимодальну модель для порівняння виходу з референсом."}, {"kind": "ol", "items": ["Почніть із найчіткіших візуальних референсів, які у вас є — і включіть кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретними у промпті; розпливчасті промпти дають шаблонний UI навіть із потужною моделлю.", "Тримайте свою дизайн-систему та конвенції в GEMINI.md і скажіть Gemini, де живуть tokens і канонічні примітиви.", "Запустіть dev-сервер і дайте Gemini рендерити у справжньому браузері, змінюючи розмір до брейкпойнтів, щоб перевірити результат.", "Ітеруйте, доручаючи Gemini порівнювати свою реалізацію зі скриншотами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Посилайтеся на зображення через @, щоб приєднати його до промпту, а потім задайте конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "gemini\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from GEMINI.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Тримайте промпти невеликими й сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Gemini, коли ви відкочуєте), щоб кожен прохід будувався на чистій базі."}]}, {"id": "extend", "heading": "GEMINI.md, MCP і розширення", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Gemini CLI практичним для тривалої роботи з дизайном, і всі три чітко лягають на відкритий робочий процес дизайну."}, {"kind": "steps", "items": [{"label": "Контекст GEMINI.md", "body": "Правила проєкту живуть у GEMINI.md у корені репозиторію (з глобальним і командним шарами). Це сталий дім для ваших дизайн-конвенцій, який читається під час кожного запуску."}, {"label": "Сервери MCP", "body": "Налаштовуйте сервери MCP у ~/.gemini/settings.json — переносний спосіб привнести дизайн-контекст і зовнішні інструменти, найактуальніше сервер Figma MCP, які працюють у різних агентах, не лише в Gemini."}, {"label": "Розширення та вбудовані інструменти", "body": "Розширення Gemini CLI та його вбудовані інструменти Google Search, файлів, оболонки й отримання даних з вебу дають йому змогу збирати референси та виконувати цикл перевірки, не виходячи з термінала."}]}, {"kind": "p", "text": "Це переносні, багатоагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Gemini CLI проти Codex, Claude Code й Cursor для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для роботи з дизайном — кожен агент має свою сильну сторону, і досвідчені команди поєднують їх. Чесний підсумок:"}, {"kind": "table", "columns": ["Агент", "Сильна сторона в дизайні", "Найкраще для"], "rows": [["Gemini CLI", "Потужне мультимодальне розуміння зображень і контекст на 1 млн токенів; відкритий код із безкоштовним рівнем", "Робота з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"], ["Codex", "Потужна візуальна довершеність із навичкою фронтенду; пісочничні асинхронні збірки", "Делеговані асинхронні збірки та переносні правила AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) та UX з обізнаністю про кодову базу", "Міркування про фронтенд і рефакторинги з великим контекстом"], ["Cursor", "Візуальний цикл «будуй і дивись» із живим попереднім переглядом та інлайн-правками", "Щільна робота над UI з ітераціями та спостереженням всередині IDE"]]}, {"kind": "p", "text": "Постійний вердикт спільноти полягає в тому, що смак походить від людей: усі вони за замовчуванням схиляються до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба розв’язати — і вона має форму інструмента дизайну, а не форму моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-халтури»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на дизайн, згенерований AI, — що він виглядає шаблонно: м’які градієнти, плаваючі панелі, надмірно великі заокруглені кути, драматичні тіні, вайб «Inter-і-фіолетовий», що «кричить, ніби це зробив AI». Серед інших повідомлених проблем — поламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з них не унікальна для Gemini CLI; це те, що трапляється, коли будь-який агент працює без підібраного контексту дизайну."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Підібрана навичка дизайну змушує агента обрати реальний напрямок замість стандартного вигляду."}, {"label": "Перевіряйте у справжньому браузері", "body": "Використовуйте мультимодальну модель, щоб рендерити та самоперевірятися на різних брейкпойнтах, щоб макети тихо не ламалися на мобільних."}, {"label": "Надайте tokens і референси", "body": "Справжні дизайн-tokens і референсні скриншоти — найбільший важіль впливу на якість виходу."}, {"label": "Закодуйте правила в GEMINI.md", "body": "Помістіть правила на кшталт «без головних карток, максимум два шрифти, ієрархія за пріоритетом бренду» туди, де агент читає їх під час кожного запуску."}]}, {"kind": "p", "text": "Зверніть увагу, що кожне пом’якшення полягає в наданні агентові підібраного контексту дизайну. Підтримування цього контексту вручну, для кожного проєкту, — це рутина, яку Open Design усуває."}]}, {"id": "open-design", "heading": "Дизайн із Gemini CLI всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це шар дизайну з відкритим кодом, якого постійно потребує описаний вище робочий процес. Він трактує Gemini CLI як рідний адаптер і обгортає його в підібрану бібліотеку навичок і дизайн-систем, структурований конвеєр рендерингу та локальний десктопний UI — тож контекст дизайну, який робить Gemini хорошим, наявний від першого запуску, а не збирається вручну щоразу. Обидва мають відкритий код і працюють локально передусім, що робить це поєднання природним."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Gemini CLI як свого агента.", "Автентифікуйтеся за допомогою облікового запису Google або ключа API Gemini (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живуть у вашому власному репозиторії, а не в хмарі хостингу."]}, {"kind": "p", "text": "Той самий агент Gemini CLI, той самий ключ — плюс справжній, переносний робочий процес дизайну з відкритим кодом навколо нього. Він локальний передусім і Apache-2.0, тож ніщо у вашій роботі чи ваших облікових даних не залишає вашу машину."}]}], "faqTitle": "Поширені запитання", "faq": [{"name": "Чи може Gemini CLI справді виконувати роботу з дизайном?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Gemini CLI створює адаптивний UI продакшн-якості, а його потужні мультимодальні моделі перевіряють вихід відносно референсів. Без цього контексту він схиляється до стандартного шаблонного вигляду — і саме цей розрив закриває Open Design."}, {"name": "Чи потрібно платити, щоб робити дизайн з Gemini CLI?", "text": "Ні — вхід з обліковим записом Google дає щедрий безкоштовний рівень, а ви також можете принести свій ключ API Gemini (BYOK) або використати Vertex AI. Open Design у будь-якому разі ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Gemini CLI хорошим саме для дизайну?", "text": "Дві речі: його моделі мають потужну мультимодальність, тож він добре читає референсні скриншоти, а його контекст на 1 млн токенів може вмістити цілу дизайн-систему та набір референсів одночасно. Обидві допомагають — але смак усе одно походить від дизайн-системи, навички та референсів, які надаєте ви."}, {"name": "Gemini CLI чи Claude Code для дизайну фронтенду?", "text": "Обидва потужні. Claude Code відомий конкретними дизайн-рішеннями з обізнаністю про кодову базу; перевага Gemini CLI — мультимодальне розуміння плюс величезний контекст і безкоштовний рівень. Багато команд використовують обидва — Open Design дає змогу перемикати агентів, не змінюючи ваш робочий процес дизайну."}, {"name": "Як підключити Gemini CLI до Figma?", "text": "Додайте сервер Figma MCP у розділ mcpServers у ~/.gemini/settings.json. Тоді Gemini зможе підтягувати реальний дизайн-контекст — компоненти, змінні, дані макета — щоб згенерований код відповідав джерелу, а не наближався до нього."}, {"name": "Чи пов’язаний Open Design із Google?", "text": "Ні. Gemini CLI — продукт Google; Open Design — незалежний проєкт із відкритим кодом, який підтримує його як рідний адаптер. Gemini є торговою маркою Google."}, {"name": "Чи в безпеці мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Google використовуються безпосередньо вашим агентом і ніколи не маршрутизуються через сервери Open Design."}], "ctaTitle": "Дизайн із Gemini CLI, відкритим способом.", "ctaBody": "Принесіть свій обліковий запис Google або ключ API Gemini, тримайте кожен файл локально й отримайте підібрану бібліотеку дизайну навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Gemini CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставте зірку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажте десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'copilot': {
        ...en['copilot']!,
        title: "GitHub Copilot CLI для дизайну — Open Design",
        description: "Як люди використовують GitHub Copilot CLI для UI- та вебдизайну — його термінальний агент для кодування, файли з користувацькими інструкціями, підтримку MCP і вибір серед кількох моделей — і як Open Design перетворює Copilot CLI на локальний дизайн-агент з відкритим кодом.",
        breadcrumb: "GitHub Copilot CLI",
        label: "Агент · GitHub Copilot CLI",
        heading: "GitHub Copilot CLI для дизайну.",
        lead: "GitHub Copilot CLI — це термінальний агент GitHub для кодування. Він планує та редагує зміни в усьому репозиторії, обирає серед передових моделей на кшталт Claude і GPT та читає інструкції вашого репозиторію — а це робить його справжнім інструментом для дизайну, щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його в дизайн-процес з відкритим кодом: ваша підписка GitHub Copilot, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює GitHub Copilot CLI на локальний дизайн-агент з відкритим кодом — ваша підписка GitHub Copilot, ваші файли, а навколо нього — кураторська бібліотека skill і дизайн-систем.", "heroCtaActions": [{"label": "Використати Copilot CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["GitHub Copilot CLI — це термінальний агент GitHub для кодування, той самий агентний рушій, що живить Copilot coding agent, перенесений у командний рядок. Дві речі роблять його цікавим саме для дизайну: він читає інструкції вашого репозиторію та AGENTS.md, тож ваші дизайн-конвенції подорожують з агентом під час кожного запуску; і він дає змогу обирати серед передових моделей від Anthropic, OpenAI та Google для кожної задачі, тож ви можете взяти ту, що найкраще розмірковує над конкретним UI. У поєднанні з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI — і працює на підписці Copilot, яка, можливо, у вас уже є. Це практичний наскрізний посібник з використання Copilot CLI для роботи над UI, фронтендом і дизайн-системами та з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим Copilot CLI є насправді, чому інструкції репозиторію та вибір моделі пасують дизайну, як налаштувати його з нуля, цикл «скриншот → UI», як користувацькі інструкції та MCP розширюють його, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які вивід штучного інтелекту виглядає шаблонно, і як Open Design закриває цей розрив як відкритий локальний дизайн-шар — ваша підписка та облікові дані залишаються на вашій машині, ваші артефакти залишаються у вашому власному репозиторії."], "heroImage": {"src": "/agents/copilot-design/copilot-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну в GitHub Copilot CLI: термінальний агент читає референсне зображення, браузер відмальовує UI, і робочий простір, зі стрілкою зворотного зв'язку, що замикається назад", "caption": "Основний цикл: Copilot CLI читає ваші референси в терміналі, будує та перевіряє UI в реальному браузері й ітерує проти них — з вашими дизайн-конвенціями в інструкціях репозиторію."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-copilot", "label": "Чим насправді є GitHub Copilot CLI"}, {"id": "why-design", "label": "Чому інструкції + вибір моделі пасують дизайну"}, {"id": "setup", "label": "Налаштування Copilot CLI для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "extend", "label": "Користувацькі інструкції, MCP та розширення"}, {"id": "vs", "label": "Copilot CLI проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Copilot CLI в Open Design"}, {"id": "faq", "label": "Поширені запитання"}], "sections": [{"id": "what-is-copilot", "heading": "Чим насправді є GitHub Copilot CLI", "blocks": [{"kind": "p", "text": "GitHub Copilot CLI — це термінальний агент GitHub для кодування. Він читає ваш репозиторій, редагує файли, виконує команди оболонки й працює безпосередньо з вашим контекстом GitHub — issue, pull request і репозиторіями — автентифікуючись через ваш наявний обліковий запис GitHub. Він живиться тим самим агентним рушієм, що й Copilot coding agent від GitHub, тож планує складні задачі та ітерує, а не лише доповнює рядки. Він став загальнодоступним у лютому 2026 року після публічного попереднього перегляду, що відкрився у вересні 2025 року."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Він читає файли з користувацькими інструкціями — правила на рівні всього репозиторію в .github/copilot-instructions.md плюс AGENTS.md — тож ваші дизайн-конвенції автоматично враховуються під час кожного запуску. І він підтримує кількох постачальників базових моделей, тож ви можете перемикати модель для кожної задачі командою /model на ту, що найкраще розмірковує над конкретним UI."}, {"kind": "steps", "items": [{"label": "Файли інструкцій", "body": "Copilot CLI читає інструкції репозиторію в .github/copilot-instructions.md, файли для конкретних шляхів у .github/instructions та AGENTS.md — природне місце, щоб закодувати ваші дизайн-конвенції, токени та чеклісти перевірки."}, {"label": "Вбудовані інструменти + MCP", "body": "Він постачається з вбудованим MCP-сервером GitHub і виконує файлові та оболонкові інструменти, а ви можете додавати власні MCP-сервери через /mcp add (зберігаються в mcp-config.json у ~/.copilot) для зовнішнього контексту на кшталт живого файлу Figma."}, {"label": "Вибір моделі", "body": "Використовуйте команду /model, щоб обрати серед передових моделей від Anthropic, OpenAI та Google — перемикаючись для кожної задачі, усе на вашій наявній підписці Copilot."}]}, {"kind": "ul", "items": ["Постачальник: GitHub", "Облікові дані: активна підписка GitHub Copilot (Pro, Pro+, Business або Enterprise)", "Встановлення: npm install -g @github/copilot, потім запустіть copilot"]}]}, {"id": "why-design", "heading": "Чому інструкції репозиторію та вибір моделі пасують дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Copilot CLI походить від двох властивостей — але, як і з кожним агентом, смак усе одно треба постачати."}, {"kind": "steps", "items": [{"label": "Конвенції, що подорожують з репозиторієм", "body": "Оскільки Copilot CLI автоматично читає .github/copilot-instructions.md і AGENTS.md, ваші токени, примітиви та правила перевірки в контексті під час кожного запуску — агент працює над брендом, а не дефолтним виглядом."}, {"label": "Оберіть правильну модель для задачі", "body": "Вибір моделі серед Anthropic, OpenAI та Google означає, що ви можете взяти ту, яка найкраще розмірковує над конкретним макетом, а потім перемкнутися для наступної задачі — без зміни вашого робочого процесу."}, {"label": "Справжні специфікації через MCP", "body": "Вбудований MCP-сервер GitHub плюс MCP-сервер Figma спрямовують агента на ваші токени, компоненти та справжні специфікації, тож він будує з першоджерела, а не наближено."}]}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак походить від трьох вхідних даних, які ви надаєте: дизайн-системи, skill і справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, що вчить кожен агент: Copilot CLI не має смаку за замовчуванням. Він видає добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (детальніше нижче)."}]}, {"id": "setup", "heading": "Налаштування Copilot CLI для дизайнерської роботи, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Copilot CLI, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Copilot CLI (Node.js required)\nnpm install -g @github/copilot\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ncopilot           # run /login and follow the prompts to sign in\n\n# 3. Choose a model for the task\n#    inside the session:\n/model            # pick a frontier model from Anthropic, OpenAI, or Google\n\n# 4. Add custom instructions and the Figma MCP server (optional)\n#    write .github/copilot-instructions.md or AGENTS.md\n/mcp add          # add the Figma MCP server for design handoff"}, {"kind": "image", "src": "/agents/copilot-design/copilot-design-setup-flow.webp", "alt": "Робочий процес налаштування з п'яти кроків: встановлення, автентифікація, вибір моделі, налаштування інструкцій, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → вибір моделі → написання інструкцій → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Розмістіть свої токени, примітиви та конвенції в .github/copilot-instructions.md або AGENTS.md, щоб вивід відповідав бренду, а не звертався за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Copilot відмальовував у реальному браузері та перевіряв свій вивід на різних точках зламу, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найвпливовіший дизайн-цикл з Copilot CLI — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не збігатиметься — спираючись на потужну мультимодальну модель, щоб порівнювати вивід назад із референсом."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і включайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретними у запиті; розпливчасті запити дають шаблонний UI навіть із потужною моделлю.", "Тримайте свою дизайн-систему та конвенції в .github/copilot-instructions.md або AGENTS.md і вказуйте Copilot, де живуть токени та канонічні примітиви.", "Запустіть dev-сервер і нехай Copilot відмальовує в реальному браузері, змінюючи розмір до точок зламу, щоб перевірити результат.", "Ітеруйте, змушуючи Copilot порівнювати свою реалізацію назад зі скриншотами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Спрямуйте Copilot на ваші референсні зображення та дайте конкретні обмеження; він показує попередній перегляд кожного редагування файлу чи команди для вашого схвалення перед виконанням:"}, {"kind": "code", "lang": "bash", "code": "copilot\n# in the prompt:\n> Implement the design in reference-desktop.png and reference-mobile.png\n  in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens described in\n  .github/copilot-instructions.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Тримайте запити маленькими та сфокусованими, фіксуйте вдалі ітерації та відкочуйте невдалі (повідомляючи Copilot, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "extend", "heading": "Користувацькі інструкції, MCP та розширення", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Copilot CLI практичним для тривалої дизайнерської роботи, і всі три чисто лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Користувацькі інструкції", "body": "Правила репозиторію живуть у .github/copilot-instructions.md (з файлами для конкретних шляхів у .github/instructions та AGENTS.md). Це довговічний дім для ваших дизайн-конвенцій, що враховується автоматично під час кожного запуску."}, {"label": "MCP-сервери", "body": "Copilot CLI постачається з вбудованим MCP-сервером GitHub і дає змогу додавати власні сервери через /mcp add (зберігаються в mcp-config.json у ~/.copilot) — переносний спосіб залучити дизайн-контекст, найбільш доречно MCP-сервер Figma, що працює між агентами, а не лише в Copilot."}, {"label": "Спеціалізовані агенти та вбудовані інструменти", "body": "Спеціалізовані режими Copilot CLI — для дослідження кодової бази, запуску збірок і тестів, перегляду змін і планування — плюс його файлові та оболонкові інструменти дають йому змогу збирати референси та виконувати цикл перевірки, не залишаючи термінала."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати для кожного проєкту наново."}]}, {"id": "vs", "heading": "Copilot CLI проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Для дизайнерської роботи немає єдиного переможця — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська перевага", "Найкраще для"], "rows": [["Copilot CLI", "Вибір серед кількох моделей (Anthropic, OpenAI, Google) і глибока інтеграція з GitHub на вашій підписці Copilot", "Вибору найкращої моделі для кожної задачі та роботи на основі інструкцій, прив'язаної до вашого репозиторію GitHub"], ["Codex", "Сильне візуальне доопрацювання з фронтенд-skill; пісочничні асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів з великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і подивися» з живим попереднім переглядом і вбудованими редагуваннями", "Щільної роботи над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1M токенів; з відкритим кодом і безкоштовним тарифом", "Роботи, насиченої скриншотами, та утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти полягає в тому, що смак походить від людей: усі вони за замовчуванням звертаються до шаблонної естетики без skill, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструменту, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований штучним інтелектом дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно великі заокруглені кути, драматичні тіні, вайб Inter-та-фіолетового, що «кричить, що це зробив ШІ». Інші повідомлювані проблеми включають зламані мобільні макети та інструкції, що протікають у текст UI. Жодна з них не є унікальною для Copilot CLI; це те, що стається, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичний skill", "body": "Кураторський дизайн-skill змушує агента взяти курс на справжній напрям замість дефолтного вигляду."}, {"label": "Перевіряйте в реальному браузері", "body": "Відмальовуйте та самоперевіряйте на різних точках зламу з браузерним MCP, щоб макети не ламалися мовчки на мобільному."}, {"label": "Постачайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це єдиний найбільший важіль на якість виводу."}, {"label": "Закодуйте правила в користувацьких інструкціях", "body": "Розмістіть правила на кшталт «без головних карток, максимум два шрифти, ієрархія передусім за брендом» у .github/copilot-instructions.md або AGENTS.md, де агент читає їх під час кожного запуску."}]}, {"kind": "p", "text": "Зауважте, що кожне пом'якшення полягає в наданні агентові кураторського дизайн-контексту. Підтримування цього контексту вручну, для кожного проєкту, — це рутина, яку Open Design прибирає."}]}, {"id": "open-design", "heading": "Дизайн із Copilot CLI всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це дизайн-шар з відкритим кодом, якого робочий процес вище постійно вимагає. Він трактує GitHub Copilot CLI як рідний адаптер і обгортає його в кураторську бібліотеку skill і дизайн-систем, структурований конвеєр рендерингу та локальний десктопний UI — тож дизайн-контекст, що робить Copilot добрим, є там з першого запуску, а не збирається вручну щоразу. Open Design незалежний, з відкритим кодом (Apache-2.0) і локальний передусім, тому це поєднання пасує: агент робить роботу, ваші файли та облікові дані залишаються вашими."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть GitHub Copilot CLI як свого агента.", "Автентифікуйтеся зі своєю підпискою GitHub Copilot — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, потім генеруйте презентації, прототипи та лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хмарі на хостингу."]}, {"kind": "p", "text": "Той самий агент Copilot CLI, та сама підписка — плюс справжній, переносний дизайн-процес з відкритим кодом навколо нього. Open Design локальний передусім і Apache-2.0, тож ніщо про вашу роботу чи ваші облікові дані не залишає вашої машини."}]}], "faqTitle": "Поширені запитання", "faq": [{"name": "Чи може GitHub Copilot CLI справді робити дизайнерську роботу?", "text": "Так — з естетичним skill, дизайн-системою та справжніми референсними зображеннями в контексті Copilot CLI видає продакшн-якісний адаптивний UI, і ви можете обрати модель, що найкраще перевіряє вивід проти референсів. Без цього контексту він схильний за замовчуванням звертатися до шаблонного вигляду, і саме цей розрив закриває Open Design."}, {"name": "Чи потрібна мені підписка, щоб робити дизайн з Copilot CLI?", "text": "Так — Copilot CLI працює на активній підписці GitHub Copilot (Pro, Pro+, Business або Enterprise); це не модель «принеси свій ключ». Ви автентифікуєтеся зі своїм обліковим записом GitHub. Open Design ніколи не проксіює ваші облікові дані — ваша підписка використовується безпосередньо вашим агентом."}, {"name": "Що робить Copilot CLI добрим саме для дизайну?", "text": "Дві речі: він автоматично читає інструкції репозиторію та AGENTS.md, тож ваші дизайн-конвенції подорожують з репозиторієм; і він дає змогу перемикатися серед передових моделей від Anthropic, OpenAI та Google для кожної задачі. Обидва допомагають — але смак усе одно походить від дизайн-системи, skill і референсів, які ви постачаєте."}, {"name": "Copilot CLI чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Copilot CLI — вибір моделі серед постачальників і глибока інтеграція з GitHub на підписці, яка, можливо, у вас уже є. Багато команд використовують обидва — Open Design дає змогу перемикати агентів без зміни вашого дизайн-процесу."}, {"name": "Як підключити Copilot CLI до Figma?", "text": "Додайте MCP-сервер Figma командою /mcp add; налаштування зберігаються в mcp-config.json у ~/.copilot. Тоді Copilot може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код збігається з першоджерелом, а не наближає його."}, {"name": "Чи пов'язаний Open Design з GitHub або Microsoft?", "text": "Ні. GitHub Copilot CLI — це продукт GitHub; Open Design — це незалежний проєкт з відкритим кодом, що підтримує його як рідний адаптер. GitHub Copilot є торговельною маркою GitHub, Inc. і Microsoft."}, {"name": "Чи в безпеці мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані GitHub Copilot використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Дизайн із GitHub Copilot CLI, відкритим шляхом.", "ctaBody": "Принесіть свою підписку GitHub Copilot, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використати Copilot CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'qwen': {
        ...en['qwen']!,
        title: "Qwen Code для дизайну — Open Design",
        description: "Як люди використовують Qwen Code CLI з відкритим кодом від Alibaba для UI- та вебдизайну — його моделі Qwen3-Coder, велике контекстне вікно, QWEN.md і MCP — і як Open Design перетворює Qwen Code на локальний дизайн-агент з відкритим кодом.",
        breadcrumb: "Qwen Code",
        label: "Агент · Qwen Code",
        heading: "Qwen Code для дизайну.",
        lead: "Qwen Code — це термінальний агент з відкритим кодом від Alibaba, адаптований із Gemini CLI та налаштований під моделі Qwen3-Coder. Його велике контекстне вікно вміщає цілу дизайн-систему одразу, що робить його справжнім інструментом для дизайну — щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його в дизайн-процес з відкритим кодом: ваш API-ключ DashScope або Qwen, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Qwen Code на локальний дизайн-агент з відкритим кодом — ваш API-ключ DashScope або Qwen, ваші файли, а навколо нього — кураторська бібліотека skill і дизайн-систем.", "heroCtaActions": [{"label": "Використати Qwen Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qwen Code — це ШІ-агент з відкритим кодом для термінала від Alibaba. Він адаптований із Gemini CLI від Google, з адаптаціями на рівні парсера та промптів, що дають змогу отримати максимум від моделей Qwen3-Coder. Дві речі роблять його цікавим саме для дизайну: це потужна агентна модель для кодування, тож вона планує, редагує файли та виконує цикл збірки й перевірки з природномовної задачі; і її велике контекстне вікно може вмістити цілу дизайн-систему та кодову базу одразу. У поєднанні з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI — і він з відкритим кодом і BYOK, тож ви приносите свій власний ключ. Це практичний наскрізний посібник з використання Qwen Code для роботи над UI, фронтендом і дизайн-системами та з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим Qwen Code є насправді, чому потужна модель для кодування плюс великий контекст пасують дизайну, як налаштувати його з нуля, цикл «референс → UI», як QWEN.md і MCP розширюють його, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які вивід штучного інтелекту виглядає шаблонно, і як Open Design закриває цей розрив як відкритий локальний дизайн-шар — природне поєднання, адже обидва з відкритим кодом і працюють на вашій власній машині."], "heroImage": {"src": "/agents/qwen-design/qwen-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну в Qwen Code: термінальний агент читає референсне зображення, браузер відмальовує UI, і робочий простір, зі стрілкою зворотного зв'язку, що замикається назад", "caption": "Основний цикл: Qwen Code читає ваші референси в терміналі, будує та перевіряє UI в реальному браузері й ітерує проти них — з цілою дизайн-системою в контексті."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-qwen", "label": "Чим насправді є Qwen Code"}, {"id": "why-design", "label": "Чому потужна модель для кодування + великий контекст пасують дизайну"}, {"id": "setup", "label": "Налаштування Qwen Code для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «референс → UI»"}, {"id": "extend", "label": "QWEN.md, MCP та розширення"}, {"id": "vs", "label": "Qwen Code проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Qwen Code в Open Design"}, {"id": "faq", "label": "Поширені запитання"}], "sections": [{"id": "what-is-qwen", "heading": "Чим насправді є Qwen Code", "blocks": [{"kind": "p", "text": "Qwen Code — це ШІ-агент з відкритим кодом (Apache-2.0), який Alibaba постачає для термінала. Він читає ваш репозиторій, редагує файли, виконує команди оболонки та працює з вебом — плануючи та перевіряючи роботу з природномовних задач, а не лише доповнюючи рядки. Він адаптований із Gemini CLI від Google, з адаптаціями на рівні парсера та промптів, налаштованими, щоб розкрити моделі Qwen3-Coder на агентних задачах кодування."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Це здатна агентна модель для кодування, тож вона може взяти референс і чітке завдання та збудувати, запустити й самовиправити адаптивний UI. І моделі Qwen3-Coder несуть велике контекстне вікно, достатньо велике, щоб вмістити цілу вашу дизайн-систему, бібліотеку компонентів і набір референсів одразу замість того, щоб стискати їх до резюме."}, {"kind": "steps", "items": [{"label": "Контекстні файли", "body": "Qwen Code читає файл QWEN.md для постійного контексту проєкту — природне місце, щоб закодувати ваші дизайн-конвенції, токени та чеклісти перевірки. Особисті та проєктні налаштування накладаються згори."}, {"label": "Вбудовані інструменти + MCP", "body": "Він постачається з файловими, оболонковими та вебінструментами з коробки й підтримує MCP-сервери (налаштовуються під mcpServers у ~/.qwen/settings.json), щоб додати зовнішній контекст на кшталт живого файлу Figma."}, {"label": "BYOK для початку", "body": "Ви приносите свій власний ключ — API-ключ DashScope (Alibaba Cloud Model Studio) або будь-яку OpenAI-сумісну кінцеву точку чи ModelScope — і налаштовуєте його в settings.json."}]}, {"kind": "ul", "items": ["Постачальник: Alibaba", "Облікові дані: API-ключ DashScope / Qwen (BYOK) або OpenAI-сумісна кінцева точка / ModelScope", "Ліцензія: Apache-2.0, відкритий код (адаптований із Gemini CLI)"]}]}, {"id": "why-design", "heading": "Чому потужна модель для кодування та великий контекст пасують дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Qwen Code походить від двох властивостей — але, як і з кожним агентом, смак усе одно треба постачати."}, {"kind": "steps", "items": [{"label": "Потужне агентне кодування", "body": "Моделі Qwen3-Coder налаштовані під агентні задачі, тож агент планує, редагує, запускає збірку та самовиправляється — перетворюючи чіткий референс і завдання на адаптивну розмітку, а не одноразову здогадку."}, {"label": "Велике контекстне вікно", "body": "Великий контекст Qwen3-Coder означає, що ціла дизайн-система, токени та багато референсних станів вміщаються одразу, тож агент перевикористовує ваші справжні примітиви, а не вигадує одноразові стилі."}, {"label": "Конвенції в QWEN.md", "body": "QWEN.md (плюс MCP-сервер Figma) спрямовує агента на ваші токени, компоненти та справжні специфікації, тож він працює над брендом, а не дефолтним виглядом."}]}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак походить від трьох вхідних даних, які ви надаєте: дизайн-системи, skill і справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, що вчить кожен агент: Qwen Code не має смаку за замовчуванням. Він видає добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (детальніше нижче)."}]}, {"id": "setup", "heading": "Налаштування Qwen Code для дизайнерської роботи, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Qwen Code, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qwen Code (Node 22+)\nnpm install -g @qwen-code/qwen-code@latest\n# or: brew install qwen-code\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nqwen              # run /auth, or set a key in ~/.qwen/settings.json\n\n# 3. Configure a DashScope (OpenAI-compatible) key in settings.json\n#    baseUrl: https://dashscope.aliyuncs.com/compatible-mode/v1\n#    model:   qwen3-coder-plus   (set DASHSCOPE_API_KEY)\n\n# 4. Add a QWEN.md and wire the Figma MCP server (optional)\n#    add MCP under \"mcpServers\" in ~/.qwen/settings.json"}, {"kind": "image", "src": "/agents/qwen-design/qwen-design-setup-flow.webp", "alt": "Робочий процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування QWEN.md, додавання skill, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування QWEN.md → додавання skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Розмістіть свої токени, примітиви та конвенції в QWEN.md і спрямуйте Qwen Code на них, щоб вивід відповідав бренду, а не звертався за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Qwen Code відмальовував у реальному браузері та перевіряв свій вивід на різних точках зламу, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «референс → UI»", "blocks": [{"kind": "p", "text": "Найвпливовіший дизайн-цикл з Qwen Code — це перетворення референсу на робочий адаптивний UI та ітерування, доки воно не збігатиметься — спираючись на агента, щоб будувати, відмальовувати та порівнювати свій вивід назад із референсом."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і описуйте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретними у запиті; розпливчасті запити дають шаблонний UI навіть із потужною моделлю.", "Тримайте свою дизайн-систему та конвенції в QWEN.md і вказуйте Qwen Code, де живуть токени та канонічні примітиви.", "Запустіть dev-сервер і нехай Qwen Code відмальовує в реальному браузері, змінюючи розмір до точок зламу, щоб перевірити результат.", "Ітеруйте, змушуючи Qwen Code порівнювати свою реалізацію назад із референсами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Посилайтеся на файл через @, щоб прикріпити його до запиту, а потім дайте конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "qwen\n# in the prompt:\n> @reference-desktop.png @reference-mobile.png\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from QWEN.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Тримайте запити маленькими та сфокусованими, фіксуйте вдалі ітерації та відкочуйте невдалі (повідомляючи Qwen Code, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "extend", "heading": "QWEN.md, MCP та розширення", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Qwen Code практичним для тривалої дизайнерської роботи, і всі три чисто лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Контекст QWEN.md", "body": "Правила проєкту живуть у QWEN.md у корені репозиторію (з глобальним і проєктним шарами). Це довговічний дім для ваших дизайн-конвенцій, що читається під час кожного запуску."}, {"label": "MCP-сервери", "body": "Налаштовуйте MCP-сервери під mcpServers у ~/.qwen/settings.json — переносний спосіб залучити дизайн-контекст і зовнішні інструменти, найбільш доречно MCP-сервер Figma, що працюють між агентами, а не лише в Qwen Code."}, {"label": "Skill і вбудовані інструменти", "body": "Skill Qwen Code та його вбудовані файлові, оболонкові та вебінструменти дають йому змогу збирати референси та виконувати цикл перевірки, не залишаючи термінала."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати для кожного проєкту наново."}]}, {"id": "vs", "heading": "Qwen Code проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Для дизайнерської роботи немає єдиного переможця — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська перевага", "Найкраще для"], "rows": [["Qwen Code", "Потужне агентне кодування на відкритих моделях Qwen3-Coder з великим контекстом; з відкритим кодом і BYOK", "Збірок з відкритим кодом і гнучкими ключами, що утримують цілу дизайн-систему в контексті"], ["Codex", "Сильне візуальне доопрацювання з фронтенд-skill; пісочничні асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів з великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і подивися» з живим попереднім переглядом і вбудованими редагуваннями", "Щільної роботи над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1M токенів; агент, з якого адаптований Qwen Code", "Роботи, насиченої скриншотами, та дуже великого контексту"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти полягає в тому, що смак походить від людей: усі вони за замовчуванням звертаються до шаблонної естетики без skill, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструменту, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований штучним інтелектом дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно великі заокруглені кути, драматичні тіні, вайб Inter-та-фіолетового, що «кричить, що це зробив ШІ». Інші повідомлювані проблеми включають зламані мобільні макети та інструкції, що протікають у текст UI. Жодна з них не є унікальною для Qwen Code; це те, що стається, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичний skill", "body": "Кураторський дизайн-skill змушує агента взяти курс на справжній напрям замість дефолтного вигляду."}, {"label": "Перевіряйте в реальному браузері", "body": "Нехай агент відмальовує та самоперевіряє на різних точках зламу, щоб макети не ламалися мовчки на мобільному."}, {"label": "Постачайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це єдиний найбільший важіль на якість виводу."}, {"label": "Закодуйте правила в QWEN.md", "body": "Розмістіть правила на кшталт «без головних карток, максимум два шрифти, ієрархія передусім за брендом» там, де агент читає їх під час кожного запуску."}]}, {"kind": "p", "text": "Зауважте, що кожне пом'якшення полягає в наданні агентові кураторського дизайн-контексту. Підтримування цього контексту вручну, для кожного проєкту, — це рутина, яку Open Design прибирає."}]}, {"id": "open-design", "heading": "Дизайн із Qwen Code всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це дизайн-шар з відкритим кодом, якого робочий процес вище постійно вимагає. Він трактує Qwen Code як рідний адаптер і обгортає його в кураторську бібліотеку skill і дизайн-систем, структурований конвеєр рендерингу та локальний десктопний UI — тож дизайн-контекст, що робить Qwen Code добрим, є там з першого запуску, а не збирається вручну щоразу. Обидва з відкритим кодом і локальні передусім, що робить це поєднання природним."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Qwen Code як свого агента.", "Автентифікуйтеся зі своїм API-ключем DashScope або Qwen (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, потім генеруйте презентації, прототипи та лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хмарі на хостингу."]}, {"kind": "p", "text": "Той самий агент Qwen Code, той самий ключ — плюс справжній, переносний дизайн-процес з відкритим кодом навколо нього. Він локальний передусім і Apache-2.0, тож ніщо про вашу роботу чи ваші облікові дані не залишає вашої машини."}]}], "faqTitle": "Поширені запитання", "faq": [{"name": "Чи може Qwen Code справді робити дизайнерську роботу?", "text": "Так — з естетичним skill, дизайн-системою та справжніми референсними зображеннями в контексті Qwen Code видає продакшн-якісний адаптивний UI, а його агентний цикл будує, відмальовує та перевіряє вивід проти референсів. Без цього контексту він схильний за замовчуванням звертатися до шаблонного вигляду, і саме цей розрив закриває Open Design."}, {"name": "Чи потрібно платити, щоб робити дизайн з Qwen Code?", "text": "Qwen Code безкоштовний і з відкритим кодом, але він BYOK — ви приносите API-ключ DashScope (Alibaba Cloud Model Studio), OpenAI-сумісну кінцеву точку або ModelScope. Alibaba також пропонує тариф для кодування з фіксованою платою. Open Design ніколи не проксіює ваші облікові дані в будь-якому разі."}, {"name": "Що робить Qwen Code добрим саме для дизайну?", "text": "Дві речі: моделі Qwen3-Coder налаштовані під агентне кодування, тож агент будує та самовиправляє адаптивний UI, а їхній великий контекст може вмістити цілу дизайн-систему та набір референсів одразу. Обидва допомагають — але смак усе одно походить від дизайн-системи, skill і референсів, які ви постачаєте."}, {"name": "Чи Qwen Code те саме, що й Gemini CLI?", "text": "Ні. Qwen Code адаптований із Gemini CLI від Google — той самий родовід з відкритим кодом — з адаптаціями на рівні парсера та промптів, що налаштовують його під моделі Qwen3-Coder. Open Design підтримує обидва, тож ви можете перемикати агентів без зміни вашого дизайн-процесу."}, {"name": "Як підключити Qwen Code до Figma?", "text": "Додайте MCP-сервер Figma під mcpServers у ~/.qwen/settings.json. Тоді Qwen Code може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код збігається з першоджерелом, а не наближає його."}, {"name": "Чи пов'язаний Open Design з Alibaba або Qwen?", "text": "Ні. Qwen Code — це продукт Alibaba; Open Design — це незалежний проєкт з відкритим кодом, що підтримує його як рідний адаптер. Qwen є торговельною маркою Alibaba."}, {"name": "Чи в безпеці мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані DashScope або Qwen використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Дизайн із Qwen Code, відкритим шляхом.", "ctaBody": "Принесіть свій власний API-ключ DashScope або Qwen, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використати Qwen Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'grok': {
        ...en['grok']!,
        title: "Grok Build для дизайну — Open Design",
        description: "Як люди використовують Grok Build (Grok Build) від xAI для UI- та вебдизайну — його режим планування, AGENTS.md і MCP, моделі Grok з підтримкою зображень і великий контекст — і як Open Design перетворює Grok Build на локальний дизайн-агент з відкритим кодом.",
        breadcrumb: "Grok Build",
        label: "Агент · Grok Build",
        heading: "Grok Build для дизайну.",
        lead: "Grok Build — це термінальний агент xAI для кодування. Він планує багатокрокову роботу, перш ніж торкнутися ваших файлів, читає зображення поряд із кодом і виконує цикл «збудуй і перевір» у вашому репозиторії — що робить його справжнім інструментом для дизайну, щойно ви даєте йому референси, конвенції та крок перевірки. Open Design вбудовує його в дизайн-процес з відкритим кодом: ваш вхід SuperGrok або API-ключ xAI, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Grok Build на локальний дизайн-агент з відкритим кодом — ваш вхід SuperGrok або API-ключ xAI, ваші файли, а навколо нього — кураторська бібліотека skill і дизайн-систем.", "heroCtaActions": [{"label": "Використати Grok Build в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Grok Build — термінальний агент xAI для кодування, що постачається як Grok Build, — це агентний інструмент, який живе у вашому терміналі. Дві речі роблять його цікавим саме для дизайну: він планує ризиковану роботу, перш ніж діяти, тож ви можете переглянути запропонований підхід до того, як будь-які файли зміняться; і його моделі Grok приймають зображення на вхід, тож можуть розмірковувати про референсний скриншот поряд із кодом, який пишуть. У поєднанні з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI — автентифікуючись прямо через ваш обліковий запис SuperGrok або X Premium+, без жонглювання API-ключами. Це практичний наскрізний посібник з використання Grok Build для роботи над UI, фронтендом і дизайн-системами та з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим Grok Build є насправді, чому режим планування та моделі з підтримкою зображень пасують дизайну, як налаштувати його з нуля, цикл «скриншот → UI», як AGENTS.md і MCP розширюють його, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які вивід штучного інтелекту виглядає шаблонно, і як Open Design закриває цей розрив як відкритий локальний дизайн-шар — ваші облікові дані та артефакти ніколи не залишають вашої машини."], "heroImage": {"src": "/agents/grok-design/grok-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну в Grok Build: термінальний агент планує з референсного зображення, браузер відмальовує UI, і робочий простір, зі стрілкою зворотного зв'язку, що замикається назад", "caption": "Основний цикл: Grok Build планує з ваших референсів у терміналі, будує та перевіряє UI в реальному браузері й ітерує проти них — з вашими конвенціями в AGENTS.md."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-grok", "label": "Чим насправді є Grok Build"}, {"id": "why-design", "label": "Чому режим планування + зображення на вході пасують дизайну"}, {"id": "setup", "label": "Налаштування Grok Build для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот → UI»"}, {"id": "extend", "label": "AGENTS.md, MCP та субагенти"}, {"id": "vs", "label": "Grok Build проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Grok Build в Open Design"}, {"id": "faq", "label": "Поширені запитання"}], "sections": [{"id": "what-is-grok", "heading": "Чим насправді є Grok Build", "blocks": [{"kind": "p", "text": "Grok Build — це термінальний агент xAI для кодування, що постачається під назвою Grok Build. Він читає ваш репозиторій, редагує файли, виконує команди оболонки та планує багатокрокову інженерну роботу з природномовних задач, а не лише доповнює рядки. Він побудований навколо моделей Grok від xAI — представлених в API xAI як сімейство моделей grok-build — і автентифікується через ваш обліковий запис xAI, тож агент і моделі походять від одного постачальника."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. У нього є режим планування, що складає структурований підхід, який ви можете схвалити, прокоментувати або переписати до того, як будь-яка зміна закріпиться — корисний шлюз, коли ви ітеруєте над UI. І його моделі Grok приймають зображення на вхід, тож ви можете дати йому референсний скриншот, і він розмірковуватиме про справжній макет замість того, щоб здогадуватися з текстового опису."}, {"kind": "steps", "items": [{"label": "Контекстні файли", "body": "Grok Build читає файл AGENTS.md для постійного контексту проєкту — природне місце, щоб закодувати ваші дизайн-конвенції, токени та чеклісти перевірки. Він дотримується тієї самої відкритої конвенції AGENTS.md, що використовують Codex та інші агенти."}, {"label": "Інструменти, MCP + субагенти", "body": "Він редагує файли, виконує команди оболонки та підтримує MCP-сервери, щоб додати зовнішній контекст на кшталт живого файлу Figma; для більших задач він може делегувати паралельним субагентам, що одночасно досліджують, будують і перевіряють."}, {"label": "Увійдіть зі своїм обліковим записом", "body": "Ви автентифікуєтеся, входячи через ваш браузер з підпискою SuperGrok або X Premium+; ви також можете принести API-ключ xAI для безголового та CI-використання."}]}, {"kind": "ul", "items": ["Постачальник: xAI", "Облікові дані: OAuth xAI SuperGrok (`grok login`) або API-ключ xAI (BYOK) для безголового використання", "Моделі: моделі Grok від xAI (сімейство grok-build в API xAI), із зображеннями на вході"]}]}, {"id": "why-design", "heading": "Чому режим планування та моделі з підтримкою зображень пасують дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Grok Build походить від двох властивостей — але, як і з кожним агентом, смак усе одно треба постачати."}, {"kind": "steps", "items": [{"label": "Міркування з підтримкою зображень", "body": "Оскільки моделі Grok приймають зображення на вхід, агент читає референсні скриншоти — порівнюючи свій відмальований вивід назад із зображенням замість того, щоб здогадуватися з текстового опису."}, {"label": "Режим планування до того, як зміни закріпляться", "body": "Режим планування складає структурований підхід, який ви схвалюєте до зміни файлів, тож дизайн-намір переглядається наперед, а не виявляється після diff."}, {"label": "Конвенції в AGENTS.md", "body": "AGENTS.md (плюс MCP-сервер Figma) спрямовує агента на ваші токени, компоненти та справжні специфікації, тож він працює над брендом, а не дефолтним виглядом."}]}, {"kind": "image", "src": "/agents/grok-design/grok-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак походить від трьох вхідних даних, які ви надаєте: дизайн-системи, skill і справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, що вчить кожен агент: Grok Build не має смаку за замовчуванням. Він видає добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (детальніше нижче)."}]}, {"id": "setup", "heading": "Налаштування Grok Build для дизайнерської роботи, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Grok Build, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Grok Build (Grok Build) on macOS/Linux\ncurl -fsSL https://x.ai/cli/install.sh | bash\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\ngrok login   # opens your browser; sign in with SuperGrok / X Premium+\n#   or, for headless / CI use, set an xAI API key:\n#   export XAI_API_KEY=xai-...\n\n# 3. Add project context\n#    create an AGENTS.md at the repo root with your design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to your MCP server configuration"}, {"kind": "image", "src": "/agents/grok-design/grok-design-setup-flow.webp", "alt": "Робочий процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування AGENTS.md, додавання skill, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування AGENTS.md → додавання skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Розмістіть свої токени, примітиви та конвенції в AGENTS.md і спрямуйте Grok на них, щоб вивід відповідав бренду, а не звертався за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Grok відмальовував у реальному браузері та перевіряв свій вивід на різних точках зламу, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот → UI»", "blocks": [{"kind": "p", "text": "Найвпливовіший дизайн-цикл з Grok Build — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не збігатиметься — спираючись на режим планування, щоб узгодити підхід, і на модель з підтримкою зображень, щоб порівнювати вивід назад із референсом."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і включайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретними у запиті; розпливчасті запити дають шаблонний UI навіть із потужною моделлю.", "Тримайте свою дизайн-систему та конвенції в AGENTS.md і вказуйте Grok, де живуть токени та канонічні примітиви.", "Використовуйте режим планування, щоб переглянути підхід, потім запустіть dev-сервер і нехай Grok відмальовує в реальному браузері, змінюючи розмір до точок зламу, щоб перевірити результат.", "Ітеруйте, змушуючи Grok порівнювати свою реалізацію назад зі скриншотами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Прикріпіть свої референсні зображення та дайте конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "grok\n# in the prompt (attach reference-desktop.png and reference-mobile.png):\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Show me the plan first, then render it in the browser and iterate\n  until it matches the references across breakpoints."}, {"kind": "p", "text": "Тримайте запити маленькими та сфокусованими, фіксуйте вдалі ітерації та відкочуйте невдалі (повідомляючи Grok, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "extend", "heading": "AGENTS.md, MCP та субагенти", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Grok Build практичним для тривалої дизайнерської роботи, і всі три чисто лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Контекст AGENTS.md", "body": "Правила проєкту живуть у AGENTS.md у корені репозиторію. Це довговічний дім для ваших дизайн-конвенцій, що читається під час кожного запуску — і це той самий відкритий формат, який розуміють інші агенти, тож правила подорожують з вами."}, {"label": "MCP-сервери", "body": "Налаштовуйте MCP-сервери, щоб залучити дизайн-контекст і зовнішні інструменти, найбільш доречно MCP-сервер Figma — переносний спосіб подати справжні специфікації в код, що працює між агентами, а не лише в Grok."}, {"label": "Субагенти та вбудовані інструменти", "body": "Grok Build може породжувати паралельних субагентів, щоб одночасно досліджувати, будувати та перевіряти, а його файлові, оболонкові та пошукові інструменти дають йому змогу збирати референси та виконувати цикл перевірки, не залишаючи термінала."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати для кожного проєкту наново."}]}, {"id": "vs", "heading": "Grok Build проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Для дизайнерської роботи немає єдиного переможця — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська перевага", "Найкраще для"], "rows": [["Grok Build", "Перегляд у режимі планування до того, як зміни закріпляться, моделі Grok з підтримкою зображень і паралельні субагенти; вхід зі своїм обліковим записом SuperGrok", "Переглянутих збірок UI з плануванням наперед і моделями xAI у циклі"], ["Codex", "Сильне візуальне доопрацювання з фронтенд-skill; пісочничні асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів з великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і подивися» з живим попереднім переглядом і вбудованими редагуваннями", "Щільної роботи над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і дуже великий контекст; з відкритим кодом і безкоштовним тарифом", "Роботи, насиченої скриншотами, та утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти полягає в тому, що смак походить від людей: усі вони за замовчуванням звертаються до шаблонної естетики без skill, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструменту, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований штучним інтелектом дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно великі заокруглені кути, драматичні тіні, вайб Inter-та-фіолетового, що «кричить, що це зробив ШІ». Інші повідомлювані проблеми включають зламані мобільні макети та інструкції, що протікають у текст UI. Жодна з них не є унікальною для Grok Build; це те, що стається, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичний skill", "body": "Кураторський дизайн-skill змушує агента взяти курс на справжній напрям замість дефолтного вигляду."}, {"label": "Перевіряйте в реальному браузері", "body": "Відмальовуйте та самоперевіряйте на різних точках зламу, щоб макети не ламалися мовчки на мобільному."}, {"label": "Постачайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це єдиний найбільший важіль на якість виводу."}, {"label": "Закодуйте правила в AGENTS.md", "body": "Розмістіть правила на кшталт «без головних карток, максимум два шрифти, ієрархія передусім за брендом» там, де агент читає їх під час кожного запуску."}]}, {"kind": "p", "text": "Зауважте, що кожне пом'якшення полягає в наданні агентові кураторського дизайн-контексту. Підтримування цього контексту вручну, для кожного проєкту, — це рутина, яку Open Design прибирає."}]}, {"id": "open-design", "heading": "Дизайн із Grok Build всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це дизайн-шар з відкритим кодом, якого робочий процес вище постійно вимагає. Він трактує Grok Build як рідний адаптер і обгортає його в кураторську бібліотеку skill і дизайн-систем, структурований конвеєр рендерингу та локальний десктопний UI — тож дизайн-контекст, що робить Grok добрим, є там з першого запуску, а не збирається вручну щоразу. Open Design незалежний і Apache-2.0, і він працює на вашій власній машині, що робить це поєднання природним."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Grok Build як свого агента.", "Автентифікуйтеся зі своїм обліковим записом SuperGrok або API-ключем xAI (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, потім генеруйте презентації, прототипи та лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хмарі на хостингу."]}, {"kind": "p", "text": "Той самий агент Grok Build, ті самі облікові дані — плюс справжній, переносний дизайн-процес з відкритим кодом навколо нього. Він локальний передусім і Apache-2.0, тож ніщо про вашу роботу чи ваші облікові дані не залишає вашої машини."}]}], "faqTitle": "Поширені запитання", "faq": [{"name": "Чи може Grok Build справді робити дизайнерську роботу?", "text": "Так — з естетичним skill, дизайн-системою та справжніми референсними зображеннями в контексті Grok Build видає продакшн-якісний адаптивний UI, а його моделі Grok з підтримкою зображень допомагають перевіряти вивід проти референсів. Без цього контексту він схильний за замовчуванням звертатися до шаблонного вигляду, і саме цей розрив закриває Open Design."}, {"name": "Як автентифікувати Grok Build?", "text": "Ви входите через ваш браузер з підпискою SuperGrok або X Premium+ (`grok login`), тож немає API-ключа, яким треба керувати. Для безголового або CI-використання ви можете натомість принести API-ключ xAI. Open Design ніколи не проксіює ваші облікові дані в будь-якому разі."}, {"name": "Що робить Grok Build добрим саме для дизайну?", "text": "Дві речі: його режим планування дає вам змогу переглянути підхід до того, як будь-яка зміна закріпиться, а його моделі Grok приймають зображення на вхід, тож він добре читає референсні скриншоти. Обидва допомагають — але смак усе одно походить від дизайн-системи, skill і референсів, які ви постачаєте."}, {"name": "Grok Build чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Grok Build — перегляд у режимі планування та моделі xAI з підтримкою зображень. Багато команд використовують обидва — Open Design дає змогу перемикати агентів без зміни вашого дизайн-процесу."}, {"name": "Як підключити Grok Build до Figma?", "text": "Додайте MCP-сервер Figma до вашої конфігурації MCP. Тоді Grok може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код збігається з першоджерелом, а не наближає його."}, {"name": "Чи пов'язаний Open Design з xAI?", "text": "Ні. Grok Build — це продукт xAI; Open Design — це незалежний проєкт з відкритим кодом, що підтримує його як рідний адаптер. Grok є торговельною маркою xAI."}, {"name": "Чи в безпеці мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані xAI використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Дизайн із Grok Build, відкритим шляхом.", "ctaBody": "Принесіть свій власний обліковий запис SuperGrok або API-ключ xAI, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використати Grok Build в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'kimi': {
        ...en['kimi']!,
        title: "Kimi CLI для дизайну — Open Design",
        description: "Як люди використовують Kimi CLI від Moonshot AI для UI- та вебдизайну — його агентні моделі Kimi K2, великий контекст, AGENTS.md і MCP — і як Open Design перетворює Kimi CLI на локальний дизайн-агент з відкритим кодом.",
        breadcrumb: "Kimi CLI",
        label: "Агент · Kimi CLI",
        heading: "Kimi CLI для дизайну.",
        lead: "Kimi CLI — це термінальний агент з відкритим кодом від Moonshot AI, що живиться серією моделей Kimi K2. Його потужне агентне кодування та велике контекстне вікно дають йому змогу вмістити цілу дизайн-систему та ітерувати проти референсів — щойно ви даєте йому конвенції та цикл перевірки, він стає справжнім інструментом для дизайну. Open Design вбудовує його в дизайн-процес з відкритим кодом: ваш API-ключ Moonshot, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Kimi CLI на локальний дизайн-агент з відкритим кодом — ваш API-ключ Moonshot, ваші файли, а навколо нього — кураторська бібліотека skill і дизайн-систем.", "heroCtaActions": [{"label": "Використати Kimi CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kimi CLI — це ШІ-агент з відкритим кодом для термінала від Moonshot AI. Дві речі роблять його цікавим саме для дизайну: він живиться серією Kimi K2 — моделлю «суміш експертів» на трильйон параметрів, ретельно оптимізованою під агентне кодування та використання інструментів; і ця модель несе велике контекстне вікно (256k токенів на нещодавніх релізах K2), достатньо велике, щоб вмістити цілу дизайн-систему та кодову базу одразу. У поєднанні з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI — і ви можете почати з входу OAuth або власного API-ключа Moonshot. Це практичний наскрізний посібник з використання Kimi CLI для роботи над UI, фронтендом і дизайн-системами та з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим Kimi CLI є насправді, чому його агентні моделі Kimi K2 та великий контекст пасують дизайну, як налаштувати його з нуля, цикл «референс → UI», як AGENTS.md, MCP і субагенти розширюють його, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які вивід штучного інтелекту виглядає шаблонно, і як Open Design закриває цей розрив як відкритий локальний дизайн-шар — природне поєднання, адже обидва з відкритим кодом і працюють на вашій власній машині."], "heroImage": {"src": "/agents/kimi-design/kimi-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну в Kimi CLI: термінальний агент читає референсне зображення, браузер відмальовує UI, і робочий простір, зі стрілкою зворотного зв'язку, що замикається назад", "caption": "Основний цикл: Kimi CLI читає ваші референси в терміналі, будує та перевіряє UI в реальному браузері й ітерує проти них — з цілою дизайн-системою в контексті."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-kimi", "label": "Чим насправді є Kimi CLI"}, {"id": "why-design", "label": "Чому агентний K2 + великий контекст пасують дизайну"}, {"id": "setup", "label": "Налаштування Kimi CLI для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «референс → UI»"}, {"id": "extend", "label": "AGENTS.md, MCP та субагенти"}, {"id": "vs", "label": "Kimi CLI проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із Kimi CLI в Open Design"}, {"id": "faq", "label": "Поширені запитання"}], "sections": [{"id": "what-is-kimi", "heading": "Чим насправді є Kimi CLI", "blocks": [{"kind": "p", "text": "Kimi CLI — це ШІ-агент з відкритим кодом (Apache-2.0), який Moonshot AI постачає для термінала. Він читає ваш репозиторій, редагує файли, виконує команди оболонки, шукає файли, отримує вебсторінки та обирає свій наступний крок зі зворотного зв'язку, який отримує — плануючи та перевіряючи роботу з природномовних задач, а не лише доповнюючи рядки. Це інструмент на Python, що встановлюється через uv, і за лаштунками він керує сімейством моделей Kimi K2."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Моделі Kimi K2 явно налаштовані під агентне, довгогоризонтне кодування та використання інструментів, тож агент може провести багатокрокову збірку до робочого результату. І контекстне вікно сягає до 256k токенів на нещодавніх релізах K2, достатньо велике, щоб вмістити цілу вашу дизайн-систему, бібліотеку компонентів і набір референсів одразу замість того, щоб стискати їх до резюме."}, {"kind": "steps", "items": [{"label": "Контекстні файли", "body": "Kimi CLI читає файл AGENTS.md для постійного контексту проєкту — природне місце, щоб закодувати ваші дизайн-конвенції, токени та чеклісти перевірки. Запустіть /init, щоб згенерувати каркас для проєкту, у якого його немає."}, {"label": "MCP, ACP + субагенти", "body": "Він керує MCP-серверами в розмовному режимі через /mcp-config, надає сесію через Agent Client Protocol (kimi acp) для Zed і JetBrains і може диспетчеризувати вбудованих субагентів coder, explore та plan в ізольованих контекстах."}, {"label": "Вхід або BYOK", "body": "Під час першого запуску /login дає вам змогу авторизуватися через OAuth (Kimi Code) або ввести власний API-ключ Moonshot; платформа Kimi також надає OpenAI- та Anthropic-сумісні кінцеві точки."}]}, {"kind": "ul", "items": ["Постачальник: Moonshot AI", "Облікові дані: API-ключ Moonshot (BYOK) або вхід OAuth через Kimi Code", "Ліцензія: Apache-2.0, відкритий код"]}]}, {"id": "why-design", "heading": "Чому агентні моделі K2 та великий контекст пасують дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Kimi CLI походить від двох властивостей моделі — але, як і з кожним агентом, смак усе одно треба постачати."}, {"kind": "steps", "items": [{"label": "Агентне, довгогоризонтне кодування", "body": "Моделі Kimi K2 оптимізовані під використання інструментів і багатокрокову роботу, тож агент може взяти референс і завдання та насправді збудувати, запустити й допрацювати UI, а не зупинитися на першому чернетковому варіанті."}, {"label": "Велике контекстне вікно", "body": "До 256k токенів на нещодавніх релізах K2 означає, що ціла дизайн-система, токени та багато референсних станів вміщаються одразу, тож агент перевикористовує ваші справжні примітиви, а не вигадує одноразові стилі."}, {"label": "Конвенції в AGENTS.md", "body": "AGENTS.md (плюс MCP-сервер на кшталт Figma) спрямовує агента на ваші токени, компоненти та справжні специфікації, тож він працює над брендом, а не дефолтним виглядом."}]}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, skill і референсне зображення сходяться в добрий дизайн-результат", "caption": "Смак походить від трьох вхідних даних, які ви надаєте: дизайн-системи, skill і справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, що вчить кожен агент: Kimi CLI не має смаку за замовчуванням. Він видає добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (детальніше нижче)."}]}, {"id": "setup", "heading": "Налаштування Kimi CLI для дизайнерської роботи, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Kimi CLI, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kimi CLI (uses uv; Python 3.12–3.14, 3.13 recommended)\ncurl -LsSf https://code.kimi.com/install.sh | bash\n# or, if you already have uv:\nuv tool install --python 3.13 kimi-cli\n\n# 2. Start it in your project and authenticate on first run\ncd your-project\nkimi              # then run /login: OAuth via Kimi Code, or paste a Moonshot API key\n\n# 3. Generate project context\n/init             # scaffolds an AGENTS.md for this project\n\n# 4. Wire an MCP server (optional, e.g. Figma for design handoff)\n/mcp-config       # add, edit, and authenticate MCP servers conversationally"}, {"kind": "image", "src": "/agents/kimi-design/kimi-design-setup-flow.webp", "alt": "Робочий процес налаштування з п'яти кроків: встановлення, автентифікація, налаштування AGENTS.md, додавання skill, перевірка", "caption": "Послідовність налаштування: встановлення → автентифікація → налаштування AGENTS.md → додавання skill → увімкнення перевірки в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Розмістіть свої токени, примітиви та конвенції в AGENTS.md і спрямуйте Kimi на них, щоб вивід відповідав бренду, а не звертався за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Kimi відмальовував у реальному браузері та перевіряв свій вивід на різних точках зламу, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «референс → UI»", "blocks": [{"kind": "p", "text": "Найвпливовіший дизайн-цикл з Kimi CLI — це перетворення референсного матеріалу на робочий адаптивний UI та ітерування, доки воно не збігатиметься — подаючи агентові ваші референси та змушуючи його порівнювати свій відмальований вивід назад із ними в реальному браузері."}, {"kind": "ol", "items": ["Починайте з найчіткіших референсів, які у вас є — і включайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретними у запиті; розпливчасті запити дають шаблонний UI навіть із потужним агентом.", "Тримайте свою дизайн-систему та конвенції в AGENTS.md і вказуйте Kimi, де живуть токени та канонічні примітиви.", "Запустіть dev-сервер і нехай Kimi відмальовує в реальному браузері, змінюючи розмір до точок зламу, щоб перевірити результат.", "Ітеруйте, змушуючи Kimi порівнювати свою реалізацію назад із референсами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Спрямуйте Kimi на ваші референси та dev-сервер, потім дайте конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "kimi\n# in the prompt:\n> Implement the design in ./references (reference-desktop.png,\n  reference-mobile.png) using React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from AGENTS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Тримайте запити маленькими та сфокусованими, фіксуйте вдалі ітерації та відкочуйте невдалі (повідомляючи Kimi, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі. Kimi CLI також може взяти короткий запис екрана чи демонстраційний кліп, коли потік важко описати словами."}]}, {"id": "extend", "heading": "AGENTS.md, MCP та субагенти", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Kimi CLI практичним для тривалої дизайнерської роботи, і всі три чисто лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Контекст AGENTS.md", "body": "Правила проєкту живуть у AGENTS.md у корені репозиторію. Це довговічний дім для ваших дизайн-конвенцій, що читається під час кожного запуску — і це той самий переносний формат, який використовують інші агенти."}, {"label": "MCP-сервери", "body": "Додавайте MCP-сервери в розмовному режимі через /mcp-config — переносний спосіб залучити дизайн-контекст і зовнішні інструменти, найбільш доречно MCP-сервер Figma, що працюють між агентами, а не лише в Kimi."}, {"label": "Субагенти та маркетплейс плагінів", "body": "Диспетчеризуйте вбудованих субагентів coder, explore та plan в ізольованих контекстах і встановлюйте skill, MCP-сервери та джерела даних з маркетплейсу чи будь-якого репозиторію GitHub, щоб збирати референси та виконувати цикл перевірки."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати для кожного проєкту наново."}]}, {"id": "vs", "heading": "Kimi CLI проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Для дизайнерської роботи немає єдиного переможця — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська перевага", "Найкраще для"], "rows": [["Kimi CLI", "Агентні моделі Kimi K2, налаштовані під довгогоризонтне кодування та використання інструментів, з великим контекстом; з відкритим кодом і BYOK", "Багатокрокових збірок і утримання цілої дизайн-системи в контексті за доступну ціну"], ["Codex", "Сильне візуальне доопрацювання з фронтенд-skill; пісочничні асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів з великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і подивися» з живим попереднім переглядом і вбудованими редагуваннями", "Щільної роботи над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1M токенів; безкоштовний тариф", "Роботи, насиченої скриншотами, та дуже великого контексту"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти полягає в тому, що смак походить від людей: усі вони за замовчуванням звертаються до шаблонної естетики без skill, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструменту, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований штучним інтелектом дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно великі заокруглені кути, драматичні тіні, вайб Inter-та-фіолетового, що «кричить, що це зробив ШІ». Інші повідомлювані проблеми включають зламані мобільні макети та інструкції, що протікають у текст UI. Жодна з них не є унікальною для Kimi CLI; це те, що стається, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичний skill", "body": "Кураторський дизайн-skill змушує агента взяти курс на справжній напрям замість дефолтного вигляду."}, {"label": "Перевіряйте в реальному браузері", "body": "Нехай Kimi відмальовує та самоперевіряє на різних точках зламу, щоб макети не ламалися мовчки на мобільному."}, {"label": "Постачайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це єдиний найбільший важіль на якість виводу."}, {"label": "Закодуйте правила в AGENTS.md", "body": "Розмістіть правила на кшталт «без головних карток, максимум два шрифти, ієрархія передусім за брендом» там, де агент читає їх під час кожного запуску."}]}, {"kind": "p", "text": "Зауважте, що кожне пом'якшення полягає в наданні агентові кураторського дизайн-контексту. Підтримування цього контексту вручну, для кожного проєкту, — це рутина, яку Open Design прибирає."}]}, {"id": "open-design", "heading": "Дизайн із Kimi CLI всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це дизайн-шар з відкритим кодом, якого робочий процес вище постійно вимагає. Він трактує Kimi CLI як рідний адаптер і обгортає його в кураторську бібліотеку skill і дизайн-систем, структурований конвеєр рендерингу та локальний десктопний UI — тож дизайн-контекст, що робить Kimi добрим, є там з першого запуску, а не збирається вручну щоразу. Обидва з відкритим кодом і локальні передусім, що робить це поєднання природним."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Kimi CLI як свого агента.", "Автентифікуйтеся зі своїм API-ключем Moonshot (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, потім генеруйте презентації, прототипи та лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хмарі на хостингу."]}, {"kind": "p", "text": "Той самий агент Kimi CLI, той самий ключ — плюс справжній, переносний дизайн-процес з відкритим кодом навколо нього. Він локальний передусім і Apache-2.0, тож ніщо про вашу роботу чи ваші облікові дані не залишає вашої машини."}]}], "faqTitle": "Поширені запитання", "faq": [{"name": "Чи може Kimi CLI справді робити дизайнерську роботу?", "text": "Так — з естетичним skill, дизайн-системою та справжніми референсними зображеннями в контексті Kimi CLI видає продакшн-якісний адаптивний UI, а його агентні моделі Kimi K2 можуть відмальовувати та перевіряти вивід проти референсів. Без цього контексту він схильний за замовчуванням звертатися до шаблонного вигляду, і саме цей розрив закриває Open Design."}, {"name": "Чи потрібно платити, щоб робити дизайн з Kimi CLI?", "text": "Ви приносите свої власні облікові дані: авторизуйтеся через вхід OAuth Kimi Code або вставте API-ключ Moonshot (BYOK), що тарифікується платформою Moonshot. Open Design ніколи не проксіює ваші облікові дані в будь-якому разі."}, {"name": "Що робить Kimi CLI добрим саме для дизайну?", "text": "Дві речі: моделі Kimi K2 налаштовані під агентне, довгогоризонтне кодування та використання інструментів, тож агент може будувати та допрацьовувати до робочого результату, а контекстне вікно сягає до 256k токенів, достатньо, щоб вмістити цілу дизайн-систему та набір референсів одразу. Обидва допомагають — але смак усе одно походить від дизайн-системи, skill і референсів, які ви постачаєте."}, {"name": "Kimi CLI чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Kimi CLI — його агентні моделі Kimi K2 та великий контекст з економікою BYOK. Багато команд використовують обидва — Open Design дає змогу перемикати агентів без зміни вашого дизайн-процесу."}, {"name": "Як підключити Kimi CLI до Figma?", "text": "Запустіть /mcp-config всередині Kimi CLI, щоб додати та автентифікувати MCP-сервер Figma. Тоді Kimi може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код збігається з першоджерелом, а не наближає його."}, {"name": "Чи пов'язаний Open Design з Moonshot AI?", "text": "Ні. Kimi CLI — це продукт Moonshot AI; Open Design — це незалежний проєкт з відкритим кодом, що підтримує його як рідний адаптер. Kimi є торговельною маркою Moonshot AI."}, {"name": "Чи в безпеці мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Moonshot використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Дизайн із Kimi CLI, відкритим шляхом.", "ctaBody": "Принесіть свій власний API-ключ Moonshot, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використати Kimi CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'deepseek': {
        ...en['deepseek']!,
        title: "DeepSeek TUI для дизайну — Open Design",
        description: "Як люди використовують термінальний агент для кодування на основі DeepSeek для UI- та вебдизайну — його потужні моделі для кодування, контекст на 1M токенів, економічність, контекстні файли та MCP — і як Open Design перетворює DeepSeek TUI на локальний дизайн-агент з відкритим кодом.",
        breadcrumb: "DeepSeek TUI",
        label: "Агент · DeepSeek TUI",
        heading: "DeepSeek TUI для дизайну.",
        lead: "DeepSeek TUI — це термінальний агент для кодування, керований моделями DeepSeek. Його потужні, економічні моделі для кодування та контекст на 1M токенів можуть вмістити цілу дизайн-систему та кодову базу одразу, що робить його справжнім інструментом для дизайну — щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його в дизайн-процес з відкритим кодом: ваш API-ключ DeepSeek, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює DeepSeek TUI на локальний дизайн-агент з відкритим кодом — ваш API-ключ DeepSeek, ваші файли, а навколо нього — кураторська бібліотека skill і дизайн-систем.", "heroCtaActions": [{"label": "Використати DeepSeek TUI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek TUI — це термінальний ШІ-агент для кодування, що живиться моделями DeepSeek. Дві речі роблять його цікавим саме для дизайну: його моделі для кодування потужні та незвично економічні, тож ви можете агресивно ітерувати, не стежачи за лічильником; і його контекстне вікно сягає до 1M токенів, достатньо велике, щоб вмістити цілу дизайн-систему та кодову базу одразу замість того, щоб стискати їх до резюме. У поєднанні з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI. Це практичний наскрізний посібник з використання термінального агента на основі DeepSeek для роботи над UI, фронтендом і дизайн-системами та з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим DeepSeek TUI є насправді, чому потужні моделі для кодування, величезний контекст і низька вартість пасують дизайну, як налаштувати його з нуля, цикл «референс → UI», як контекстні файли та MCP розширюють його, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які вивід штучного інтелекту виглядає шаблонно, і як Open Design закриває цей розрив як відкритий локальний дизайн-шар — природне поєднання, адже обидва відкриті й працюють на вашій власній машині."], "heroImage": {"src": "/agents/deepseek-design/deepseek-design-hero.webp", "alt": "Цикл зворотного зв'язку дизайну в DeepSeek TUI: термінальний агент читає референси та конвенції, браузер відмальовує UI, і робочий простір, зі стрілкою зворотного зв'язку, що замикається назад", "caption": "Основний цикл: DeepSeek TUI читає ваші референси та конвенції в терміналі, будує та перевіряє UI в реальному браузері й ітерує проти них — з цілою дизайн-системою в контексті."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-deepseek", "label": "Чим насправді є DeepSeek TUI"}, {"id": "why-design", "label": "Чому потужні моделі для кодування + величезний контекст пасують дизайну"}, {"id": "setup", "label": "Налаштування DeepSeek TUI для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «референс → UI»"}, {"id": "extend", "label": "Контекстні файли, MCP та інструменти"}, {"id": "vs", "label": "DeepSeek TUI проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI slop»"}, {"id": "open-design", "label": "Дизайн із DeepSeek TUI в Open Design"}, {"id": "faq", "label": "Поширені запитання"}], "sections": [{"id": "what-is-deepseek", "heading": "Чим насправді є DeepSeek TUI", "blocks": [{"kind": "p", "text": "DeepSeek TUI — це керований клавіатурою термінальний ШІ-агент, що працює на моделях DeepSeek. Він читає ваш репозиторій, редагує файли, виконує команди оболонки, керує git і може шукати в вебі — плануючи та перевіряючи роботу з природномовних задач, а не лише доповнюючи рядки. Сам DeepSeek є постачальником моделей: OpenAI-сумісний API (він також надає кінцеву точку у форматі Anthropic), тож широкий діапазон термінальних агентів спільноти можна спрямувати на DeepSeek, задавши базовий URL і ключ. Кілька TUI з відкритим кодом постачають DeepSeek як першокласного постачальника."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються три властивості. Моделі DeepSeek для кодування потужні, тож агент розмірковує про макет, структуру та ієрархію компонентів з чіткого опису. Його контекстне вікно сягає до 1M токенів, достатньо велике, щоб вмістити цілу вашу дизайн-систему та бібліотеку компонентів одразу. І його ціна дуже низька за токен, з кешуванням контексту за префіксом згори — тож ітерування над дизайном коштує мало."}, {"kind": "steps", "items": [{"label": "Контекстні файли", "body": "Термінальні агенти читають файл контексту проєкту (файл у стилі AGENTS.md або власну конвенцію агента) для постійних правил — природне місце, щоб закодувати ваші дизайн-конвенції, токени та чеклісти перевірки."}, {"label": "Інструменти + MCP", "body": "Більшість DeepSeek TUI постачають файлові, оболонкові, git- та вебінструменти й підтримують MCP-сервери, щоб додати зовнішній контекст на кшталт живого файлу Figma — API DeepSeek підтримує виклик інструментів, на який ці агенти спираються."}, {"label": "Принесіть свій власний ключ", "body": "Ви автентифікуєтеся з API-ключем DeepSeek з платформи DeepSeek. Оскільки API OpenAI-сумісний, спрямувати агента на DeepSeek зазвичай — два рядки: базовий URL і ключ."}]}, {"kind": "ul", "items": ["Постачальник: DeepSeek (постачальник моделей і API)", "Облікові дані: API-ключ DeepSeek (BYOK) з платформи DeepSeek", "Моделі: deepseek-v4-flash і deepseek-v4-pro (лише текст; без рідного введення зображень)"]}]}, {"id": "why-design", "heading": "Чому потужні моделі для кодування та величезний контекст пасують дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага DeepSeek TUI походить від моделі та її економіки — але, як і з кожним агентом, смак усе одно треба постачати."}, {"kind": "steps", "items": [{"label": "Потужне, економічне кодування", "body": "Моделі DeepSeek для кодування здатні та недорогі, тож агент добре розмірковує про макет і структуру, а ви можете ітерувати багато разів без того, щоб вартість була обмеженням."}, {"label": "Контекстне вікно на 1M токенів", "body": "Великий контекст означає, що ціла дизайн-система, токени та багато референсних станів вміщаються одразу, тож агент перевикористовує ваші справжні примітиви, а не вигадує одноразові стилі — і кешування контексту тримає повторювані запити дешевими."}, {"label": "Конвенції в контекстному файлі", "body": "Файл контексту проєкту (плюс MCP-сервер Figma) спрямовує агента на ваші токени, компоненти та справжні специфікації, тож він працює над брендом, а не дефолтним виглядом."}]}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, skill і референс сходяться в добрий дизайн-результат", "caption": "Смак походить від трьох вхідних даних, які ви надаєте: дизайн-системи, skill і справжніх референсів."}, {"kind": "p", "text": "Урок той самий, що вчить кожен агент: DeepSeek TUI не має смаку за замовчуванням. Він видає добрий дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичний skill і конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (детальніше нижче)."}]}, {"id": "setup", "heading": "Налаштування DeepSeek TUI для дизайнерської роботи, з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до DeepSeek TUI, який може будувати та перевіряти UI. Точні назви встановлення та команд відрізняються залежно від того, який термінальний агент ви оберете, тож кроки нижче залишаються на рівні, що тримається для всіх них."}, {"kind": "code", "lang": "bash", "code": "# 1. Get a DeepSeek API key from the DeepSeek platform\n#    https://platform.deepseek.com\nexport DEEPSEEK_API_KEY=sk-...\n\n# 2. Install a DeepSeek-capable terminal agent (follow its README),\n#    then point it at DeepSeek. The API is OpenAI-compatible:\n#      base URL: https://api.deepseek.com\n#      model:    deepseek-v4-flash (or deepseek-v4-pro)\n#    (an Anthropic-format endpoint also exists at /anthropic)\n\n# 3. Start it in your project and generate project context\ncd your-project\n#   create/scaffold a project context file with your design rules\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it to the agent's MCP server configuration"}, {"kind": "image", "src": "/agents/deepseek-design/deepseek-design-setup-flow.webp", "alt": "Робочий процес налаштування з п'яти кроків: отримати ключ, встановити агента, налаштувати контекстний файл, додати skill, перевірити", "caption": "Послідовність налаштування: отримати ключ → спрямувати агента на DeepSeek → налаштувати контекстний файл → додати skill → увімкнути перевірку в браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої дизайн-правила", "body": "Розмістіть свої токени, примітиви та конвенції в контекстному файлі агента і спрямуйте його на них, щоб вивід відповідав бренду, а не звертався за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку в браузері", "body": "Підключіть Playwright або браузерний MCP, щоб агент відмальовував у реальному браузері та перевіряв свій вивід на різних точках зламу, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «референс → UI»", "blocks": [{"kind": "p", "text": "Моделі DeepSeek працюють лише з текстом — вони не читають зображення рідно — тож найвпливовіший дизайн-цикл — це перетворення чітких референсів і описаних макетів на робочий адаптивний UI, а потім перевірка результату в реальному браузері замість того, щоб просити модель подивитися на скриншот."}, {"kind": "ol", "items": ["Починайте з найчіткіших референсів, які у вас є — і описуйте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретними у запиті; розпливчасті запити дають шаблонний UI навіть із потужною моделлю. Розпишіть відступи, ієрархію та компоненти для перевикористання.", "Тримайте свою дизайн-систему та конвенції в контекстному файлі й вказуйте агентові, де живуть токени та канонічні примітиви.", "Запустіть dev-сервер і нехай агент відмальовує в реальному браузері, змінюючи розмір до точок зламу, щоб перевірити результат — саме тут відбувається перевірка, оскільки модель не може бачити саме зображення.", "Ітеруйте, змушуючи агента порівнювати відмальований DOM і обчислені стилі назад із вашою описаною специфікацією — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Опишіть цільовий результат точно та дайте конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "# in the agent's prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Layout: two-column dashboard, 240px sidebar, 24px gutters,\n  card grid at 3/2/1 columns for desktop/tablet/mobile.\n  Reuse my existing design-system components and tokens from the\n  context file. Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate against the\n  spec across breakpoints until it matches."}, {"kind": "p", "text": "Тримайте запити маленькими та сфокусованими, фіксуйте вдалі ітерації та відкочуйте невдалі (повідомляючи агента, коли ви відкочуєте), щоб кожен прохід будувався на чистій основі."}]}, {"id": "extend", "heading": "Контекстні файли, MCP та інструменти", "blocks": [{"kind": "p", "text": "Три точки розширення роблять DeepSeek TUI практичним для тривалої дизайнерської роботи, і всі три чисто лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Файл контексту проєкту", "body": "Правила проєкту живуть у контекстному файлі в корені репозиторію (з глобальним і командним шарами). Це довговічний дім для ваших дизайн-конвенцій, що читається під час кожного запуску."}, {"label": "MCP-сервери", "body": "Налаштовуйте MCP-сервери в агенті — переносний спосіб залучити дизайн-контекст і зовнішні інструменти, найбільш доречно MCP-сервер Figma, що працюють між агентами, а не лише в одному. API DeepSeek підтримує виклик інструментів, на який ці сервери спираються."}, {"label": "Вбудовані інструменти", "body": "DeepSeek TUI постачають файлові, оболонкові, git- та вебінструменти, тож агент може збирати референси та виконувати цикл перевірки, не залишаючи термінала."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати для кожного проєкту наново."}]}, {"id": "vs", "heading": "DeepSeek TUI проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Для дизайнерської роботи немає єдиного переможця — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне резюме:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська перевага", "Найкраще для"], "rows": [["DeepSeek TUI", "Потужні, дуже економічні моделі для кодування з відкритими вагами та контекстом на 1M токенів; лише текст (без рідного бачення)", "Високооб'ємного ітерування з обмеженим бюджетом і утримання цілої дизайн-системи в контексті"], ["Codex", "Сильне візуальне доопрацювання з фронтенд-skill; пісочничні асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів з великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і подивися» з живим попереднім переглядом і вбудованими редагуваннями", "Щільної роботи над UI у режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Рідне мультимодальне розуміння зображень і контекст на 1M токенів; з відкритим кодом і безкоштовним тарифом", "Роботи, насиченої скриншотами, де агент читає референси безпосередньо"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти полягає в тому, що смак походить від людей: усі вони за замовчуванням звертаються до шаблонної естетики без skill, референсів і обмежень. Це і є справжня проблема, яку треба розв'язати — і вона має форму дизайн-інструменту, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI slop»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований штучним інтелектом дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно великі заокруглені кути, драматичні тіні, вайб Inter-та-фіолетового, що «кричить, що це зробив ШІ». Інші повідомлювані проблеми включають зламані мобільні макети та інструкції, що протікають у текст UI. Жодна з них не є унікальною для DeepSeek TUI; це те, що стається, коли будь-який агент працює без кураторського дизайн-контексту. Оскільки DeepSeek працює лише з текстом, особливо важливо перевіряти в реальному браузері, а не довіряти моделі «подивитися» на результат."}, {"kind": "steps", "items": [{"label": "Додайте естетичний skill", "body": "Кураторський дизайн-skill змушує агента взяти курс на справжній напрям замість дефолтного вигляду."}, {"label": "Перевіряйте в реальному браузері", "body": "Відмальовуйте та самоперевіряйте на різних точках зламу з браузерним інструментом — тут це суттєво, оскільки модель не може сама прочитати скриншот — щоб макети не ламалися мовчки на мобільному."}, {"label": "Постачайте токени та референси", "body": "Справжні дизайн-токени та конкретні, описані референси — це єдиний найбільший важіль на якість виводу."}, {"label": "Закодуйте правила в контекстному файлі", "body": "Розмістіть правила на кшталт «без головних карток, максимум два шрифти, ієрархія передусім за брендом» там, де агент читає їх під час кожного запуску."}]}, {"kind": "p", "text": "Зауважте, що кожне пом'якшення полягає в наданні агентові кураторського дизайн-контексту. Підтримування цього контексту вручну, для кожного проєкту, — це рутина, яку Open Design прибирає."}]}, {"id": "open-design", "heading": "Дизайн із DeepSeek TUI всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це дизайн-шар з відкритим кодом, якого робочий процес вище постійно вимагає. Він трактує агента DeepSeek як рідний адаптер і обгортає його в кураторську бібліотеку skill і дизайн-систем, структурований конвеєр рендерингу та локальний десктопний UI — тож дизайн-контекст, що робить DeepSeek добрим, є там з першого запуску, а не збирається вручну щоразу. Обидва відкриті й локальні передусім, що робить це поєднання природним."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть DeepSeek TUI як свого агента.", "Автентифікуйтеся зі своїм власним API-ключем DeepSeek (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та skill, потім генеруйте презентації, прототипи та лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хмарі на хостингу."]}, {"kind": "p", "text": "Той самий агент DeepSeek, той самий ключ — плюс справжній, переносний дизайн-процес з відкритим кодом навколо нього. Він локальний передусім і Apache-2.0, тож ніщо про вашу роботу чи ваші облікові дані не залишає вашої машини."}]}], "faqTitle": "Поширені запитання", "faq": [{"name": "Чи може DeepSeek TUI справді робити дизайнерську роботу?", "text": "Так — з естетичним skill, дизайн-системою та конкретними референсами в контексті термінальний агент на основі DeepSeek видає продакшн-якісний адаптивний UI, а ви перевіряєте вивід у реальному браузері. Моделі DeepSeek працюють лише з текстом, тож цикл перевірки замінює рідне читання зображень. Без цього контексту він схильний за замовчуванням звертатися до шаблонного вигляду, і саме цей розрив закриває Open Design."}, {"name": "Скільки коштує робити дизайн з DeepSeek TUI?", "text": "Мало — API DeepSeek серед найдешевших за токен, а кешування контексту за префіксом ще більше зрізає вартість повторюваних запитів, тож ви можете агресивно ітерувати. Ви приносите свій власний API-ключ DeepSeek (BYOK); Open Design ніколи не проксіює ваші облікові дані."}, {"name": "Що робить DeepSeek добрим саме для дизайну?", "text": "Потужні, економічні моделі для кодування, відкриті ваги та контекст на 1M токенів, що вміщає цілу дизайн-систему та набір референсів одразу. DeepSeek працює лише з текстом — він не читає зображення рідно — тож смак усе одно походить від дизайн-системи, skill і описаних референсів, які ви постачаєте, перевірених у браузері."}, {"name": "DeepSeek TUI чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага DeepSeek TUI — відкриті ваги, дуже низька вартість і величезний контекст для високооб'ємного ітерування. Багато команд використовують обидва — Open Design дає змогу перемикати агентів без зміни вашого дизайн-процесу."}, {"name": "Як підключити DeepSeek TUI до Figma?", "text": "Додайте MCP-сервер Figma у конфігурації MCP вашого термінального агента. Тоді агент може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код збігається з першоджерелом, а не наближає його. API DeepSeek підтримує виклик інструментів, на який спирається MCP."}, {"name": "Чи пов'язаний Open Design з DeepSeek?", "text": "Ні. DeepSeek є постачальником моделей і API; Open Design — це незалежний проєкт з відкритим кодом, що підтримує термінальні агенти на основі DeepSeek як рідний адаптер. DeepSeek є торговельною маркою DeepSeek."}, {"name": "Чи в безпеці мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваш API-ключ DeepSeek використовується безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Дизайн із DeepSeek TUI, відкритим шляхом.", "ctaBody": "Принесіть свій власний API-ключ DeepSeek, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використати DeepSeek TUI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Поставити зірочку на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити застосунок для ПК", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'trae-cli': {
        ...en['trae-cli']!,
        title: "Trae CLI для дизайну — Open Design",
        description: "Як люди використовують Trae CLI (trae-agent) від ByteDance для UI- та вебдизайну — його відкритий, незалежний від моделі CLI-агент, можливість підключити власного LLM-провайдера та робочий процес на основі конфігурації — і як Open Design перетворює Trae CLI на локальний, відкритий дизайн-агент через ACP.",
        breadcrumb: "Trae CLI",
        label: "Агент · Trae CLI",
        heading: "Trae CLI для дизайну.",
        lead: "Trae CLI — це відкритий термінальний агент від ByteDance (trae-agent). Він незалежний від моделі — ви спрямовуєте його на того LLM-провайдера, якому довіряєте — і він читає ваш репозиторій, редагує файли та виконує команди з завдань природною мовою, що робить його справжнім інструментом дизайну, щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його у відкритий дизайн-процес через ACP: ваш власний ключ провайдера, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Trae CLI на локальний, відкритий дизайн-агент — ваш власний ключ LLM-провайдера, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього, керована через ACP.", "heroCtaActions": [{"label": "Використовуйте Trae CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Trae CLI — це відкритий AI-агент від ByteDance для термінала, що постачається як проєкт trae-agent. Дві речі роблять його цікавим саме для дизайну: він незалежний від моделі, тож ви можете підключити будь-якого LLM-провайдера, якому довіряєте, замість прив'язки до одного постачальника; і це прозорий агент під ліцензією MIT, який читає вашу кодову базу, редагує файли та виконує shell-команди з завдань природною мовою. У парі з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI — і він безкоштовний та відкритий для старту, потрібен лише ключ провайдера. Це практичний наскрізний посібник з використання Trae CLI для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Trae CLI, чому відкритий, незалежний від моделі агент підходить дизайну, як налаштувати його з нуля, цикл «скриншот — UI», як його розширюють файл конфігурації та інструменти, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара, адже обидва є відкритими й працюють на вашій власній машині, а Open Design керує Trae CLI через Agent Client Protocol (ACP)."], "heroImage": {"src": "/agents/trae-cli-design/trae-cli-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Trae CLI: термінальний агент читає референсне зображення, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Trae CLI читає ваші референси та конвенції в терміналі, будує й перевіряє UI у справжньому браузері та ітерує відповідно до них."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-trae-cli", "label": "Чим насправді є Trae CLI"}, {"id": "why-design", "label": "Чому відкритий, незалежний від моделі агент підходить дизайну"}, {"id": "setup", "label": "Налаштуйте Trae CLI для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот — UI»"}, {"id": "extend", "label": "Конфігурація, інструменти та провайдери"}, {"id": "vs", "label": "Trae CLI проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Trae CLI в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-trae-cli", "heading": "Чим насправді є Trae CLI", "blocks": [{"kind": "p", "text": "Trae CLI — це агент командного рядка з відкритого проєкту trae-agent від ByteDance. Він читає ваш репозиторій, переглядає, створює та редагує файли, а також виконує shell-команди в постійному середовищі — плануючи й перевіряючи роботу з завдань природною мовою, а не просто доповнюючи рядки. Він під ліцензією MIT і побудований навколо прозорої модульної архітектури, тож його легко інспектувати й розширювати. Він відрізняється від окремого Trae IDE — AI-редактора від ByteDance на основі VS Code, хоча обидва походять від того самого постачальника."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Він незалежний від моделі — ви обираєте LLM-провайдера, тож ви ніколи не прив'язані до сильних чи слабких сторін однієї моделі. І він повністю відкритий та керований конфігурацією, тож його поведінку, інструменти та провайдера можна зафіксувати в системі контролю версій поруч із вашим проєктом, а не ховати за хостингованим сервісом."}, {"kind": "steps", "items": [{"label": "Режими run та interactive", "body": "Trae CLI виконує одне завдання через `trae-cli run \"...\"` або тримає безперервну сесію через `trae-cli interactive` — природне місце, щоб ітерувати над UI відповідно до ваших дизайн-конвенцій."}, {"label": "Вбудовані інструменти", "body": "Він з коробки постачає інструменти редагування файлів, виконання bash/shell і структурованих міркувань, тож може будувати, запускати dev-сервер та інспектувати помилки виконання, не залишаючи термінал."}, {"label": "Підключіть власного провайдера", "body": "Ви надаєте API-ключ провайдера, якому довіряєте — OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure чи локальної моделі Ollama — через змінні середовища або файл конфігурації."}]}, {"kind": "ul", "items": ["Постачальник: ByteDance (відкритий проєкт trae-agent)", "Облікові дані: API-ключ LLM-провайдера (BYOK) — напр. OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure або локальна модель Ollama", "Ліцензія: MIT, відкритий код"]}]}, {"id": "why-design", "heading": "Чому відкритий, незалежний від моделі агент підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Trae CLI походить від того, що він відкритий і гнучкий щодо провайдерів — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Незалежність від моделі за задумом", "body": "Оскільки ви обираєте провайдера, ви можете спрямувати дизайнерську роботу на будь-яку модель, яка сьогодні найкраще міркує про макет і фронтенд-код, а пізніше замінити її, не змінюючи свій робочий процес."}, {"label": "Відкритий і керований конфігурацією", "body": "Агент, його інструменти та провайдер зафіксовані у файлі конфігурації, який можна закомітити, тож команда отримує однакову поведінку агента на кожній машині замість розбіжностей у кожного розробника."}, {"label": "Конвенції у вашому репозиторії", "body": "Спрямуйте агента на ваші токени, компоненти та реальні специфікації — що зберігаються у вашому проєкті — тож він працює на бренд, а не за замовчуванням до шаблонного вигляду."}]}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Trae CLI за замовчуванням не має смаку. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані й передає їх Trae CLI через ACP, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Trae CLI для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Trae CLI, який може будувати та перевіряти UI. Trae CLI встановлюється з джерел через uv, а потім налаштовується з LLM-провайдером, якого ви хочете використовувати."}, {"kind": "code", "lang": "bash", "code": "# 1. Get Trae CLI (trae-agent) from source — needs uv\ngit clone https://github.com/bytedance/trae-agent.git\ncd trae-agent\nuv sync --all-extras\nsource .venv/bin/activate\n\n# 2. Authenticate by pointing it at your LLM provider key\n#    set it in the environment (or a trae_config.yaml file)\nexport OPENAI_API_KEY=...        # or ANTHROPIC_API_KEY, GOOGLE_API_KEY, etc.\n\n# 3. Run a task in your project\ntrae-cli run \"Create a hello world page\"\n#    or hold a session:\ntrae-cli interactive\n\n# 4. Check the resolved configuration (keys are masked)\ntrae-cli show-config"}, {"kind": "image", "src": "/agents/trae-cli-design/trae-cli-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, автентифікація, налаштування конвенцій, додавання навички, перевірка", "caption": "Послідовність налаштування: встановити → автентифікуватися ключем провайдера → налаштувати свої дизайн-конвенції → додати навичку → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Тримайте свої токени, примітиви та конвенції в репозиторії та спрямуйте на них Trae CLI, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Нехай Trae CLI запустить dev-сервер і відрендерить у справжньому браузері, щоб перевіряти свій результат на різних точках перелому, а не лише підтверджувати, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Trae CLI — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не співпаде. Оскільки Trae CLI незалежний від моделі, спрямуйте його на провайдера, чия модель добре опрацьовує ваші референси, і покладайтеся на справжній браузер для перевірки результату."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і описуйте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть із сильною моделлю.", "Тримайте свою дизайн-систему та конвенції в репозиторії та скажіть Trae CLI, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і нехай Trae CLI відрендерить у справжньому браузері, змінюючи розмір під точки перелому для перевірки результату.", "Ітеруйте, змушуючи Trae CLI порівнювати свою реалізацію з референсами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Запустіть інтерактивну сесію та дайте конкретні обмеження, а не однорядковий запит:"}, {"kind": "code", "lang": "bash", "code": "trae-cli interactive\n# in the session:\n> Implement the attached reference design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until it\n  matches the references across breakpoints."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Trae CLI, коли ви відкочуєте), тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "Конфігурація, інструменти та провайдери", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Trae CLI практичним для тривалої дизайнерської роботи, і всі три чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Файл конфігурації", "body": "Trae CLI читає trae_config.yaml, що фіксує вашого провайдера, модель і налаштування — довговічний, контрольований у версіях дім того, як агент працює на проєкті."}, {"label": "Вибір провайдера", "body": "Оскільки він підтримує багатьох провайдерів (OpenAI, Anthropic, Google, OpenRouter, Doubao, Azure, Ollama), ви спрямовуєте дизайнерську роботу на модель, якій довіряєте, та замінюєте її без переналаштування робочого процесу."}, {"label": "Вбудовані інструменти", "body": "Його інструменти редагування файлів, shell і структурованих міркувань дозволяють йому збирати контекст, будувати, запускати dev-сервер і виконувати цикл перевірки, не залишаючи термінал."}]}, {"kind": "p", "text": "Це переносні можливості рівня агента — саме те, що Open Design створений оркеструвати через ACP, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Trae CLI проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Trae CLI", "Відкритий (MIT) і незалежний від моделі; підключайте власний ключ провайдера, керований конфігурацією та прозорий", "Команд, які хочуть безкоштовного, інспектованого агента й свободу обирати чи змінювати LLM-провайдерів"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1 млн токенів; відкритий, з безкоштовним рівнем", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Trae CLI; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Нехай Trae CLI рендерить і самоперевіряється на різних точках перелому, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила у вашому репозиторії", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» там, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Trae CLI всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Trae CLI як адаптер першої сторони — керуючи ним через Agent Client Protocol (ACP) за допомогою його бінарника trae-cli — і огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI, тож дизайн-контекст, що робить Trae CLI хорошим, є з першого запуску, а не збирається вручну щоразу. Обидва відкриті й локальні передусім, що робить цю пару природним вибором."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Trae CLI як свого агента.", "Автентифікуйтеся власним ключем LLM-провайдера (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Trae CLI, той самий ключ провайдера — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Він локальний передусім і відкритий, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Trae CLI справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальним референсним контекстом Trae CLI створює адаптивний UI продакшн-якості, а оскільки він незалежний від моделі, ви можете спрямувати роботу на провайдера, що найкраще міркує про ваш фронтенд. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Чи потрібно платити, щоб проєктувати з Trae CLI?", "text": "Сам Trae CLI безкоштовний і відкритий (MIT). Ви підключаєте власний ключ LLM-провайдера, тож ваша єдина витрата — те, що бере цей провайдер, або нічого, якщо ви запускаєте локальну модель через Ollama. Open Design у будь-якому разі ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Trae CLI хорошим саме для дизайну?", "text": "Дві речі: він незалежний від моделі, тож ви обираєте LLM-провайдера, найкраще пристосованого до фронтенд-роботи, і він повністю відкритий та керований конфігурацією, тож його поведінка прозора й відтворювана в межах команди. Але смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Trae CLI чи Claude Code для фронтенд-дизайну?", "text": "Обидва спроможні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Trae CLI — бути відкритим і гнучким щодо провайдерів, тож ви ніколи не прив'язані до однієї моделі. Багато команд використовують обидва — Open Design дозволяє перемикати агентів, не змінюючи свій дизайн-процес."}, {"name": "Що потрібно Open Design, щоб запустити Trae CLI?", "text": "Open Design керує бінарником trae-cli через Agent Client Protocol (ACP) і використовує налаштований вами ключ LLM-провайдера. Ви обираєте Trae CLI як свого агента, спрямовуєте його на провайдера, а Open Design надає кураторський дизайн-контекст навколо нього."}, {"name": "Чи пов'язаний Open Design з ByteDance або Trae?", "text": "Ні. Trae CLI (trae-agent) — продукт ByteDance; Open Design — незалежний відкритий проєкт, що підтримує його як адаптер першої сторони. Trae є торговельною маркою ByteDance."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і відкритий. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані LLM-провайдера використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Trae CLI відкритим способом.", "ctaBody": "Підключіть власний ключ LLM-провайдера, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Trae CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'aider': {
        ...en['aider']!,
        title: "Aider для дизайну — Open Design",
        description: "Як люди використовують Aider — відкритий, незалежний від моделі AI-напарник у вашому терміналі — для UI- та вебдизайну, з git-нативними правками, файлом CONVENTIONS.md, підтримкою зображень і BYOK, і як Open Design перетворює Aider на локальний, відкритий дизайн-агент.",
        breadcrumb: "Aider",
        label: "Агент · Aider",
        heading: "Aider для дизайну.",
        lead: "Aider — це відкритий AI-напарник, який живе у вашому терміналі й працює безпосередньо з вашим git-репозиторієм. Він незалежний від моделі — спрямуйте його на Claude, GPT-4o, DeepSeek чи Gemini з власним ключем — і він редагує файли, автоматично комітить та читає зображення на моделях із підтримкою зору. Це робить його справжнім інструментом дизайну, щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його у відкритий дизайн-процес: ваші ключі провайдерів, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Aider на локальний, відкритий дизайн-агент — ваші власні API-ключі провайдерів, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Aider в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Aider — це відкритий інструмент AI-парного програмування, що працює у вашому терміналі та з кодом у вашому git-репозиторії. Дві речі роблять його цікавим саме для дизайну: він незалежний від моделі, тож ви підключаєте власний ключ майже до будь-якого LLM — Claude, GPT-4o, DeepSeek, Gemini чи локальної моделі — і він git-нативний, редагуючи файли на місці й комітячи кожну зміну з осмисленим повідомленням, тож кожна ітерація є оглядовою та оборотною. На моделях із підтримкою зору він також може читати зображення, тож скриншот стає частиною підказки. У парі з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI. Це практичний наскрізний посібник з використання Aider для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Aider, чому незалежний від моделі, git-нативний інструмент підходить дизайну, як налаштувати його з нуля, цикл «скриншот — UI», як його розширюють CONVENTIONS.md та команди Aider, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара, адже обидва є відкритими й працюють на вашій власній машині."], "heroImage": {"src": "/agents/aider-design/aider-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Aider: термінальний агент читає референсне зображення, git-репозиторій із комітами, браузер відображає UI, з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Aider читає ваші референси в терміналі, редагує й комітить UI у вашому git-репозиторії та ітерує відповідно до них — з будь-якою моделлю, яку ви підключаєте."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-aider", "label": "Чим насправді є Aider"}, {"id": "why-design", "label": "Чому незалежність від моделі + git-нативність підходять дизайну"}, {"id": "setup", "label": "Налаштуйте Aider для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот — UI»"}, {"id": "extend", "label": "CONVENTIONS.md, зображення та команди"}, {"id": "vs", "label": "Aider проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Aider в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-aider", "heading": "Чим насправді є Aider", "blocks": [{"kind": "p", "text": "Aider — це відкритий (Apache-2.0) інструмент AI-парного програмування, що працює у вашому терміналі. Він читає вашу наявну кодову базу, відображає весь репозиторій для контексту, редагує файли на місці й автоматично комітить кожну зміну з осмисленим повідомленням — тож ви можете порівнювати, керувати та скасовувати роботу AI знайомими git-інструментами. Він працює зі 100+ мовами програмування й починає нові проєкти або розвиває наявні."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Aider незалежний від моделі: ви підключаєте власний ключ майже до будь-якого LLM — Claude, GPT-4o, DeepSeek, Gemini чи локальної моделі — тож ви ніколи не прив'язані до одного провайдера. А на моделях із підтримкою зору на кшталт GPT-4o і Claude він може читати файли зображень, перетворюючи референсний скриншот на частину підказки."}, {"kind": "steps", "items": [{"label": "Файл конвенцій", "body": "Aider читає файл CONVENTIONS.md, який ви завантажуєте через /read CONVENTIONS.md (або aider --read CONVENTIONS.md) — природне місце, щоб закодувати ваші дизайн-конвенції, токени та контрольні списки рев'ю як контекст лише для читання."}, {"label": "Git-нативні правки", "body": "Кожна зміна застосовується до файлів у вашому репозиторії й комітиться автоматично, тож кожна дизайн-ітерація є оглядовою та оборотною знайомими git-інструментами."}, {"label": "Підключіть власну модель", "body": "Підключіть OpenAI, Anthropic, DeepSeek, Gemini чи локальну модель власним API-ключем; Aider не прив'язаний до одного постачальника чи хостингованого бекенду."}]}, {"kind": "ul", "items": ["Постачальник: Aider (Aider-AI, відкритий код) — незалежний від моделі", "Облікові дані: ваш власний API-ключ провайдера — BYOK (OpenAI, Anthropic, DeepSeek, Gemini чи локальна модель)", "Ліцензія: Apache-2.0, відкритий код"]}]}, {"id": "why-design", "heading": "Чому незалежний від моделі, git-нативний інструмент підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Aider походить від того, як він працює з вашим репозиторієм і вашим вибором моделі — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Незалежність від моделі, BYOK", "body": "Виберіть модель, що найкраще проєктує для вашого завдання й бюджету — Claude, GPT-4o, DeepSeek, Gemini — і вільно перемикайтеся, не змінюючи робочий процес, усе на вашому власному ключі."}, {"label": "Git-нативна ітерація", "body": "Автокоміти роблять кожен дизайн-прохід оглядовим diff, який можна відкотити, тож ви ітеруєте на чистій основі, а не на невідстежуваній купі правок."}, {"label": "Конвенції в CONVENTIONS.md", "body": "CONVENTIONS.md (завантажений лише для читання) спрямовує агента на ваші токени, компоненти та правила, тож він працює на бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/aider-design/aider-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Aider за замовчуванням не має смаку. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Aider для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Aider, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Aider (recommended installer; Python 3.8–3.13)\npython -m pip install aider-install\naider-install\n# or with pipx: pipx install aider-chat\n\n# 2. Start it in your git project and bring your own key\ncd your-project\naider --model sonnet --api-key anthropic=<your-key>\n# or: aider --api-key openai=<your-key>   (also deepseek=, gemini=)\n\n# 3. Load your design conventions as read-only context\naider --read CONVENTIONS.md\n\n# 4. Add a reference image (on a vision-capable model)\n#    inside the chat: /add reference-desktop.png"}, {"kind": "image", "src": "/agents/aider-design/aider-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, підключення власного ключа, завантаження CONVENTIONS.md, додавання референсу, перевірка", "caption": "Послідовність налаштування: встановити → підключити власний ключ → завантажити CONVENTIONS.md → додати референс → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Розмістіть свої токени, примітиви та конвенції в CONVENTIONS.md і завантажте його лише для читання, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Запустіть dev-сервер і нехай Aider відрендерить у справжньому браузері, перевіряючи свій результат на різних точках перелому, а не лише підтверджуючи, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Aider — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не співпаде — використовуючи модель із підтримкою зору, щоб порівняти результат із референсом, з кожним проходом, закомічений у git."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і додавайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть із сильною моделлю.", "Тримайте свою дизайн-систему та конвенції в CONVENTIONS.md і скажіть Aider, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і перевірте відрендерений результат у справжньому браузері, змінюючи розмір під точки перелому.", "Ітеруйте, змушуючи Aider порівнювати свою реалізацію зі скриншотами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Додайте зображення через /add (або /paste з буфера обміну) на моделі з підтримкою зору, потім дайте конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "aider --model gpt-4o --read CONVENTIONS.md\n# in the chat:\n> /add reference-desktop.png\n> /add reference-mobile.png\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from CONVENTIONS.md.\n  Match spacing, layout, and hierarchy; make it responsive.\n  I'll render it in the browser and tell you what to fix until it matches\n  the references across breakpoints."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими. Оскільки Aider комітить кожну зміну, ви зберігаєте вдалі ітерації й використовуєте git (або /undo), щоб відкотити невдалі — тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "CONVENTIONS.md, зображення та команди", "blocks": [{"kind": "p", "text": "Три можливості роблять Aider практичним для тривалої дизайнерської роботи, і всі три чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Контекст CONVENTIONS.md", "body": "Завантажуйте конвенції кодування та дизайну через /read CONVENTIONS.md або aider --read CONVENTIONS.md, або встановіть read: CONVENTIONS.md у .aider.conf.yml, щоб завантажувати щоразу. Це довговічний дім для ваших токенів, примітивів і правил."}, {"label": "Зображення та вебсторінки", "body": "На моделях із підтримкою зору /add файл зображення або /paste з буфера обміну, щоб дати Aider справжній референс; /web <url> зчитує текст сторінки в чат для додаткового контексту."}, {"label": "Команди в чаті", "body": "Команди на кшталт /add для внесення файлів у контекст, /read для референсів лише для читання та /undo для відкату останнього коміту дозволяють йому збирати референси й виконувати цикл перевірки, не залишаючи термінал."}]}, {"kind": "p", "text": "Це переносні, репозиторно-нативні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Aider проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Aider", "Відкритий, незалежний від моделі (BYOK) і git-нативний; автокоміти роблять кожну ітерацію оглядовою та оборотною", "Репозиторно-нативної ітерації у вашій наявній кодовій базі з будь-якою моделлю, що проєктує найкраще"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1 млн токенів; відкритий, з безкоштовним рівнем", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Aider; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Рендерте й самоперевіряйте на різних точках перелому, щоб макети не ламалися мовчки на мобільному — на моделі з підтримкою зору подавайте скриншоти назад."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила в CONVENTIONS.md", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» там, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Aider всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Aider як адаптер першої сторони й огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Aider хорошим, є з першого запуску, а не збирається вручну щоразу. Обидва відкриті й локальні передусім, що робить цю пару природним вибором."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Aider як свого агента.", "Автентифікуйтеся власним API-ключем провайдера (BYOK) — OpenAI, Anthropic, DeepSeek чи Gemini; облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному git-репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Aider, той самий ключ — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Він локальний передусім і відкритий, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Aider справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Aider створює адаптивний UI продакшн-якості, а на моделях із підтримкою зору він читає скриншоти, щоб перевірити результат відносно референсів. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Які моделі я можу використовувати з Aider для дизайну?", "text": "Aider незалежний від моделі. Ви підключаєте власний API-ключ і майже будь-який LLM — Claude, GPT-4o, DeepSeek, Gemini чи локальну модель. Для дизайнерської роботи на основі зображень використовуйте модель із підтримкою зору, як-от GPT-4o чи Claude. Open Design ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Aider хорошим саме для дизайну?", "text": "Дві речі: він незалежний від моделі, тож ви обираєте модель, що найкраще проєктує для вашого завдання, і він git-нативний, комітячи кожну зміну, тож кожна дизайн-ітерація є оглядовою та оборотною. Обидва допомагають — але смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Чи редагує Aider мої файли та комітить у git?", "text": "Так. Aider редагує файли безпосередньо у вашому репозиторії й автоматично комітить кожну зміну з осмисленим повідомленням, тож ви можете порівнювати, керувати та скасовувати роботу AI знайомими git-інструментами."}, {"name": "Як дати Aider мої дизайн-конвенції?", "text": "Створіть CONVENTIONS.md зі своїми токенами, примітивами та правилами, потім завантажте його лише для читання через /read CONVENTIONS.md або aider --read CONVENTIONS.md (або встановіть read: CONVENTIONS.md у .aider.conf.yml, щоб завантажувати щоразу). Тоді Aider працює на ваш бренд, а не за замовчуванням до вигляду."}, {"name": "Чи пов'язаний Open Design з Aider?", "text": "Ні. Aider — незалежний відкритий проєкт (Aider-AI); Open Design — окремий незалежний відкритий проєкт, що підтримує Aider як адаптер першої сторони. Ці двоє не пов'язані."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і відкритий. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному git-репозиторії, а ваші API-ключі провайдерів використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Aider відкритим способом.", "ctaBody": "Підключіть власний API-ключ провайдера, тримайте кожен файл локально у вашому git-репозиторії й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Aider в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'antigravity': {
        ...en['antigravity']!,
        title: "Antigravity для дизайну — Open Design",
        description: "Як люди використовують Google Antigravity — agent-first платформу розробки від Google на основі мультимодальних моделей Gemini 3.x, з її Editor View, Manager Surface, інтегрованим керуванням браузером та Artifacts — для UI- та вебдизайну, і як Open Design перетворює Antigravity на локальний, відкритий дизайн-агент.",
        breadcrumb: "Antigravity",
        label: "Агент · Antigravity",
        heading: "Antigravity для дизайну.",
        lead: "Antigravity — це agent-first платформа розробки від Google. Її моделі Gemini 3.x читають скриншоти й міркують про макет, її інтегрований браузер дозволяє агентам перевіряти те, що вони будують, а її Artifacts перетворюють роботу агента на оглядові результати — що робить її справжнім інструментом дизайну, щойно ви даєте їй референси, конвенції та цикл перевірки. Open Design вбудовує її у відкритий дизайн-процес: ваш обліковий запис Google, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Antigravity на локальний, відкритий дизайн-агент — ваш обліковий запис Google, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Antigravity в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Antigravity — це agent-first платформа розробки від Google, запущена разом із Gemini 3. Три речі роблять її цікавою саме для дизайну: її агенти працюють на нативно мультимодальних моделях Gemini 3.x, тож вони читають скриншот і міркують про макет, відступи та ієрархію; вона постачає інтегрований браузер, яким агент може керувати, тож він рендерить і перевіряє власний UI замість того, щоб гадати; і вона створює Artifacts — списки завдань, плани реалізації, скриншоти та записи браузера — що перетворюють роботу агента на щось, що ви справді можете переглянути. У парі з правильними референсами, конвенціями та циклом перевірки вона будує справжній адаптивний UI — і безкоштовна для старту з обліковим записом Google. Це практичний наскрізний посібник з використання Antigravity для UI, фронтенду та роботи з дизайн-системами, а також з її вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Antigravity, чому мультимодальний Gemini та інтегрований браузер підходять дизайну, як налаштувати її з нуля, цикл «скриншот — UI», як її розширюють контекст агента та інструментарій, як вона порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара, адже Open Design відкритий і працює на вашій власній машині."], "heroImage": {"src": "/agents/antigravity-design/antigravity-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Antigravity: agent-first IDE читає референсне зображення, інтегрований браузер відображає UI, а поверхня Manager з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: агент Antigravity читає ваші референси, будує й перевіряє UI у своєму інтегрованому браузері та ітерує відповідно до них — виводячи роботу як оглядові Artifacts."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-antigravity", "label": "Чим насправді є Antigravity"}, {"id": "why-design", "label": "Чому мультимодальний Gemini + вбудований браузер підходять дизайну"}, {"id": "setup", "label": "Налаштуйте Antigravity для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот — UI»"}, {"id": "extend", "label": "Контекст агента, інструменти та Artifacts"}, {"id": "vs", "label": "Antigravity проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Antigravity в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-antigravity", "heading": "Чим насправді є Antigravity", "blocks": [{"kind": "p", "text": "Antigravity — це agent-first платформа розробки від Google — IDE на основі AI, побудована так, щоб роботу виконували автономні агенти, а не бічні чат-боти. Анонсована 18 листопада 2025 року разом із Gemini 3 і доступна в публічному превʼю безкоштовно для приватних осіб, вона дозволяє делегувати складні багатоінструментні програмні завдання агенту, який працює в редакторі, терміналі та інтегрованому браузері. Її агенти працюють переважно на мультимодальних моделях Gemini 3.x від Google."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються три властивості. Її агенти читають скриншоти й міркують про фактичний макет, бо Gemini 3.x нативно мультимодальний. Вона може керувати справжнім браузером, тож рендерить і перевіряє те, що будує. І вона виводить Artifacts — списки завдань, плани, скриншоти та записи браузера — тож ви переглядаєте відчутний результат замість сирих логів інструментів."}, {"kind": "steps", "items": [{"label": "Editor View + Manager Surface", "body": "Editor View — це знайоме AI IDE з автодоповненням табів та інлайн-командами; Manager Surface дозволяє породжувати, оркеструвати й спостерігати за кількома агентами, що працюють асинхронно в різних робочих просторах — природне місце, щоб запустити довге дизайн-завдання."}, {"label": "Інтегрований браузер + Artifacts", "body": "Агенти можуть діяти у вбудованому браузері й видавати Artifacts (скриншоти, записи браузера, списки завдань, плани), на які ви можете залишити відгук — цикл перевірки, вбудований у платформу, а не прикручений збоку."}, {"label": "Безкоштовно для старту", "body": "Вхід із персональним обліковим записом Google дає щедрі ліміти на Gemini 3.x; платформа працює на macOS, Windows і Linux."}]}, {"kind": "ul", "items": ["Постачальник: Google", "Облікові дані: обліковий запис Google (персональний Gmail), безкоштовно під час публічного превʼю", "Бінарник: запуск через agy; працює на macOS, Windows і Linux"]}]}, {"id": "why-design", "heading": "Чому мультимодальний Gemini та вбудований браузер підходять дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Antigravity походить від моделі та платформи разом — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Сильне мультимодальне розуміння", "body": "Оскільки Gemini 3.x нативно мультимодальний, агент добре читає референсні скриншоти — порівнюючи свій відрендерений результат із зображенням замість того, щоб гадати за текстовим описом."}, {"label": "Інтегрований браузер для перевірки", "body": "Агент керує справжнім браузером, тож рендерить UI, перевіряє його в різних станах і ловить зламані макети — і фіксує результат як Artifact-запис браузера, який ви можете переглянути."}, {"label": "Конвенції, які читає агент", "body": "Закодуйте свої токени, компоненти та правила рев'ю в контексті проєкту агента, тож він працює на ваш бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Antigravity за замовчуванням не має смаку. Вона створює якісний дизайн, коли ви даєте їй обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Antigravity для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до агента Antigravity, який може будувати та перевіряти UI. Точні меню в застосунку можуть змінюватися під час превʼю, тож це залишається на рівні, на який можна покладатися."}, {"kind": "code", "lang": "bash", "code": "# 1. Download Antigravity for your OS (macOS, Windows, Linux)\n#    from the official download page: antigravity.google/download\n\n# 2. Launch it and sign in\nagy               # opens Antigravity; sign in with your Google account\n\n# 3. Accept the data-use policy, pick a theme, and open your project folder\n\n# 4. Start an agent task in the Editor View or the Manager Surface,\n#    selecting a Gemini 3.x model (e.g. Gemini 3.1 Pro)"}, {"kind": "image", "src": "/agents/antigravity-design/antigravity-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: завантаження, вхід через Google, відкриття проєкту, додавання дизайн-правил і навички, увімкнення перевірки у браузері", "caption": "Послідовність налаштування: завантажити → увійти через Google → відкрити свій проєкт → додати дизайн-правила й навичку → використати інтегрований браузер для перевірки."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Розмістіть свої токени, примітиви та конвенції в контексті проєкту агента, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Використовуйте інтегрований браузер", "body": "Нехай агент відрендерить у вбудованому браузері Antigravity й перевірить свій результат на різних точках перелому — підтверджуючи, що UI виглядає правильно, а не лише що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Antigravity — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не співпаде — спираючись на мультимодальну модель для порівняння результату з референсом і на інтегрований браузер для перевірки."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і додавайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть із сильною моделлю.", "Тримайте свою дизайн-систему та конвенції в контексті проєкту агента й скажіть йому, де знаходяться токени й канонічні примітиви.", "Нехай агент відрендерить в інтегрованому браузері Antigravity, змінюючи розмір під точки перелому для перевірки результату.", "Ітеруйте, змушуючи агента порівнювати свою реалізацію зі скриншотами — а не просто підтверджувати, що вона збирається — і переглядайте Artifacts із записом браузера та скриншотами, які він створює."]}, {"kind": "p", "text": "Прикріпіть свої референсні зображення й дайте конкретні обмеження, потім дайте агенту перевірити у браузері:"}, {"kind": "code", "lang": "text", "code": "# In an Antigravity agent task, attach reference-desktop.png and\n# reference-mobile.png, then prompt:\n\nImplement this design in React + Vite + Tailwind + TypeScript.\nReuse my existing design-system components and tokens.\nMatch spacing, layout, and hierarchy; make it responsive.\nRender it in the integrated browser and iterate until it matches\nthe references across breakpoints, and show me the screenshots."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи агента, коли ви відкочуєте), тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "Контекст агента, інструменти та Artifacts", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Antigravity практичною для тривалої дизайнерської роботи, і всі три чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Контекст проєкту", "body": "Постійні правила проєкту — це довговічний дім ваших дизайн-конвенцій — токенів, примітивів і контрольних списків рев'ю, які агент читає в кожному завданні, тож результат лишається в межах бренду."}, {"label": "Інтегрований браузер + термінал", "body": "Агенти діють у редакторі, терміналі та вбудованому браузері, тож можуть збирати референси, запускати dev-сервер і перевіряти відрендерений UI, не залишаючи платформу."}, {"label": "Artifacts, які ви переглядаєте", "body": "Списки завдань, плани реалізації, скриншоти та записи браузера роблять роботу агента читабельною; ви залишаєте відгук на Artifact, а агент враховує виправлення."}]}, {"kind": "p", "text": "Це можливості, яких потребує серйозний дизайн-цикл — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Antigravity проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Antigravity", "Agent-first IDE з мультимодальним Gemini 3.x, інтегрованим браузером для самоперевірки та оглядовими Artifacts; безкоштовна в превʼю", "Асинхронних мультиагентних збірок із вбудованою перевіркою UI у браузері"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Відкритий термінальний агент на мультимодальному Gemini з контекстом на 1 млн токенів і безкоштовним рівнем", "Роботи в терміналі з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Antigravity; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте в інтегрованому браузері", "body": "Використовуйте мультимодальну модель і вбудований браузер Antigravity, щоб рендерити й самоперевірятися на різних точках перелому, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила в контексті проєкту", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» там, де агент читає їх у кожному завданні."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Antigravity всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Antigravity як адаптер першої сторони й огортає її кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Antigravity хорошою, є з першого запуску, а не збирається вручну щоразу. Open Design відкритий і локальний передусім, що робить цю пару природним вибором."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Antigravity як свого агента.", "Автентифікуйтеся своїм обліковим записом Google — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Antigravity, той самий обліковий запис Google — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Open Design локальний передусім і під ліцензією Apache-2.0, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Antigravity справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Antigravity створює адаптивний UI продакшн-якості, а її мультимодальні агенти Gemini 3.x перевіряють результат в інтегрованому браузері. Без цього контексту вона схильна за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Чи потрібно платити, щоб проєктувати з Antigravity?", "text": "Antigravity доступна в публічному превʼю безкоштовно для приватних осіб, зі щедрими лімітами на Gemini 3.x, коли ви входите з персональним обліковим записом Google. Open Design у будь-якому разі ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Antigravity хорошою саме для дизайну?", "text": "Три речі: її агенти працюють на нативно мультимодальних моделях Gemini 3.x, що добре читають референсні скриншоти, вона постачає інтегрований браузер, яким агент може керувати для перевірки UI, і вона виводить Artifacts — скриншоти та записи браузера — які ви можете переглянути. Смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Antigravity чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Antigravity — її agent-first платформа: мультимодальний Gemini 3.x, інтегрований браузер для перевірки та оглядові Artifacts. Багато команд використовують обидва — Open Design дозволяє перемикати агентів, не змінюючи свій дизайн-процес."}, {"name": "Як мені перевірити те, що будує Antigravity?", "text": "Antigravity постачає інтегрований браузер, яким можуть керувати її агенти, тож вони рендерять UI, перевіряють його на різних точках перелому й фіксують скриншоти та записи браузера як Artifacts. Перегляд цих Artifacts — і змушування агента порівнювати свій результат із вашими референсами — це те, як ви тримаєте результат відповідним до специфікації."}, {"name": "Чи пов'язаний Open Design з Google?", "text": "Ні. Antigravity — продукт Google; Open Design — незалежний відкритий проєкт, що підтримує її як адаптер першої сторони. Antigravity та Gemini є торговельними марками Google."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і під ліцензією Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Google використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Antigravity відкритим способом.", "ctaBody": "Підключіть власний обліковий запис Google, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Antigravity в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'reasonix': {
        ...en['reasonix']!,
        title: "DeepSeek Reasonix для дизайну — Open Design",
        description: "Як люди використовують DeepSeek Reasonix — створений спільнотою, DeepSeek-нативний термінальний агент для кодування — для UI- та вебдизайну, і як Open Design перетворює його на локальний, відкритий дизайн-агент. BYOK із власним API-ключем DeepSeek.",
        breadcrumb: "DeepSeek Reasonix",
        label: "Агент · DeepSeek Reasonix",
        heading: "DeepSeek Reasonix для дизайну.",
        lead: "DeepSeek Reasonix — це відкритий, створений спільнотою термінальний агент для кодування на основі моделей DeepSeek. Він читає ваш репозиторій, редагує файли та дешево виконує ваш цикл перевірки — увесь його дизайн побудований навколо префіксного кешу DeepSeek, щоб довгі сесії лишалися доступними. З референсами, конвенціями та перевіркою у браузері він стає справжнім інструментом дизайну. Open Design вбудовує його у відкритий дизайн-процес: ваш власний API-ключ DeepSeek, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює DeepSeek Reasonix на локальний, відкритий дизайн-агент — ваш власний API-ключ DeepSeek, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте DeepSeek Reasonix в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["DeepSeek Reasonix — це відкритий, створений спільнотою AI-агент для кодування в терміналі на основі моделей DeepSeek. Це не офіційний продукт DeepSeek — він підтримується автором GitHub esengine та спільнотою й побудований саме навколо механіки префіксного кешу DeepSeek, щоб довгі, ітеративні сесії лишалися дешевими. Він читає ваш репозиторій, редагує файли, виконує команди й працює з завдань природною мовою, а не просто доповнює рядки. Ви підключаєте власний API-ключ DeepSeek (BYOK), а агент працює на моделях DeepSeek, як-от deepseek-v4-pro і deepseek-v4-flash. Це практичний наскрізний посібник з використання DeepSeek Reasonix для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є DeepSeek Reasonix, чому економний агент на DeepSeek підходить ітеративному дизайну, як налаштувати його з нуля з власним ключем, цикл «референс — UI», як його розширюють навички та MCP, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара, адже обидва є відкритими й працюють на вашій власній машині."], "heroImage": {"src": "/agents/reasonix-design/reasonix-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку DeepSeek Reasonix: термінальний агент читає дизайн-референси, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: DeepSeek Reasonix працює в терміналі відповідно до ваших референсів і конвенцій, ви перевіряєте UI у справжньому браузері, а він ітерує — дешево, завдяки префіксному кешу DeepSeek."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-reasonix", "label": "Чим насправді є DeepSeek Reasonix"}, {"id": "why-design", "label": "Чому економний агент DeepSeek підходить дизайну"}, {"id": "setup", "label": "Налаштуйте DeepSeek Reasonix для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «референс — UI»"}, {"id": "extend", "label": "Навички, MCP та конфігурація"}, {"id": "vs", "label": "DeepSeek Reasonix проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з DeepSeek Reasonix в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-reasonix", "heading": "Чим насправді є DeepSeek Reasonix", "blocks": [{"kind": "p", "text": "DeepSeek Reasonix — це відкритий (MIT) AI-агент для кодування в терміналі, створений автором GitHub esengine та спільнотою. Він DeepSeek-нативний: спроєктований навколо механіки префіксного кешу DeepSeek, щоб довгі, ітеративні сесії лишалися дешевими. Він читає ваш репозиторій, редагує файли через редактор SEARCH/REPLACE із контролем рев'ю, виконує shell-команди й працює з завдань природною мовою — плануючи й перевіряючи, а не просто доповнюючи рядки. Важливо чітко розуміти: це проєкт спільноти, а не офіційний продукт компанії DeepSeek."}, {"kind": "p", "text": "Для дизайнерської роботи важливо те, що це спроможний агент для кодування з урахуванням репозиторію, який працює на сильних моделях DeepSeek за низькою вартістю. Моделі DeepSeek, які він використовує, лише текстові — вони не читають зображення нативно — тож практичний дизайн-цикл орієнтований на референси й перевіряється у справжньому браузері, а не агент «бачить» скриншот безпосередньо. Економність — це релевантна для дизайну перевага: ви можете ітерувати над UI багато разів без рахунку, що зазвичай відлякує від щільних циклів."}, {"kind": "steps", "items": [{"label": "DeepSeek-нативний, BYOK", "body": "Reasonix працює на моделях DeepSeek, як-от deepseek-v4-pro і deepseek-v4-flash. Ви підключаєте власний API-ключ DeepSeek — обліковий запис живе у вашому середовищі, а не в конфігурації агента."}, {"label": "Редагування з урахуванням репозиторію", "body": "Він читає й редагує файли у вашому проєкті через редактор із контролем рев'ю та виконує shell-команди, тож може будувати й ітерувати над справжнім кодом UI у вашому власному репозиторії."}, {"label": "Навички + MCP", "body": "Він підтримує навички, написані в Markdown, і MCP-сервери, тож ви можете дати йому довговічні конвенції та підключити зовнішній контекст, як-от дизайн-джерело."}]}, {"kind": "ul", "items": ["Постачальник: спільнота / автор GitHub esengine (не компанія DeepSeek)", "Облікові дані: ваш власний API-ключ DeepSeek (BYOK), наданий через середовище", "Ліцензія: MIT, відкритий код"]}]}, {"id": "why-design", "heading": "Чому економний агент DeepSeek підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага DeepSeek Reasonix полягає не стільки в одній яскравій можливості, скільки в тому, щоб зробити ітеративну роботу над UI дешевою й повторюваною — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Дешева, щільна ітерація", "body": "Оскільки він спроєктований навколо префіксного кешу DeepSeek, довгі дизайн-сесії лишаються доступними — тож ви можете запускати цикл «збудуй — перевір — уточни» багато разів, а не нормувати його."}, {"label": "Повторне використання з урахуванням репозиторію", "body": "Він редагує файли безпосередньо у вашому репозиторії, тож може повторно використовувати ваші наявні компоненти й токени замість винаходу одноразових стилів, коли ви спрямовуєте його на них."}, {"label": "Конвенції в навичках", "body": "Markdown-навички та конфігурація проєкту дозволяють закодувати токени, компоненти та правила рев'ю, тож агент працює на ваш бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: DeepSeek Reasonix за замовчуванням не має смаку. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси, описані йому — і браузер для перевірки. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте DeepSeek Reasonix для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось шлях від чистої машини до DeepSeek Reasonix, який може будувати та перевіряти UI. Оскільки це проєкт спільноти, завжди дотримуйтесь інструкцій встановлення у README репозиторію; наведений нижче нарис — це загальна форма."}, {"kind": "code", "lang": "bash", "code": "# 1. Install DeepSeek Reasonix (Node 22+) — see the repo README\nnpm install -g reasonix\n\n# 2. Bring your own DeepSeek API key (BYOK)\n#    Reasonix reads it from your environment, not from config files.\nexport DEEPSEEK_API_KEY=sk-...    # your DeepSeek key\n\n# 3. Start it in your project\ncd your-project\nreasonix                         # see README for the exact subcommands\n\n# 4. Add a design source via MCP (optional)\n#    e.g. a Figma MCP server, configured per the repo docs"}, {"kind": "image", "src": "/agents/reasonix-design/reasonix-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, додавання ключа DeepSeek, налаштування конвенцій, додавання навички, перевірка у браузері", "caption": "Послідовність налаштування: встановити → додати свій API-ключ DeepSeek → закодувати конвенції → додати навичку → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Розмістіть свої токени, примітиви та конвенції в навичці чи конфігурації проєкту й спрямуйте на них Reasonix, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Оскільки моделі DeepSeek лише текстові, підключіть Playwright або браузерний MCP, щоб агент рендерив у справжньому браузері й перевіряв свій результат на різних точках перелому, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «референс — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з DeepSeek Reasonix — це перетворення чітких референсів на робочий адаптивний UI та ітерування, доки воно не співпаде. Оскільки моделі DeepSeek лише текстові, референси подаються як детальні описи й специфікації — а не читаються нативно як зображення — і збіг підтверджується рендерингом у справжньому браузері."}, {"kind": "ol", "items": ["Перекладіть свої референси на конкретні специфікації — опишіть макет, відступи, ієрархію та стани (десктоп і мобільний, наведення, порожній, завантаження) словами, адже модель читає текст, а не пікселі.", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть із сильною моделлю.", "Тримайте свою дизайн-систему та конвенції в навичці чи конфігурації проєкту й скажіть Reasonix, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і перевірте результат у справжньому браузері, змінюючи розмір під точки перелому — підключіть браузерний MCP, щоб агент міг самоперевірятися.", "Ітеруйте, порівнюючи відрендерений UI з вашими референсами у браузері — а не просто підтверджуючи, що він збирається."]}, {"kind": "p", "text": "Дайте агенту конкретні обмеження в підказці, а не розпливчастий бриф:"}, {"kind": "code", "lang": "bash", "code": "reasonix\n# in the prompt:\n> Implement this design in React + Vite + Tailwind + TypeScript.\n  Reference: a two-column hero, 48px vertical rhythm, brand teal\n  accent, system-ui type — desktop and mobile described in DESIGN.md.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in a browser and iterate until it matches the spec\n  across breakpoints."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Reasonix, коли ви відкочуєте), тож кожен прохід будується на чистій основі — і дешевий, дружній до кешу цикл лишається продуктивним."}]}, {"id": "extend", "heading": "Навички, MCP та конфігурація", "blocks": [{"kind": "p", "text": "Кілька точок розширення роблять DeepSeek Reasonix практичним для тривалої дизайнерської роботи, і вони чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Markdown-навички", "body": "Reasonix підтримує навички, написані в Markdown — довговічний дім ваших дизайн-конвенцій, токенів і контрольних списків рев'ю, що застосовуються щоразу."}, {"label": "MCP-сервери", "body": "Він інтегрує MCP-сервери — переносний спосіб внести дизайн-контекст і зовнішні інструменти — найбільш релевантно дизайн-джерело на кшталт Figma MCP-сервера — що працюють у різних агентів, а не лише в Reasonix."}, {"label": "Конфігурація проєкту та вбудовані інструменти", "body": "Конфігурація на рівні проєкту плюс вбудовані файлові, shell- та вебінструменти дозволяють йому збирати контекст і виконувати цикл перевірки, не залишаючи термінал. Перевірте README репозиторію щодо точних шляхів конфігурації."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "DeepSeek Reasonix проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["DeepSeek Reasonix", "Відкритий і на основі DeepSeek; економний завдяки префіксному кешуванню, BYOK із власним ключем DeepSeek (створений спільнотою, лише текстові моделі)", "Дешевої, високооб'ємної ітерації над UI у вашому власному репозиторії"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1 млн токенів; відкритий, з безкоштовним рівнем", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для DeepSeek Reasonix; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту — а оскільки його моделі лише текстові, точний опис референсів важить ще більше."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Оскільки модель не бачить, рендерте й самоперевіряйте на різних точках перелому у справжньому браузері, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та описані референси", "body": "Справжні дизайн-токени й точно описані референсні стани — це найбільший важіль якості результату для лише текстового агента."}, {"label": "Закодуйте правила в навичці чи конфігурації", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» там, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з DeepSeek Reasonix всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає DeepSeek Reasonix як адаптер першої сторони й огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Reasonix хорошим, є з першого запуску, а не збирається вручну щоразу. Обидва відкриті й локальні передусім, що робить цю пару природним вибором."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть DeepSeek Reasonix як свого агента.", "Автентифікуйтеся власним API-ключем DeepSeek (BYOK) — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент DeepSeek Reasonix, той самий ключ — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Він локальний передусім і відкритий, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може DeepSeek Reasonix справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та точно описаними референсами в контексті DeepSeek Reasonix створює адаптивний UI продакшн-якості у вашому власному репозиторії, а ви перевіряєте результат у справжньому браузері. Його моделі DeepSeek лише текстові, тож цикл — це «референс описано-і-перевірено», а не читання зображень. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Чи потрібно платити, щоб проєктувати з DeepSeek Reasonix?", "text": "Ви підключаєте власний API-ключ DeepSeek, тож платите DeepSeek за використання (BYOK) — але агент побудований навколо префіксного кешу DeepSeek, щоб тримати цю вартість низькою впродовж довгих сесій. Сам Reasonix безкоштовний і під ліцензією MIT. Open Design ніколи не проксіює ваші облікові дані."}, {"name": "Чи є DeepSeek Reasonix офіційним продуктом DeepSeek?", "text": "Ні. DeepSeek Reasonix — це створений спільнотою, відкритий проєкт від автора GitHub esengine — він працює на моделях DeepSeek і використовує API-ключ DeepSeek, але не створений і не схвалений компанією DeepSeek. DeepSeek є торговельною маркою свого відповідного власника."}, {"name": "DeepSeek Reasonix чи Claude Code для фронтенд-дизайну?", "text": "Обидва можуть робити справжню дизайнерську роботу. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага DeepSeek Reasonix — бути відкритим і економним, виконуючи дешеву, високооб'ємну ітерацію на моделях DeepSeek із вашим власним ключем. Багато команд використовують більше одного — Open Design дозволяє перемикати агентів, не змінюючи свій дизайн-процес."}, {"name": "Як підключити DeepSeek Reasonix до дизайн-джерела на кшталт Figma?", "text": "Reasonix підтримує MCP-сервери, тож ви можете додати MCP дизайн-джерела (як-от Figma MCP-сервер) згідно з документацією репозиторію. Тоді агент може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — як текст, з яким може діяти, тож згенерований код відповідає джерелу, а не наближається до нього."}, {"name": "Чи пов'язаний Open Design з DeepSeek?", "text": "Ні. DeepSeek Reasonix — проєкт спільноти, що працює на моделях DeepSeek; Open Design — незалежний відкритий проєкт, що підтримує його як адаптер першої сторони. Він не пов'язаний ані з компанією DeepSeek, ані з мейнтейнерами Reasonix. DeepSeek є торговельною маркою свого відповідного власника."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і відкритий. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваш API-ключ DeepSeek використовується безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з DeepSeek Reasonix відкритим способом.", "ctaBody": "Підключіть власний API-ключ DeepSeek, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо відкритого агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте DeepSeek Reasonix в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'hermes': {
        ...en['hermes']!,
        title: "Hermes для дизайну — Open Design",
        description: "Як люди використовують Hermes від Nous Research — автономного, мультипровайдерного термінального агента для кодування — для UI- та вебдизайну, і як Open Design перетворює його на локальний, відкритий дизайн-агент із вашим власним ключем xAI, OpenAI чи Anthropic.",
        breadcrumb: "Hermes",
        label: "Агент · Hermes",
        heading: "Hermes для дизайну.",
        lead: "Hermes — це відкритий, автономний термінальний агент від Nous Research. Він планує, виконує й делегує роботу на власній машині — і він незалежний від провайдера, тож ви підключаєте власний ключ xAI, OpenAI чи Anthropic. Ця автономність робить його справжнім інструментом дизайну, щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його у відкритий дизайн-процес: ваш ключ, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Hermes на локальний, відкритий дизайн-агент — ваш власний ключ xAI, OpenAI чи Anthropic, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Hermes в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Hermes — це відкритий, автономний AI-агент від Nous Research. Дві речі роблять його цікавим саме для дизайну: він по-справжньому агентний, тож планує завдання, виконує його й делегує частини ізольованим субагентам, а не просто доповнює рядки; і він незалежний від провайдера, тож ви спрямовуєте його на будь-яку модель, якій довіряєте — xAI Grok за замовчуванням, або OpenAI та Anthropic через підключення власного ключа. У парі з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI на вашій власній машині. Це практичний наскрізний посібник з використання Hermes для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Hermes, чому автономний, мультипровайдерний агент підходить дизайну, як налаштувати його з нуля, цикл «скриншот — UI», як його розширюють навички та субагенти, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара, адже обидва є відкритими й працюють на вашій власній машині."], "heroImage": {"src": "/agents/hermes-design/hermes-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Hermes: автономний термінальний агент читає референсне зображення, делегує субагентам, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Hermes читає ваші референси в терміналі, планує й делегує збірку, перевіряє UI у справжньому браузері та ітерує відповідно до них — на будь-якій моделі, яку ви підключаєте."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-hermes", "label": "Чим насправді є Hermes"}, {"id": "why-design", "label": "Чому автономний, мультипровайдерний агент підходить дизайну"}, {"id": "setup", "label": "Налаштуйте Hermes для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот — UI»"}, {"id": "extend", "label": "Навички, субагенти та провайдери"}, {"id": "vs", "label": "Hermes проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Hermes в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-hermes", "heading": "Чим насправді є Hermes", "blocks": [{"kind": "p", "text": "Hermes — це відкритий (MIT) автономний AI-агент від Nous Research. Він працює постійно на вашій власній машині чи сервері, читає ваш репозиторій, редагує файли, виконує shell-команди, шукає в інтернеті й — що ключово — планує та виконує багатокрокову роботу самостійно, делегуючи частини ізольованим субагентам. Це автономний агент, а не копілот, прив'язаний до IDE."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Він по-справжньому агентний, тож ви можете дати йому ціль, і він планує, будує та перевіряє, а не чекає на покрокові вказівки. І він незалежний від провайдера: ви підключаєте власний ключ, за замовчуванням xAI Grok, але вільно спрямовуєте його на OpenAI, Anthropic чи будь-який інший підтримуваний endpoint — тож ви контролюєте, яка модель міркує над вашим дизайном."}, {"kind": "steps", "items": [{"label": "Навички", "body": "Hermes будує й повторно використовує навички — процедурну пам'ять, яку він створює з досвіду — природне місце, щоб зафіксувати ваші дизайн-конвенції, токени та контрольні списки рев'ю, щоб вони зберігалися між запусками."}, {"label": "Субагенти + інструменти", "body": "Він породжує ізольованих субагентів для паралельних робочих потоків і постачає файлові, shell-, веб- та браузерні інструменти, тож може збирати референси й виконувати цикл «збудуй і перевір», не залишаючи термінал."}, {"label": "Підключіть власний ключ", "body": "Hermes за замовчуванням використовує xAI Grok і підтримує OpenAI, Anthropic, OpenRouter та багатьох інших провайдерів через BYOK — встановіть ключ або запустіть OAuth-потік і виберіть свою модель."}]}, {"kind": "ul", "items": ["Постачальник: Nous Research", "Облікові дані: ключ провайдера через BYOK — xAI (Grok, за замовчуванням), OpenAI чи Anthropic — додаються через hermes auth add", "Ліцензія: MIT, відкритий код"]}]}, {"id": "why-design", "heading": "Чому автономний, мультипровайдерний агент підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Hermes походить від двох властивостей — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Автономне планування й виконання", "body": "Оскільки Hermes планує, виконує й делегує самостійно, він може взяти дизайн-ціль — співпасти з цим референсом, зробити адаптивним — і ітерувати до неї, замість того щоб потребувати прописування кожного кроку."}, {"label": "Підключіть модель, якій довіряєте", "body": "Незалежний від провайдера BYOK означає, що ви обираєте модель для міркувань під завдання: xAI Grok за замовчуванням, або моделі OpenAI та Anthropic, коли вам потрібні їхні сильні сторони — без прив'язки до естетики одного постачальника."}, {"label": "Конвенції в навичках", "body": "Навички (плюс MCP-сервер на кшталт Figma) спрямовують агента на ваші токени, компоненти та реальні специфікації, тож він працює на бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Hermes за замовчуванням не має смаку. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Hermes для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Hermes, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Hermes (one-line installer from Nous Research)\ncurl -fsSL https://hermes-agent.nousresearch.com/install.sh | bash\n\n# 2. Run the setup wizard\nhermes setup\n\n# 3. Add a provider and authenticate (BYOK)\n#    default is xAI Grok; OpenAI / Anthropic also supported\nhermes auth add        # add a provider key or run its OAuth flow\nhermes model           # pick the provider and model (grok-4.3 by default)\n\n# 4. Wire a Figma MCP server (optional, for design handoff)\n#    configure it among Hermes' MCP / tool settings"}, {"kind": "image", "src": "/agents/hermes-design/hermes-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, автентифікація, налаштування навички, додавання дизайн-системи, перевірка", "caption": "Послідовність налаштування: встановити → додати ключ провайдера → зафіксувати дизайн-правила в навичці → додати дизайн-систему → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Зафіксуйте свої токени, примітиви та конвенції в навичці Hermes і спрямуйте на них агента, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Hermes рендерив у справжньому браузері й перевіряв свій результат на різних точках перелому, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Hermes — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не співпаде — дозволяючи автономному агенту спланувати збірку й порівняти свій результат із референсом."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і додавайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть із сильною моделлю.", "Тримайте свою дизайн-систему та конвенції в навичці й скажіть Hermes, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і нехай Hermes відрендерить у справжньому браузері, змінюючи розмір під точки перелому для перевірки результату.", "Ітеруйте, змушуючи Hermes порівнювати свою реалізацію зі скриншотами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Спрямуйте Hermes на свої референси й дайте конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "hermes\n# in the prompt:\n> Use reference-desktop.png and reference-mobile.png in this folder.\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens from my skill.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Hermes, коли ви відкочуєте), тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "Навички, субагенти та провайдери", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Hermes практичним для тривалої дизайнерської роботи, і всі три чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Навички", "body": "Hermes будує й повторно використовує навички — процедурну пам'ять, створену з досвіду. Вони є довговічним домом ваших дизайн-конвенцій, що застосовуються в подальших запусках, а не пояснюються щоразу заново."}, {"label": "Субагенти та MCP", "body": "Він делегує роботу ізольованим субагентам і підтримує MCP-сервери — переносний спосіб внести дизайн-контекст і зовнішні інструменти, найбільш релевантно Figma MCP-сервер, що працюють у різних агентів, а не лише в Hermes."}, {"label": "Вибір провайдера", "body": "Оскільки Hermes незалежний від провайдера (xAI Grok за замовчуванням, OpenAI та Anthropic через BYOK), ви можете підбирати модель під завдання без перебудови робочого процесу."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Hermes проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Hermes", "Автономний агент «планування-виконання-делегування»; незалежний від провайдера BYOK (xAI Grok за замовчуванням, також OpenAI/Anthropic); відкритий і самохостингований", "Невтручальних автономних збірок на будь-якій моделі, якій довіряєте, що тримаються локально"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1 млн токенів; безкоштовний рівень", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Hermes; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Нехай Hermes рендерить і самоперевіряється на різних точках перелому, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила в навичці", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» в навичці, яку агент застосовує щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Hermes всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Hermes як адаптер першої сторони й огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Hermes хорошим, є з першого запуску, а не збирається вручну щоразу. Обидва відкриті й локальні передусім, що робить цю пару природним вибором."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Hermes як свого агента.", "Автентифікуйтеся власним ключем провайдера (BYOK) — xAI Grok за замовчуванням, або OpenAI чи Anthropic — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Hermes, той самий ключ — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Він локальний передусім і під ліцензією Apache-2.0, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Hermes справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Hermes створює адаптивний UI продакшн-якості, а як автономний агент він може рендерити й перевіряти результат відносно референсів самостійно. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Які моделі та ключі використовує Hermes?", "text": "Hermes незалежний від провайдера й працює з власним ключем. За замовчуванням він використовує xAI Grok (наприклад grok-4.3), а також підтримує OpenAI, Anthropic, OpenRouter і багатьох інших провайдерів — ви додаєте ключ провайдера (або запускаєте його OAuth-потік) через hermes auth add і обираєте модель через hermes model. Open Design ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Hermes хорошим саме для дизайну?", "text": "Дві речі: він по-справжньому автономний, тож планує, будує та перевіряє UI, а не чекає на покрокові вказівки; і він незалежний від провайдера, тож ви можете запускати модель для міркувань, якій довіряєте. Обидва допомагають — але смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Hermes чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Hermes — автономне планування й виконання плюс вибір провайдера — і ви навіть можете спрямувати Hermes на ключ Anthropic. Багато команд використовують обидва — Open Design дозволяє перемикати агентів, не змінюючи свій дизайн-процес."}, {"name": "Як підключити Hermes до Figma?", "text": "Додайте Figma MCP-сервер у конфігурацію інструментів Hermes. Тоді Hermes може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код відповідає джерелу, а не наближається до нього."}, {"name": "Чи пов'язаний Open Design з Nous Research?", "text": "Ні. Hermes — продукт Nous Research; Open Design — незалежний відкритий проєкт, що підтримує його як адаптер першої сторони. Hermes і Nous Research є торговельними марками свого відповідного власника."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і під ліцензією Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані провайдера використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Hermes відкритим способом.", "ctaBody": "Підключіть власний ключ xAI, OpenAI чи Anthropic, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Hermes в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'devin': {
        ...en['devin']!,
        title: "Devin for Terminal для дизайну — Open Design",
        description: "Як люди використовують Devin for Terminal — автономного AI-програміста від Cognition у командному рядку — для UI- та вебдизайну, і як Open Design перетворює його на локальний, відкритий дизайн-агент із кураторською бібліотекою навичок і дизайн-систем.",
        breadcrumb: "Devin for Terminal",
        label: "Агент · Devin",
        heading: "Devin for Terminal для дизайну.",
        lead: "Devin for Terminal — це автономний AI-програміст від Cognition, що працює у вашому терміналі. Він планує й виконує багатокрокові завдання самостійно та може передати сесію ізольованому хмарному агенту — що робить його справжнім способом випускати фронтенд-роботу, щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його у відкритий дизайн-процес: ваш обліковий запис Devin, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Devin for Terminal на локальний, відкритий дизайн-агент — ваш обліковий запис Devin, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Devin в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Devin for Terminal — це автономний AI-програміст від Cognition, перенесений у локальний командний рядок. Дві речі роблять його цікавим саме для дизайну: він по-справжньому агентний, тож планує й виконує багатокрокове завдання від початку до кінця, а не просто доповнює рядки; і він може передати сесію ізольованому хмарному агенту з власним комп'ютером, тож довші збірки продовжують працювати після того, як ви закриваєте ноутбук. У парі з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI. Це практичний наскрізний посібник з використання Devin for Terminal для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Devin for Terminal, чому автономний програміст підходить дизайнерській роботі, як налаштувати його з нуля, цикл «скриншот — UI», як його розширюють правила проєкту та зовнішні інструменти, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара для будь-якого агента, що може планувати й випускати фронтенд-роботу."], "heroImage": {"src": "/agents/devin-design/devin-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Devin for Terminal: автономний термінальний агент читає референсне зображення, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Devin читає ваші референси в терміналі, планує й будує UI, перевіряє його у справжньому браузері та ітерує відповідно до них — передаючи довші запуски в хмару, коли потрібно."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-devin", "label": "Чим насправді є Devin for Terminal"}, {"id": "why-design", "label": "Чому автономний програміст підходить дизайну"}, {"id": "setup", "label": "Налаштуйте Devin для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот — UI»"}, {"id": "extend", "label": "Правила проєкту, інструменти та передача в хмару"}, {"id": "vs", "label": "Devin проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Devin в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-devin", "heading": "Чим насправді є Devin for Terminal", "blocks": [{"kind": "p", "text": "Devin for Terminal — це версія Devin для командного рядка, автономного AI-програміста від Cognition. Він працює як локальний агент для кодування з доступом до вашої кодової бази, інструментів і середовища — читаючи ваш репозиторій, редагуючи файли, виконуючи shell-команди та плануючи й перевіряючи роботу з завдання природною мовою, а не просто доповнюючи рядки. Cognition побудувала власну бібліотеку рендерингу термінала на Rust, щоб інтерфейс лишався швидким і чуйним."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Він по-справжньому автономний, тож ви можете описати результат, і він виконує багатокроковий шлях до нього. А коли збірка переростає ваш ноутбук, ви можете передати сесію хмарному агенту, який працює у власному ізольованому середовищі й продовжує працювати асинхронно — тож ви можете повернутися до готового pull request."}, {"kind": "steps", "items": [{"label": "Автономне, агентне виконання", "body": "Devin планує й виконує багатокрокове завдання самостійно — реалізуючи функцію, будуючи UI, запускаючи й тестуючи його — керований чіткими підказками з явними критеріями завершення."}, {"label": "Локальний агент, передача в хмару", "body": "Він працює локально у вашому терміналі й може ескалувати сесію ізольованому хмарному агенту, що має власний комп'ютер і продовжує роботу після того, як ви відійшли."}, {"label": "На основі облікового запису, вибір моделі", "body": "Ви входите з обліковим записом Devin (Cognition); Devin працює на передових моделях — ви можете обирати між варіантами на кшталт власної SWE-1.6 від Cognition та інших передових моделей."}]}, {"kind": "ul", "items": ["Постачальник: Cognition", "Облікові дані: обліковий запис Devin (Cognition) — вхід на основі підписки/облікового запису, а не підключення власного ключа", "Форм-фактор: локальний термінальний агент із опційною ізольованою передачею в хмару"]}]}, {"id": "why-design", "heading": "Чому автономний програміст підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Devin походить від того, як він працює — автономне, наскрізне виконання — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Наскрізні, багатокрокові збірки", "body": "Оскільки Devin планує й виконує цілі завдання, він може створити каркас сторінки, підключити компоненти, запустити dev-сервер і протестувати результат за один захід, а не зупинятися на фрагменті."}, {"label": "Ізольовані хмарні запуски", "body": "Довша фронтенд-робота — повноцінний лендінг, багатоекранний потік — може передаватися ізольованому хмарному агенту й продовжувати будуватися, тож ітерація не блокується вашим ноутбуком."}, {"label": "Конвенції у правилах проєкту", "body": "Спрямуйте агента на ваші токени, компоненти та реальні специфікації через правила й документи вашого проєкту, тож він працює на бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/devin-design/devin-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Devin за замовчуванням не має смаку. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Devin для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Devin for Terminal, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Devin for Terminal\ncurl -fsSL https://cli.devin.ai/install.sh | bash\n\n# 2. Start it in your project and sign in on first run\ncd your-project\ndevin             # sign in with your Devin (Cognition) account\n\n# 3. Describe the task in natural language, with clear\n#    completion criteria, and let Devin plan and execute.\n\n# 4. When a build outgrows your laptop, hand the session\n#    off to a sandboxed cloud agent that keeps working."}, {"kind": "image", "src": "/agents/devin-design/devin-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, вхід, кодування дизайн-правил, додавання референсів, перевірка у браузері", "caption": "Послідовність налаштування: встановити → увійти → закодувати свої дизайн-правила → надати референси → перевірити у справжньому браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Розмістіть свої токени, примітиви та конвенції там, де агент їх читає — у правилах і документах вашого проєкту — тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Нехай Devin відрендерить у справжньому браузері й перевірить свій результат на різних точках перелому, тож він перевіряє відповідно до дизайну, а не лише підтверджує, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Devin — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не співпаде — дозволяючи автономному агенту будувати, запускати й порівнювати свій результат із референсом."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і додавайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретні в підказці й давайте явні критерії завершення; розпливчасті підказки дають шаблонний UI навіть із сильним агентом.", "Тримайте свою дизайн-систему та конвенції у правилах проєкту й скажіть Devin, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і нехай Devin відрендерить у справжньому браузері, змінюючи розмір під точки перелому для перевірки результату.", "Ітеруйте, змушуючи Devin порівнювати свою реалізацію з референсами — а не просто підтверджувати, що вона збирається — і передавайте в хмару для довших проходів."]}, {"kind": "p", "text": "Дайте Devin референси й конкретні обмеження з чітким визначенням готовності:"}, {"kind": "code", "lang": "bash", "code": "devin\n# in the prompt:\n> Implement the attached reference (desktop + mobile) in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints. Done = pixel-close on both\n  desktop and mobile with no console errors."}, {"kind": "p", "text": "Тримайте підказки сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Devin, коли ви відкочуєте), тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "Правила проєкту, інструменти та передача в хмару", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Devin for Terminal практичним для тривалої дизайнерської роботи, і всі три чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Правила та контекст проєкту", "body": "Тримайте свої дизайн-конвенції, токени та контрольні списки рев'ю у правилах і документах вашого проєкту, тож агент читає їх щоразу й працює на ваш бренд."}, {"label": "Кодова база, інструменти та середовище", "body": "Devin працює як локальний агент із доступом до вашої кодової бази, інструментів і середовища — він може запустити dev-сервер, виконати збірку й перевірити результат, не залишаючи термінал."}, {"label": "Ізольована передача в хмару", "body": "Передайте сесію хмарному агенту у власному ізольованому середовищі, щоб асинхронно виконувати довші збірки, тести та створення PR, а потім повернутися до готового pull request."}]}, {"kind": "p", "text": "Це саме той вид переносних, агентоподібних можливостей, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Devin проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Devin", "Повністю автономний програміст; планує й виконує багатокрокові збірки та передає ізольованому хмарному агенту", "Делегування наскрізних фронтенд-збірок, що продовжують працювати після того, як ви відійшли"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1 млн токенів; відкритий, з безкоштовним рівнем", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Devin; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Нехай Devin рендерить і самоперевіряється на різних точках перелому, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила в контексті проєкту", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» там, де агент читає їх щоразу, з явними критеріями завершення."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Devin всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Devin for Terminal як адаптер першої сторони й огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Devin хорошим, є з першого запуску, а не збирається вручну щоразу. Open Design відкритий і локальний передусім, що робить цю пару природним вибором для агента, якого ви вже запускаєте у своєму терміналі."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Devin for Terminal як свого агента.", "Автентифікуйтеся своїм обліковим записом Devin (Cognition) — облікові дані використовуються безпосередньо вашим агентом і ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Devin, той самий обліковий запис — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Open Design локальний передусім і під ліцензією Apache-2.0, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину через нас."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Devin for Terminal справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Devin створює адаптивний UI продакшн-якості, а як автономний агент він може будувати, запускати й перевіряти результат відносно ваших референсів. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Як мені увійти в Devin?", "text": "Devin працює на основі облікового запису: ви входите з обліковим записом Devin (Cognition), а не підключаєте власний ключ моделі. Встановіть Devin for Terminal, запустіть його у своєму проєкті та автентифікуйтеся під час першого запуску. Open Design ніколи не проксіює ваші облікові дані — ваш агент використовує їх безпосередньо."}, {"name": "Що робить Devin хорошим саме для дизайну?", "text": "Це повністю автономний програміст: він планує й виконує багатокрокові фронтенд-збірки від початку до кінця та може передати сесію ізольованому хмарному агенту, що продовжує працювати після того, як ви відійшли. Смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Devin чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Devin — повністю автономне, наскрізне виконання з ізольованою передачею в хмару. Багато команд використовують обидва — Open Design дозволяє перемикати агентів, не змінюючи свій дизайн-процес."}, {"name": "Чи працює Devin в ізольованому середовищі?", "text": "Devin for Terminal працює локально з доступом до вашої кодової бази й середовища, і він може передати сесію хмарному агенту, що працює у власному ізольованому середовищі — корисно для довших збірок, тестів і створення PR, що продовжуються асинхронно."}, {"name": "Чи пов'язаний Open Design з Cognition?", "text": "Ні. Devin for Terminal — продукт Cognition; Open Design — незалежний відкритий проєкт, що підтримує його як адаптер першої сторони. Devin є торговельною маркою Cognition."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і під ліцензією Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Devin використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Devin відкритим способом.", "ctaBody": "Увійдіть зі своїм обліковим записом Devin, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо автономного агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Devin в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'pi': {
        ...en['pi']!,
        title: "Pi для дизайну — Open Design",
        description: "Як люди використовують Pi, відкритий мультипровайдерний термінальний агент для кодування, для UI- та вебдизайну — його маршрутизацію до будь-якої моделі, BYOK-ключі провайдерів, Skills та Extensions — і як Open Design перетворює Pi на локальний, відкритий дизайн-агент.",
        breadcrumb: "Pi",
        label: "Агент · Pi",
        heading: "Pi для дизайну.",
        lead: "Pi — це відкритий термінальний агент для кодування, що маршрутизує до будь-якої моделі — Anthropic, OpenAI, Google і 20+ провайдерів — на ваших власних API-ключах. Це незалежне від провайдера ядро робить його гнучким інструментом дизайну: виберіть модель, що сьогодні найкраще читає скриншоти, перемкніться завтра, збережіть свій робочий процес. Open Design вбудовує його у відкритий дизайн-процес: ваші ключі провайдерів, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Pi на локальний, відкритий дизайн-агент — ваші власні API-ключі провайдерів, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Pi в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Pi — це відкритий (MIT) AI-агент для кодування в терміналі. Цікавим саме для дизайну його робить те, що він незалежний від провайдера: він нормалізує Anthropic, OpenAI, Google і понад 20 інших провайдерів за одним інтерфейсом, тож ви автентифікуєтеся власними API-ключами (BYOK) і обираєте модель, що пасує завданню — і ви можете перемикати моделі посеред сесії, не вчившись інструменту заново. У парі з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI. Це практичний наскрізний посібник з використання Pi для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Pi, чому мультипровайдерний BYOK-агент підходить дизайну, як налаштувати його з нуля, цикл «скриншот — UI», як його розширюють Skills та Extensions, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара, адже обидва є відкритими й працюють на вашій власній машині."], "heroImage": {"src": "/agents/pi-design/pi-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Pi: термінальний агент читає референсне зображення, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Pi читає ваші референси в терміналі, будує й перевіряє UI у справжньому браузері та ітерує відповідно до них — на будь-якому провайдері, на якого ви його спрямуєте."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-pi", "label": "Чим насправді є Pi"}, {"id": "why-design", "label": "Чому мультипровайдерний BYOK-агент підходить дизайну"}, {"id": "setup", "label": "Налаштуйте Pi для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот — UI»"}, {"id": "extend", "label": "Skills, Extensions і теми"}, {"id": "vs", "label": "Pi проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Pi в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-pi", "heading": "Чим насправді є Pi", "blocks": [{"kind": "p", "text": "Pi — це відкритий (MIT) AI-агент для кодування в терміналі, частина набору інструментів pi від earendil-works. Він читає ваш репозиторій, редагує файли та виконує shell-команди — плануючи й перевіряючи роботу з завдань природною мовою, а не просто доповнюючи рядки. Його ядро навмисно невелике: чотири інструменти за замовчуванням — read, write, edit і bash — плюс вбудовані grep, find і ls."}, {"kind": "p", "text": "Для дизайнерської роботи визначна властивість у тому, що Pi незалежний від провайдера. Він нормалізує Anthropic, OpenAI, Google і багатьох інших провайдерів за одним уніфікованим API, тож ви підключаєте власні ключі й обираєте модель під завдання — наприклад сильну мультимодальну модель для читання референсних скриншотів — і перемикаєтеся через /model чи Ctrl+L посеред сесії, не змінюючи робочий процес."}, {"kind": "steps", "items": [{"label": "Будь-яка модель, ваші ключі", "body": "Pi маршрутизує до 20+ провайдерів, зокрема Anthropic і OpenAI. Ви автентифікуєтеся власними API-ключами (BYOK) або входите в підписку Claude Pro/Max, ChatGPT Plus/Pro чи GitHub Copilot через /login."}, {"label": "Skills + Extensions", "body": "Pi завантажує Skills (Markdown-пакети можливостей за стандартом Agent Skills) і TypeScript Extensions — природне місце, щоб закодувати ваші дизайн-конвенції та додати кастомні інструменти."}, {"label": "Гілкування сесій", "body": "Сесії зберігаються як JSONL-дерева, тож ви можете відгалузити дослідження й навігувати історією в одному файлі, не втрачаючи попередні проходи."}]}, {"kind": "ul", "items": ["Постачальник: earendil-works (відкритий проєкт спільноти)", "Облікові дані: ваш власний API-ключ провайдера (BYOK — Anthropic, OpenAI, Google тощо) або вхід у підписку через /login; зберігається локально в ~/.pi/agent/auth.json (0600)", "Ліцензія: MIT, відкритий код"]}]}, {"id": "why-design", "heading": "Чому мультипровайдерний, BYOK-агент підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Pi — це гнучкість, а не одна вбудована модель — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Виберіть правильну модель під завдання", "body": "Оскільки Pi маршрутизує до будь-якого провайдера, ви можете звернутися до сильної мультимодальної моделі для читання референсних скриншотів, а потім перемкнутися на іншу для рефакторингу — не залишаючи агента."}, {"label": "Ваші ключі, без прив'язки", "body": "BYOK означає, що ви не прив'язані до цін чи лімітів контексту одного постачальника; обирайте модель, чиї сильні сторони пасують дизайн-завданню перед вами."}, {"label": "Конвенції в Skills", "body": "Skill (плюс MCP-джерело на кшталт Figma-сервера) спрямовує агента на ваші токени, компоненти та реальні специфікації, тож він працює на бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/pi-design/pi-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Pi за замовчуванням не має смаку, і жоден вибір моделі його не надає. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Pi для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Pi, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Pi coding agent CLI (Node)\nnpm install -g --ignore-scripts @earendil-works/pi-coding-agent\n\n# 2. Authenticate with your own provider key (BYOK)\nexport ANTHROPIC_API_KEY=sk-ant-...   # or OPENAI_API_KEY=sk-...\n#    (or run /login inside Pi for a Claude / ChatGPT / Copilot subscription)\n\n# 3. Start it in your project\ncd your-project\npi\n\n# 4. Switch models any time with /model or Ctrl+L"}, {"kind": "image", "src": "/agents/pi-design/pi-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, автентифікація, кодування дизайн-правил, додавання навички, перевірка", "caption": "Послідовність налаштування: встановити → автентифікуватися (BYOK) → закодувати дизайн-правила в Skill → вибрати модель → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Розмістіть свої токени, примітиви та конвенції в Skill і спрямуйте на них Pi, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Pi рендерив у справжньому браузері й перевіряв свій результат на різних точках перелому, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Pi — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не співпаде — спираючись на мультимодальну модель для порівняння результату з референсом. Оскільки Pi незалежний від провайдера, спрямуйте його на будь-яку модель, що найкраще читає зображення для цього проходу."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і додавайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Виберіть сильну мультимодальну модель для проходу через /model, адже саме розуміння зображень визначає якість циклу «скриншот — UI».", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть із сильною моделлю.", "Тримайте свою дизайн-систему та конвенції в Skill і скажіть Pi, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і нехай Pi відрендерить у справжньому браузері, змінюючи розмір під точки перелому, потім ітеруйте, порівнюючи його реалізацію зі скриншотами — а не просто підтверджуючи, що вона збирається."]}, {"kind": "p", "text": "Дайте агенту референси й конкретні обмеження наперед:"}, {"kind": "code", "lang": "bash", "code": "pi\n# in the prompt:\n> Implement reference-desktop.png and reference-mobile.png in\n  React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see the Skill).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Pi, коли ви відкочуєте), тож кожен прохід будується на чистій основі. Гілкувані JSONL-сесії Pi також дозволяють досліджувати альтернативу, не втрачаючи оригінальну гілку."}]}, {"id": "extend", "heading": "Skills, Extensions і теми", "blocks": [{"kind": "p", "text": "Pi саморозширюється під час виконання через кілька шарів, і вони чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Навички", "body": "Markdown-пакети можливостей за стандартом Agent Skills — довговічний, переносний дім ваших дизайн-конвенцій, токенів і контрольних списків рев'ю. Та сама Skill працює в сумісних агентах, а не лише в Pi."}, {"label": "Extensions і шаблони підказок", "body": "TypeScript Extensions додають кастомні інструменти, команди та UI; повторно використовувані шаблони підказок запускаються через /name. Обидва дозволяють скриптувати цикл перевірки, не залишаючи термінал."}, {"label": "MCP і теми", "body": "Pi підключається до MCP-серверів, щоб внести зовнішній дизайн-контекст (найбільш релевантно Figma MCP-сервер), а теми гаряче перезавантажуються, тож термінальний UI лишається читабельним під час роботи."}]}, {"kind": "p", "text": "Це переносні можливості — особливо Skills і MCP — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Pi проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Pi", "Незалежний від провайдера й BYOK — маршрутизуйте до будь-якої моделі (Anthropic, OpenAI, Google…) та перемикайтеся посеред сесії; MIT, саморозширюваний", "Вибору найкращої моделі під завдання без прив'язки до постачальника"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1 млн токенів; безкоштовний рівень", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Кут зору Pi ортогональний до інших: це агент, який дозволяє використовувати будь-яку з тих базових моделей на ваших власних ключах. Повторюваний вердикт спільноти все одно тримається — смак походить від людей: усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити, і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Pi чи для якоїсь однієї моделі; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням — а оскільки це переносна Skill, вона мандрує з вами між моделями."}, {"label": "Перевіряйте у справжньому браузері", "body": "Виберіть мультимодальну модель і нехай Pi рендерить і самоперевіряється на різних точках перелому, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила там, де Pi їх читає", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» в Skill, яку агент завантажує щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту — незалежно від того, на якого провайдера ви маршрутизуєте. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Pi всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Pi як адаптер першої сторони й огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Pi хорошим, є з першого запуску, а не збирається вручну щоразу. Обидва відкриті й локальні передусім, що робить цю пару природним вибором."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Pi як свого агента.", "Автентифікуйтеся власним API-ключем провайдера (BYOK) або входом у підписку — облікові дані залишаються на вашій машині в ~/.pi/agent/auth.json і ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Pi, ті самі ключі, та сама свобода перемикати моделі — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Він локальний передусім і під ліцензією MIT, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Pi справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Pi створює адаптивний UI продакшн-якості, і ви можете спрямувати його на сильну мультимодальну модель, щоб перевірити результат відносно референсів. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Чи потрібно платити, щоб проєктувати з Pi?", "text": "Сам Pi безкоштовний і відкритий (MIT). Ви платите лише за базову модель — підключіть власний API-ключ провайдера (BYOK) або використовуйте підписку Claude Pro/Max, ChatGPT Plus/Pro чи GitHub Copilot через /login. Open Design у будь-якому разі ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Pi хорошим саме для дизайну?", "text": "Він незалежний від провайдера: ви підключаєте власні ключі й маршрутизуєте до будь-якого з 20+ провайдерів, обираючи модель, чиї сильні сторони пасують завданню, і перемикаючись посеред сесії. Але смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте, а не від моделі."}, {"name": "Яку модель використовувати з Pi для фронтенд-дизайну?", "text": "Pi маршрутизує до багатьох провайдерів, тож обирайте під завдання — сильна мультимодальна модель добре читає референсні скриншоти, тоді як інші можуть пасувати рефакторингу. Перевага Pi в тому, що ви можете перемикатися, не змінюючи робочий процес. Open Design дозволяє зберігати той самий дизайн-контекст незалежно від обраної моделі."}, {"name": "Як підключити Pi до Figma?", "text": "Pi підтримує MCP-сервери, тож ви можете додати Figma MCP-сервер і витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код відповідає джерелу, а не наближається до нього."}, {"name": "Чи пов'язаний Open Design з Pi?", "text": "Ні. Pi — незалежний відкритий проєкт від earendil-works; Open Design — окремий незалежний відкритий проєкт, що підтримує Pi як адаптер першої сторони."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і відкритий. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші ключі провайдерів використовуються безпосередньо Pi (зберігаються локально в ~/.pi/agent/auth.json), ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Pi відкритим способом.", "ctaBody": "Підключіть власні ключі провайдерів, маршрутизуйте до будь-якої моделі, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Pi в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'kiro': {
        ...en['kiro']!,
        title: "Kiro CLI для дизайну — Open Design",
        description: "Як люди використовують Kiro CLI від Amazon для UI- та вебдизайну — його розробку на основі специфікацій, гачки агента, керівні файли та MCP — і як Open Design перетворює Kiro CLI на локальний, відкритий дизайн-агент.",
        breadcrumb: "Kiro CLI",
        label: "Агент · Kiro CLI",
        heading: "Kiro CLI для дизайну.",
        lead: "Kiro CLI — це термінальний агент Amazon для розробки на основі специфікацій — він перетворює підказку на специфікацію вимог, дизайн-документ і список завдань ще до того, як пише код. Саме ця структура потрібна дизайнерській роботі: спочатку намір, потім збірка. Open Design вбудовує його у відкритий дизайн-процес: ваш Builder ID або вхід, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Kiro CLI на локальний, відкритий дизайн-агент — ваш AWS Builder ID або вхід, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Kiro CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kiro CLI — це термінальний агент Amazon для розробки на основі специфікацій. Особливим його робить робочий процес: замість того щоб стрибати прямо від підказки до коду, Kiro формалізує вимоги у специфікацію, створює дизайн-документ і послідовний список завдань, і лише потім реалізує — тримаючи збірку підзвітною заявленому наміру. Він також постачає гачки агента, що спрацьовують на події на кшталт збереження файлу, керівні файли, що несуть ваші стандарти й конвенції в кожен запуск, і підтримку Model Context Protocol для зовнішніх інструментів. Kiro в превʼю, доступний як IDE, CLI та вебінтерфейс, і ви можете почати безкоштовно. Це практичний наскрізний посібник з використання Kiro CLI для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Kiro CLI, чому робочий процес на основі специфікацій підходить дизайну, як налаштувати його з нуля, цикл «скриншот — UI», як його розширюють керівні файли, гачки та MCP, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар навколо нього."], "heroImage": {"src": "/agents/kiro-design/kiro-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Kiro CLI: термінальний агент перетворює специфікацію на дизайн, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Kiro CLI перетворює ваш намір на специфікацію й список завдань у терміналі, будує й перевіряє UI у справжньому браузері та ітерує відповідно до ваших референсів."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-kiro", "label": "Чим насправді є Kiro CLI"}, {"id": "why-design", "label": "Чому розробка на основі специфікацій підходить дизайну"}, {"id": "setup", "label": "Налаштуйте Kiro CLI для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот — UI»"}, {"id": "extend", "label": "Специфікації, керівні файли, гачки та MCP"}, {"id": "vs", "label": "Kiro проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Kiro CLI в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-kiro", "heading": "Чим насправді є Kiro CLI", "blocks": [{"kind": "p", "text": "Kiro — це агентний AI від Amazon, що постачається як IDE, інтерфейс командного рядка та вебінтерфейс, побудований, щоб провести вас від прототипу до продакшну з розробкою на основі специфікацій. Kiro CLI приносить цього агента у ваш термінал: ви можете почати інтерактивну чат-сесію, створювати агентів і керувати ними та запускати сервери Model Context Protocol — усе з командного рядка. Kiro в превʼю."}, {"kind": "p", "text": "Для дизайнерської роботи визначна властивість — це робочий процес. Замість того щоб перетворювати підказку прямо на код, Kiro спершу пише специфікацію — вимоги, дизайн-документ і послідовний список завдань — і реалізує відповідно до неї. Це робить план агента видимим і оглядовим ще до того, як буде збудовано будь-який UI, що чітко лягає на те, як мають ухвалюватися дизайн-рішення: спочатку намір, потім виконання."}, {"kind": "steps", "items": [{"label": "Специфікації", "body": "Kiro перетворює підказку на структуровану специфікацію — вимоги, дизайн-документ і дискретні завдання — ще до того, як пише код, тож план оглядовий наперед."}, {"label": "Керівні файли + гачки", "body": "Керівні файли несуть ваші стандарти, конвенції та бажані інструменти в кожен запуск; гачки агента спрацьовують на події на кшталт збереження файлу, щоб автоматично виконувати фонові завдання."}, {"label": "Безкоштовно для старту, готовий до MCP", "body": "Увійдіть через Builder ID, Google, GitHub чи вашу організацію й почніть безкоштовно; Kiro CLI також керує MCP-серверами, щоб внести зовнішній контекст."}]}, {"kind": "ul", "items": ["Постачальник: Amazon (AWS)", "Облікові дані: AWS Builder ID, Google, GitHub чи AWS IAM Identity Center через kiro-cli login (обліковий запис AWS не потрібен)", "Статус: у превʼю; доступний як IDE, CLI та вебінтерфейс"]}]}, {"id": "why-design", "heading": "Чому розробка на основі специфікацій підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Kiro CLI походить від його робочого процесу — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Намір перед пікселями", "body": "Оскільки Kiro спершу пише специфікацію й дизайн-документ, ви можете виправити макет, ієрархію та обсяг на етапі планування — ще до того, як агент зобов'язався до шаблонної реалізації."}, {"label": "Керівні файли несуть ваш бренд", "body": "Керівні файли тримають ваші токени, компоненти та конвенції перед агентом у кожному запуску, тож результат працює на бренд, а не за замовчуванням до вигляду."}, {"label": "Гачки забезпечують цикл", "body": "Гачки агента можуть автоматично запускати перевірки при збереженні — місце, щоб вбудувати крок перевірки чи рев'ю, а не покладатися на те, що агент про нього згадає."}]}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Kiro CLI за замовчуванням не має смаку. Специфікація тримає збірку чесною, але він створює якісний дизайн лише тоді, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Kiro CLI для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Kiro CLI, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Kiro CLI (see kiro.dev/docs/cli for the macOS/Linux/Windows command)\n\n# 2. Authenticate — opens your browser to complete sign-in\nkiro-cli login   # choose Builder ID, Google, GitHub, or your organization\n\n# 3. Confirm you are signed in\nkiro-cli whoami\n\n# 4. Start an interactive session in your project\ncd your-project\nkiro-cli chat\n\n# 5. Wire MCP servers (optional, e.g. for design handoff)\nkiro-cli mcp add ..."}, {"kind": "image", "src": "/agents/kiro-design/kiro-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, автентифікація, додавання керівних файлів, додавання навички, перевірка", "caption": "Послідовність налаштування: встановити → автентифікуватися → додати керівні файли й дизайн-специфікацію → додати навичку → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Розмістіть свої токени, примітиви та конвенції в керівних файлах, тож агент читає їх у кожному запуску, а результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Підключіть Playwright або браузерний MCP-сервер, щоб Kiro рендерив у справжньому браузері й перевіряв свій результат на різних точках перелому, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Kiro CLI — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не співпаде — дозволяючи специфікації спочатку зафіксувати намір, а потім будувати відповідно до неї."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і додавайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Нехай Kiro напише специфікацію й дизайн-документ із вашої підказки та перегляньте план до того, як він будує — саме тут ви ловите проблеми макета й обсягу рано.", "Тримайте свою дизайн-систему та конвенції в керівних файлах і скажіть Kiro, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і нехай Kiro відрендерить у справжньому браузері, змінюючи розмір під точки перелому для перевірки результату.", "Ітеруйте, змушуючи Kiro порівнювати свою реалізацію з референсами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Відкрийте інтерактивну сесію й дайте конкретні обмеження наперед, тож специфікація, яку він пише, відображає ваш справжній намір:"}, {"kind": "code", "lang": "bash", "code": "kiro-cli chat\n# in the prompt:\n> Here are my references: reference-desktop.png and reference-mobile.png.\n  Write a spec, then implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens (see my steering files).\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Тримайте завдання малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Kiro, коли ви відкочуєте), тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "Специфікації, керівні файли, гачки та MCP", "blocks": [{"kind": "p", "text": "Чотири точки розширення роблять Kiro CLI практичним для тривалої дизайнерської роботи, і всі чотири чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Специфікації", "body": "Вимоги, дизайн-документ і послідовний список завдань — довговічний запис того, чим має бути функція, оглядовий до й під час збірки."}, {"label": "Керівні файли", "body": "Додайте контекст, стандарти кодування та бажані робочі процеси чи інструменти, які агент читає в кожному запуску — природний дім для ваших дизайн-конвенцій і токенів."}, {"label": "Гачки агента", "body": "Автоматизації, що спрацьовують на події на кшталт збереження файлу, виконуючи фонові завдання, як-от перевірки чи документацію — місце, щоб автоматично забезпечити крок перевірки."}, {"label": "MCP-сервери", "body": "Kiro CLI керує серверами Model Context Protocol — переносним способом внести зовнішній дизайн-контекст та інструменти, що працюють у різних агентів, а не лише в Kiro."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Kiro проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Kiro CLI", "Робочий процес на основі специфікацій — вимоги, дизайн-документ і список завдань перед кодом; керівні файли та гачки тримають збірки в межах бренду", "Структурованих, оглядових збірок, де намір та обсяг зафіксовані до реалізації"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і дуже великий контекст; відкритий, з безкоштовним рівнем", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Kiro CLI; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту — специфікація тримає збірку в межах завдання, але не надає смаку."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Рендерте й самоперевіряйте на різних точках перелому — підключіть це як гачок, якщо можете — щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила в керівних файлах", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» там, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Kiro CLI всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Kiro CLI як адаптер першої сторони й огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Kiro хорошим, є з першого запуску, а не збирається вручну щоразу. Open Design локальний передусім, що тримає цю пару простою: ваші файли й ваш вхід залишаються на вашій машині."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Kiro CLI як свого агента.", "Автентифікуйтеся своїм AWS Builder ID чи іншим входом — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Kiro CLI, той самий вхід — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Open Design локальний передусім і під ліцензією Apache-2.0, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Kiro CLI справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Kiro CLI створює адаптивний UI продакшн-якості, а його робочий процес на основі специфікацій тримає збірку підзвітною заявленому наміру. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Чи потрібен обліковий запис AWS, щоб використовувати Kiro CLI?", "text": "Ні — Kiro дозволяє входити через AWS Builder ID, Google, GitHub чи вашу організацію (AWS IAM Identity Center), і вам не потрібен обліковий запис AWS для його використання. Kiro в превʼю й безкоштовний для старту. Open Design у будь-якому разі ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Kiro CLI хорошим саме для дизайну?", "text": "Його робочий процес на основі специфікацій: Kiro пише вимоги, дизайн-документ і список завдань ще до того, як кодує, тож ви виправляєте макет і обсяг до того, як збірка зобов'язалася. Керівні файли несуть ваші конвенції, а гачки можуть забезпечувати перевірки — але смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Kiro CLI чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Kiro CLI — його оглядовий робочий процес на основі специфікацій із керівними файлами та гачками. Багато команд використовують обидва — Open Design дозволяє перемикати агентів, не змінюючи свій дизайн-процес."}, {"name": "Як підключити Kiro CLI до зовнішніх дизайн-інструментів?", "text": "Kiro CLI керує серверами Model Context Protocol (MCP) — використовуйте kiro-cli mcp, щоб додати їх. MCP-сервер може внести справжній дизайн-контекст та інструменти в агента, тож згенерований код відповідає джерелу, а не наближається до нього."}, {"name": "Чи пов'язаний Open Design з Amazon або AWS?", "text": "Ні. Kiro — продукт Amazon (AWS); Open Design — незалежний відкритий проєкт, що підтримує його як адаптер першої сторони. Kiro є торговельною маркою Amazon."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і під ліцензією Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваш вхід Kiro використовується безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Kiro CLI відкритим способом.", "ctaBody": "Підключіть власний AWS Builder ID або вхід, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Kiro CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'kilo': {
        ...en['kilo']!,
        title: "Kilo Code для дизайну — Open Design",
        description: "Як люди використовують Kilo Code — відкритий, незалежний від моделі AI-агент для кодування — для UI- та вебдизайну: його режими Architect/Code, підтримку MCP, BYOK у багатьох провайдерів, і як Open Design перетворює Kilo на локальний, відкритий дизайн-агент.",
        breadcrumb: "Kilo",
        label: "Агент · Kilo",
        heading: "Kilo Code для дизайну.",
        lead: "Kilo Code — це відкритий, незалежний від моделі AI-агент для кодування у вашому IDE та CLI. Оскільки ви можете спрямувати його майже на будь-яку модель і підключити власні ключі провайдерів, він стає справжнім інструментом дизайну, щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його у відкритий дизайн-процес: ваші ключі провайдерів, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Kilo Code на локальний, відкритий дизайн-агент — ваші ключі провайдерів, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Kilo Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Kilo Code — це відкритий AI-агент для кодування, що працює у VS Code, IDE JetBrains і терміналі. Дві речі роблять його цікавим саме для дизайну: він незалежний від моделі, тож ви можете керувати ним будь-якою передовою моделлю з підтримкою зору, що найкраще читає скриншот; і він BYOK у багатьох провайдерів, тож ви тримаєте контроль над вартістю й обліковими даними. У парі з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI. Це практичний наскрізний посібник з використання Kilo Code для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Kilo Code, чому незалежний від моделі, відкритий агент підходить дизайну, як налаштувати його з нуля, цикл «скриншот — UI», як його розширюють кастомні правила та MCP, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара, адже обидва є відкритими й працюють на вашій власній машині."], "heroImage": {"src": "/agents/kilo-design/kilo-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Kilo Code: агент в IDE та терміналі читає референсне зображення, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Kilo Code читає ваші референси в IDE чи CLI, будує й перевіряє UI у справжньому браузері та ітерує відповідно до них — з моделлю, яку ви обираєте."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-kilo", "label": "Чим насправді є Kilo Code"}, {"id": "why-design", "label": "Чому відкритий, незалежний від моделі агент підходить дизайну"}, {"id": "setup", "label": "Налаштуйте Kilo Code для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «скриншот — UI»"}, {"id": "extend", "label": "Режими, кастомні правила та MCP"}, {"id": "vs", "label": "Kilo Code проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Kilo Code в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-kilo", "heading": "Чим насправді є Kilo Code", "blocks": [{"kind": "p", "text": "Kilo Code — це відкритий AI-агент для кодування, створений Kilo Code, Inc. Він працює як розширення VS Code, в IDE JetBrains і як інтерфейс командного рядка — читаючи ваш репозиторій, редагуючи файли, виконуючи команди та плануючи й перевіряючи роботу з завдань природною мовою, а не просто доповнюючи рядки. Його визначна риса в тому, що він незалежний від моделі: ви обираєте, яка модель ним керує, і підключаєте власні ключі провайдерів."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Оскільки він незалежний від моделі, ви можете спрямувати його на будь-яку сильну модель із підтримкою зору, що найкраще читає референсний скриншот і міркує про макет. А оскільки він відкритий і BYOK, ви можете інспектувати, який саме контекст надсилається, і тримати облікові дані й вартість під власним контролем."}, {"kind": "steps", "items": [{"label": "Режими агента", "body": "Kilo постачає спеціалізовані режими — Architect для планування, Code для збірки, Debug для виправлення та Ask для запитань — плюс кастомні режими, тож ви можете спланувати дизайн, а потім реалізувати його в окремих, сфокусованих проходах."}, {"label": "Кастомні правила + MCP", "body": "Він читає кастомні правила на рівні проєкту для постійного контексту й підтримує MCP-сервери (з MCP-маркетплейсом), тож ви можете додати зовнішній контекст, як-от живий файл Figma чи дизайн-інструментарій."}, {"label": "Підключіть власні ключі", "body": "Kilo — BYOK у багатьох провайдерів — Anthropic, OpenAI, Google, OpenRouter та інших — або ви можете використовувати власний шлюз Kilo, що надає 500+ моделей за вартістю провайдера."}]}, {"kind": "ul", "items": ["Постачальник: Kilo Code, Inc. (відкритий код)", "Облікові дані: ваш власний API-ключ провайдера (BYOK — Anthropic, OpenAI, Google, OpenRouter та інші) або власний шлюз Kilo", "Ліцензія: відкритий код"]}]}, {"id": "why-design", "heading": "Чому відкритий, незалежний від моделі агент підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Kilo Code походить від відкритості й вибору моделі — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Незалежність від моделі за задумом", "body": "Оскільки ви обираєте модель, ви можете керувати Kilo будь-якою моделлю з підтримкою зору, що найкраще читає референсні скриншоти — і перемкнутися, коли з'явиться краща, не змінюючи робочий процес."}, {"label": "Відкритий та інспектований", "body": "Kilo відкритий, тож ви можете бачити, який саме контекст і підказки надсилаються — корисно, коли ви хочете, щоб агент повторно використовував ваші справжні дизайн-примітиви, а не винаходив одноразові стилі."}, {"label": "Конвенції в кастомних правилах", "body": "Кастомні правила проєкту (плюс MCP-сервер для Figma) спрямовують агента на ваші токени, компоненти та реальні специфікації, тож він працює на бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Kilo Code за замовчуванням не має смаку. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Kilo Code для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Kilo Code, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install the Kilo Code extension from the VS Code\n#    (or JetBrains) marketplace, or install the CLI.\n\n# 2. Open your project and sign in / add a provider key\ncd your-project\nkilo              # connect your provider (BYOK) or Kilo's gateway\n\n# 3. Add project context\n#    create custom rules for this project's design conventions\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add it from the MCP marketplace / MCP settings"}, {"kind": "image", "src": "/agents/kilo-design/kilo-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, автентифікація, додавання кастомних правил, додавання навички, перевірка", "caption": "Послідовність налаштування: встановити → підключити провайдера → додати кастомні правила → додати навичку → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Розмістіть свої токени, примітиви та конвенції в кастомних правилах Kilo і спрямуйте на них агента, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Kilo рендерив у справжньому браузері й перевіряв свій результат на різних точках перелому, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «скриншот — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Kilo Code — це перетворення референсного зображення на робочий адаптивний UI та ітерування, доки воно не співпаде — спираючись на модель із підтримкою зору для порівняння результату з референсом."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і додавайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть із сильною моделлю.", "Тримайте свою дизайн-систему та конвенції в кастомних правилах Kilo і скажіть агенту, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і нехай Kilo відрендерить у справжньому браузері, змінюючи розмір під точки перелому для перевірки результату.", "Ітеруйте, змушуючи Kilo порівнювати свою реалізацію зі скриншотами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Використайте режим Architect, щоб спланувати збірку, потім перемкніться в режим Code й прикріпіть свої референси з конкретними обмеженнями:"}, {"kind": "code", "lang": "bash", "code": "# Plan in Architect mode, then build in Code mode:\n> Implement this design from @reference-desktop.png and\n  @reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens\n  from the custom rules.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the\n  references across breakpoints."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Kilo, коли ви відкочуєте), тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "Режими, кастомні правила та MCP", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Kilo Code практичним для тривалої дизайнерської роботи, і всі три чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Режими (Architect → Code)", "body": "Сплануйте структуру екрана в режимі Architect, потім реалізуйте її в режимі Code й виправте проблеми в режимі Debug — відокремлюючи дизайн-намір від реалізації. Кастомні режими дозволяють закодувати власний прохід дизайн-рев'ю."}, {"label": "Кастомні правила", "body": "Кастомні правила проєкту — це довговічний дім ваших дизайн-конвенцій — токенів, примітивів і контрольних списків рев'ю — що читаються в кожному запуску, тож агент працює на ваш бренд."}, {"label": "MCP-сервери", "body": "Kilo підтримує MCP-сервери через свій маркетплейс — переносний спосіб внести дизайн-контекст і зовнішні інструменти, найбільш релевантно Figma MCP-сервер, що працюють у різних агентів, а не лише в Kilo."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Kilo Code проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Kilo Code", "Відкритий і незалежний від моделі з BYOK у багатьох провайдерів; режими Architect/Code і MCP", "Вибору власної моделі під завдання й тримання вартості й облікових даних під вашим контролем"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1 млн токенів", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Kilo Code; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Використовуйте модель із підтримкою зору, щоб рендерити й самоперевірятися на різних точках перелому, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила в кастомних правилах", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» там, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Kilo Code всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Kilo Code як адаптер першої сторони й огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Kilo хорошим, є з першого запуску, а не збирається вручну щоразу. Обидва відкриті й локальні передусім, що робить цю пару природним вибором."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Kilo Code як свого агента.", "Автентифікуйтеся власним ключем провайдера (BYOK) або шлюзом Kilo — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Kilo Code, ті самі ключі — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Він локальний передусім і відкритий, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Kilo Code справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Kilo Code створює адаптивний UI продакшн-якості, а модель із підтримкою зору перевіряє результат відносно референсів. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Чи потрібно платити, щоб проєктувати з Kilo Code?", "text": "Kilo Code відкритий і безкоштовний для встановлення. Ви підключаєте власний API-ключ провайдера (BYOK) і платите цьому провайдеру безпосередньо або використовуєте власний шлюз Kilo за вартістю провайдера. Open Design у будь-якому разі ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Kilo Code хорошим саме для дизайну?", "text": "Він незалежний від моделі й відкритий, тож ви можете керувати ним будь-якою моделлю з підтримкою зору, що найкраще читає референсні скриншоти, інспектувати, який саме контекст надсилається, і тримати вартість й облікові дані під власним контролем. Смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Kilo Code чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Kilo Code — бути відкритим і незалежним від моделі з BYOK, тож ви обираєте модель. Багато команд використовують обидва — Open Design дозволяє перемикати агентів, не змінюючи свій дизайн-процес."}, {"name": "Як підключити Kilo Code до Figma?", "text": "Додайте Figma MCP-сервер з MCP-маркетплейсу Kilo чи налаштувань MCP. Тоді Kilo може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код відповідає джерелу, а не наближається до нього."}, {"name": "Чи пов'язаний Open Design з Kilo Code?", "text": "Ні. Kilo Code — продукт Kilo Code, Inc.; Open Design — незалежний відкритий проєкт, що підтримує його як адаптер першої сторони. Обидва випадково є відкритими, але це окремі проєкти."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і відкритий. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані провайдера використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Kilo Code відкритим способом.", "ctaBody": "Підключіть власний ключ провайдера, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Kilo Code в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'vibe': {
        ...en['vibe']!,
        title: "Mistral Vibe CLI для дизайну — Open Design",
        description: "Як люди використовують Vibe CLI від Mistral для UI- та вебдизайну — його open-weights моделі кодування Devstral, агентне багатофайлове редагування, config.toml, MCP та ACP — і як Open Design перетворює Vibe CLI на локальний, відкритий дизайн-агент.",
        breadcrumb: "Mistral Vibe CLI",
        label: "Агент · Mistral Vibe CLI",
        heading: "Mistral Vibe CLI для дизайну.",
        lead: "Mistral Vibe CLI — це відкритий термінальний агент для кодування від Mistral AI на основі сімейства моделей Devstral. Він редагує файли, виконує команди й працює через Agent Client Protocol — що робить його справжнім інструментом дизайну, щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його у відкритий дизайн-процес: ваш API-ключ Mistral (BYOK) або локальні моделі, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Mistral Vibe CLI на локальний, відкритий дизайн-агент — ваш API-ключ Mistral або локальні моделі Devstral, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Vibe CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Mistral Vibe CLI — це відкритий (Apache-2.0) агент для кодування в терміналі від Mistral AI. Він сканує структуру файлів вашого проєкту та статус Git для контексту, потім досліджує, редагує й виконує зміни у вашій кодовій базі з завдань природною мовою. Дві речі роблять його цікавим саме для дизайну: він працює на моделях кодування Devstral від Mistral, частині open-weights екосистеми, яку ви можете запускати локально чи в хмарі; і він говорить мовою Agent Client Protocol (ACP), тож вбудовується в редактори й інструменти, а не живе лише в одному терміналі. У парі з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI. Це практичний наскрізний посібник з використання Vibe CLI для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Vibe CLI, чому open-weights агент для кодування підходить дизайну, як налаштувати його з нуля, цикл «референс — UI», як його розширюють config.toml, MCP та ACP, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар — природна пара, адже обидва є відкритими й працюють на вашій власній машині."], "heroImage": {"src": "/agents/vibe-design/vibe-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Mistral Vibe CLI: термінальний агент читає референс, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Vibe CLI читає ваші референси в терміналі, будує й перевіряє UI у справжньому браузері та ітерує відповідно до них — керований моделями кодування Devstral від Mistral."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-vibe", "label": "Чим насправді є Mistral Vibe CLI"}, {"id": "why-design", "label": "Чому open-weights агент для кодування підходить дизайну"}, {"id": "setup", "label": "Налаштуйте Vibe CLI для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «референс — UI»"}, {"id": "extend", "label": "config.toml, MCP та ACP"}, {"id": "vs", "label": "Vibe CLI проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Vibe CLI в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-vibe", "heading": "Чим насправді є Mistral Vibe CLI", "blocks": [{"kind": "p", "text": "Mistral Vibe CLI — це відкритий (Apache-2.0) агент для кодування, який Mistral AI постачає для термінала. Він надає інтерактивний чат-інтерфейс з інструментами для маніпуляції файлами, пошуку коду, контролю версій і виконання команд та автоматично сканує структуру файлів вашого проєкту й статус Git, щоб дати агенту релевантний контекст. Він працює на моделях кодування Devstral від Mistral — плануючи й перевіряючи роботу з завдань природною мовою, а не просто доповнюючи рядки."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Він працює на open-weights сімействі Devstral від Mistral (Devstral 2 і менша Devstral Small 2), тож ви можете запускати агента проти Mistral API в хмарі або проти локальних моделей — корисно для приватної чи офлайн дизайнерської роботи. І він говорить мовою Agent Client Protocol, тож той самий агент може керувати редакторами й інструментами, а не лише однією термінальною сесією."}, {"kind": "steps", "items": [{"label": "Файли конфігурації", "body": "Vibe CLI налаштовується через файл config.toml (на рівні проєкту ./.vibe/config.toml, із запасним варіантом у ~/.vibe/config.toml). Це практичне місце, щоб закодувати ваших провайдерів, вибір моделі та налаштування проєкту."}, {"label": "Вбудовані інструменти + MCP", "body": "Він постачає інструменти роботи з файлами, пошуку, контролю версій і виконання команд та підтримує MCP-сервери (налаштовані в секції [[mcp_servers]]), щоб додати зовнішній контекст, як-от живий файл Figma."}, {"label": "BYOK або локально", "body": "Автентифікуйтеся API-ключем Mistral з консолі Mistral або спрямуйте його на локальні/сумісні моделі, тож він працює повністю офлайн."}]}, {"kind": "ul", "items": ["Постачальник: Mistral AI", "Облікові дані: API-ключ Mistral (BYOK) з консолі Mistral або локальні / сумісні моделі", "Ліцензія: Apache-2.0, відкритий код"]}]}, {"id": "why-design", "heading": "Чому open-weights агент для кодування підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Vibe CLI походить від його open-weights сімейства моделей і його охоплення протоколів — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Моделі кодування Devstral", "body": "Vibe працює на сімействі Devstral від Mistral, налаштованих на кодування моделях, побудованих для агентної, багатофайлової роботи — тож агент редагує в межах справжньої фронтенд-кодової бази, а не видає ізольовані фрагменти."}, {"label": "Open-weights і дружній до локального", "body": "Devstral Small 2 достатньо мала, щоб працювати на споживчому обладнанні, тож дизайнерська робота може лишатися повністю локальною й офлайн — референси й код ніколи не мусять залишати вашу машину."}, {"label": "Конвенції в config.toml + контекст", "body": "Конфігурація проєкту та ваші власні інструкції спрямовують агента на ваші токени, компоненти та реальні специфікації, тож він працює на бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Vibe CLI за замовчуванням не має смаку. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Vibe CLI для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Vibe CLI, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Mistral Vibe CLI\nuv tool install mistral-vibe\n# or: pip install mistral-vibe\n\n# 2. Run the setup wizard to register your API key\nvibe --setup     # saves config to ~/.vibe/config.toml and ~/.vibe/.env\n#    or set it directly:  export MISTRAL_API_KEY=...\n\n# 3. Start Vibe in your project\ncd your-project\nvibe\n\n# 4. Wire the Figma MCP server (optional, for design handoff)\n#    add an [[mcp_servers]] entry in your config.toml"}, {"kind": "image", "src": "/agents/vibe-design/vibe-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, автентифікація, налаштування config.toml, додавання навички, перевірка", "caption": "Послідовність налаштування: встановити → автентифікуватися → налаштувати config.toml → додати навичку → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Тримайте свої токени, примітиви та конвенції там, де агент їх читає, і спрямуйте на них Vibe, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду."}, {"label": "Додайте перевірку у браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Vibe рендерив у справжньому браузері й перевіряв свій результат на різних точках перелому, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «референс — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Vibe CLI — це перетворення чіткого референсу на робочий адаптивний UI та ітерування, доки воно не співпаде — спираючись на інструменти агента, щоб рендерити, інспектувати й виправляти власний результат."}, {"kind": "ol", "items": ["Починайте з найчіткіших референсів, які у вас є — і описуйте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть із сильною моделлю.", "Тримайте свою дизайн-систему та конвенції там, де Vibe їх читає, і скажіть йому, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і нехай Vibe відрендерить у справжньому браузері, змінюючи розмір під точки перелому для перевірки результату.", "Ітеруйте, змушуючи Vibe порівнювати свою реалізацію з референсами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Посилайтеся на файли через @ (Vibe автодоповнює шляхи до файлів) і керуйте slash-командами через /, потім дайте конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "vibe\n# in the prompt:\n> @design-spec.md @tokens.css\n  Implement this design in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Run the dev server, render it in the browser, and iterate until\n  it matches the references across breakpoints."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Vibe, коли ви відкочуєте), тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "config.toml, MCP та ACP", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Vibe CLI практичним для тривалої дизайнерської роботи, і всі три чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "config.toml", "body": "Правила проєкту та налаштування провайдера/моделі живуть у config.toml (на рівні проєкту, із запасним варіантом ~/.vibe). Це довговічний дім того, як агент вбудований у ваш проєкт, що читається в кожному запуску."}, {"label": "MCP-сервери", "body": "Налаштуйте MCP-сервери у вашому config.toml ([[mcp_servers]], із транспортами HTTP, streamable-HTTP і stdio) — переносний спосіб внести дизайн-контекст і зовнішні інструменти, найбільш релевантно Figma MCP-сервер, що працюють у різних агентів, а не лише в Vibe."}, {"label": "Agent Client Protocol", "body": "Vibe говорить мовою ACP, тож тим самим агентом можна керувати з редакторів та інших ACP-клієнтів. Саме так Open Design його інтегрує — через ACP за допомогою бінарника vibe-acp."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Vibe CLI проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Mistral Vibe CLI", "Open-weights моделі кодування Devstral, які можна запускати локально; Apache-2.0 та ACP-нативний", "Приватної чи офлайн дизайнерської роботи й open-weights стеку"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і дуже велике вікно контексту", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Vibe CLI; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Нехай Vibe рендерить і самоперевіряється на різних точках перелому, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила в конфігурації та контексті", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» там, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Vibe CLI всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Mistral Vibe CLI як адаптер першої сторони — керуючи ним через ACP за допомогою бінарника vibe-acp — і огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI. Тож дизайн-контекст, що робить Vibe хорошим, є з першого запуску, а не збирається вручну щоразу. Обидва відкриті й локальні передусім, що робить цю пару природним вибором."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Mistral Vibe CLI як свого агента.", "Автентифікуйтеся своїм API-ключем Mistral (BYOK) або спрямуйте Vibe на локальні моделі — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Vibe CLI, той самий ключ — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Він локальний передусім і під ліцензією Apache-2.0, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Mistral Vibe CLI справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсами в контексті Vibe CLI створює адаптивний UI продакшн-якості, а його моделі Devstral редагують у межах справжньої фронтенд-кодової бази. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Як автентифікувати Vibe CLI?", "text": "Запустіть майстер налаштування через vibe --setup, щоб зареєструвати API-ключ Mistral (з консолі Mistral), або встановіть MISTRAL_API_KEY у своєму середовищі. Він також може працювати проти локальних чи сумісних моделей, повністю офлайн. Open Design у будь-якому разі ніколи не проксіює ваші облікові дані."}, {"name": "Що робить Vibe CLI хорошим саме для дизайну?", "text": "Це Apache-2.0, ACP-нативний агент на основі open-weights моделей кодування Devstral від Mistral — тож ви можете запускати його локально для приватної роботи й редагувати в межах справжньої кодової бази. Але смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Vibe CLI чи Claude Code для фронтенд-дизайну?", "text": "Обидва сильні. Claude Code відомий конкретними дизайн-рішеннями з урахуванням кодової бази; перевага Vibe CLI — open-weights стек Devstral, який можна запускати локально, та ліцензія Apache-2.0. Багато команд використовують обидва — Open Design дозволяє перемикати агентів, не змінюючи свій дизайн-процес."}, {"name": "Як підключити Vibe CLI до Figma?", "text": "Додайте Figma MCP-сервер як запис [[mcp_servers]] у вашому config.toml. Тоді Vibe може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код відповідає джерелу, а не наближається до нього."}, {"name": "Чи пов'язаний Open Design з Mistral AI?", "text": "Ні. Mistral Vibe CLI — продукт Mistral AI; Open Design — незалежний відкритий проєкт, що підтримує його як адаптер першої сторони, керований через ACP. Mistral є торговельною маркою Mistral AI."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і під ліцензією Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Mistral використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Mistral Vibe CLI відкритим способом.", "ctaBody": "Підключіть власний API-ключ Mistral або локальні моделі, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Vibe CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
      'qoder': {
        ...en['qoder']!,
        title: "Qoder CLI для дизайну — Open Design",
        description: "Як люди використовують Qoder CLI — агентну платформу кодування від Alibaba — для UI- та вебдизайну: її режими agent і quest, глибоке розуміння репозиторію й repo wiki, та рівні моделей Lite/Efficient/Auto — і як Open Design перетворює Qoder CLI на локальний, відкритий дизайн-агент.",
        breadcrumb: "Qoder CLI",
        label: "Агент · Qoder CLI",
        heading: "Qoder CLI для дизайну.",
        lead: "Qoder CLI — це термінальний агент Qoder, агентної платформи кодування від Alibaba. Він розуміє весь репозиторій — архітектуру, патерни та конвенції, зафіксовані в його repo wiki — і виконує автономну роботу на основі специфікацій, що робить його справжнім інструментом дизайну, щойно ви даєте йому референси, конвенції та цикл перевірки. Open Design вбудовує його у відкритий дизайн-процес: ваш обліковий запис Qoder, ваші файли, локально передусім.",
        rich: {"heroCtaLead": "Open Design перетворює Qoder CLI на локальний, відкритий дизайн-агент — ваш обліковий запис Qoder, ваші файли, кураторська бібліотека навичок і дизайн-систем навколо нього.", "heroCtaActions": [{"label": "Використовуйте Qoder CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "intro": ["Qoder CLI — це термінальний агент Qoder, агентної платформи кодування від Alibaba. Дві речі роблять його цікавим саме для дизайну: він будує глибокий контекст вашого репозиторію — архітектуру, патерни проєктування й конвенції, які він дистилює у вікі репозиторію — тож повторно використовує ваші справжні примітиви замість винаходу одноразових стилів; і він виконує автономні quest'и на основі специфікацій, що планують, реалізують і перевіряють завдання від початку до кінця, а не просто доповнюють рядки. У парі з правильними референсами, конвенціями та циклом перевірки він будує справжній адаптивний UI. Це практичний наскрізний посібник з використання Qoder CLI для UI, фронтенду та роботи з дизайн-системами, а також з його вбудовування у структурований дизайн-процес з Open Design.", "Він охоплює те, чим насправді є Qoder CLI, чому його розуміння репозиторію та агентні quest'и підходять дизайну, як налаштувати його з нуля, цикл «референс — UI», як його розширюють правила, MCP та repo wiki, як він порівнюється з Codex, Claude Code, Cursor і Gemini CLI, пастки, через які результат AI виглядає шаблонним, і як Open Design закриває цю прогалину як відкритий, локальний дизайн-шар навколо агента, яким ви вже користуєтеся."], "heroImage": {"src": "/agents/qoder-design/qoder-design-hero.webp", "alt": "Цикл дизайнерського зворотного зв'язку Qoder CLI: термінальний агент читає референсне зображення з контекстом repo wiki, браузер відображає UI, а робочий простір з петлею стрілки зворотного зв'язку", "caption": "Основний цикл: Qoder CLI читає ваші референси й контекст репозиторію в терміналі, будує й перевіряє UI у справжньому браузері та ітерує відповідно до них."}, "tocLabel": "На цій сторінці", "toc": [{"id": "what-is-qoder", "label": "Чим насправді є Qoder CLI"}, {"id": "why-design", "label": "Чому агентність + контекст репозиторію підходять дизайну"}, {"id": "setup", "label": "Налаштуйте Qoder CLI для дизайну (з нуля)"}, {"id": "screenshot-workflow", "label": "Робочий процес «референс — UI»"}, {"id": "extend", "label": "Правила, MCP та repo wiki"}, {"id": "vs", "label": "Qoder CLI проти Codex, Claude Code, Cursor і Gemini CLI"}, {"id": "pitfalls", "label": "Пастки та вигляд «AI-шаблону»"}, {"id": "open-design", "label": "Дизайн з Qoder CLI в Open Design"}, {"id": "faq", "label": "Часті запитання"}], "sections": [{"id": "what-is-qoder", "heading": "Чим насправді є Qoder CLI", "blocks": [{"kind": "p", "text": "Qoder — це агентна платформа кодування від Alibaba — середовище розробки на основі AI, доступне як десктопний застосунок і CLI, що розуміє справжні кодові бази й опрацьовує задачі розробки від початку до кінця. Qoder CLI приносить цей рушій у термінал: він читає ваш репозиторій, редагує файли, виконує shell-команди й опрацьовує завдання з природної мови, а не просто доповнює рядки. Вхід здійснюється з обліковим записом Qoder."}, {"kind": "p", "text": "Для дизайнерської роботи виділяються дві властивості. Qoder будує глибокий контекст вашого репозиторію — архітектуру, патерни проєктування й конвенції, дистильовані у вікі репозиторію — тож він заземлює результат у ваших справжніх примітивах. І він виконує агентний робочий процес на основі специфікацій: ви окреслюєте, чого хочете, а він планує, реалізує й перевіряє роботу, зокрема в кілька кроків."}, {"kind": "steps", "items": [{"label": "Режими Agent і Quest", "body": "Режим Agent — це розмовне парне програмування з контрольними точками за участю людини; режим Quest делегує довшу, багатокрокову роботу автономному агенту, що планує, реалізує й самоперевіряється — природне місце, щоб передати дизайн-завдання на основі специфікації."}, {"label": "Repo wiki + MCP", "body": "Qoder дистилює вашу кодову базу у вікі репозиторію з архітектури й конвенцій та підтримує MCP-сервери, щоб внести зовнішній контекст, як-от живий файл Figma."}, {"label": "Рівні моделей", "body": "Qoder CLI надає рівні Lite, Efficient і Auto; Auto дозволяє своєму планувальнику обирати модель під завдання, тож ви не керуєте вибором моделі вручну."}]}, {"kind": "ul", "items": ["Постачальник: Alibaba", "Облікові дані: обліковий запис Qoder (вхід через браузер або персональний токен доступу Qoder для неінтерактивного використання)", "Рівні моделей: Lite, Efficient, Auto"]}]}, {"id": "why-design", "heading": "Чому агентний агент із урахуванням репозиторію підходить дизайну", "blocks": [{"kind": "p", "text": "Дизайнерська перевага Qoder CLI походить від двох властивостей — але, як і з кожним агентом, смак усе одно потрібно надати."}, {"kind": "steps", "items": [{"label": "Глибоке розуміння репозиторію", "body": "Оскільки Qoder будує контекст усієї вашої кодової бази й дистилює його у repo wiki, агент повторно використовує ваші наявні компоненти й токени замість винаходу одноразових стилів для кожного екрана."}, {"label": "Автономні quest'и на основі специфікацій", "body": "Режим Quest перетворює письмову специфікацію на спланований, реалізований і самоперевірений результат, тож дизайн-завдання виконується від початку до кінця, а не зупиняється на першому чернетковому варіанті."}, {"label": "Конвенції, які читає агент", "body": "Правила проєкту (плюс Figma MCP-сервер) спрямовують агента на ваші токени, компоненти та реальні специфікації, тож він працює на бренд, а не за замовчуванням до вигляду."}]}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-taste-triangle.webp", "alt": "Діаграма, що показує, як дизайн-система, навичка та референсне зображення сходяться у якісний дизайнерський результат", "caption": "Смак походить від трьох наданих вами вхідних даних: дизайн-системи, навички та справжніх референсних зображень."}, {"kind": "p", "text": "Урок той самий, якого вчить кожен агент: Qoder CLI за замовчуванням не має смаку. Він створює якісний дизайн, коли ви даєте йому обмеження — дизайн-систему, естетичну навичку та конкретні референси. Open Design пакує саме ці вхідні дані, тому ці двоє пасують одне одному (докладніше нижче)."}]}, {"id": "setup", "heading": "Налаштуйте Qoder CLI для дизайнерської роботи з нуля", "blocks": [{"kind": "p", "text": "Ось повний шлях від чистої машини до Qoder CLI, який може будувати та перевіряти UI."}, {"kind": "code", "lang": "bash", "code": "# 1. Install Qoder CLI (Node 20+)\nnpm install -g @qoder-ai/qodercli\n# (macOS/Linux via Homebrew also available)\n\n# 2. Verify the install\nqodercli --version\n\n# 3. Start it in your project and sign in on first run\ncd your-project\nqodercli          # then /login — sign in via browser or a Qoder access token\n\n# 4. Pick a model tier for the session\n#    Lite, Efficient, or Auto (Auto lets the scheduler choose per task)"}, {"kind": "image", "src": "/agents/qoder-design/qoder-design-setup-flow.webp", "alt": "П'ятикроковий процес налаштування: встановлення, автентифікація, налаштування правил, додавання навички, перевірка", "caption": "Послідовність налаштування: встановити → увійти → налаштувати правила проєкту → додати навичку → увімкнути перевірку у браузері."}, {"kind": "steps", "items": [{"label": "Закодуйте свої правила дизайну", "body": "Розмістіть свої токени, примітиви та конвенції там, де агент їх читає, тож результат відповідає бренду, а не за замовчуванням до шаблонного вигляду. Repo wiki Qoder допомагає тримати цей контекст актуальним."}, {"label": "Додайте перевірку у браузері", "body": "Підключіть Playwright або браузерний MCP, щоб Qoder рендерив у справжньому браузері й перевіряв свій результат на різних точках перелому, а не лише підтверджував, що збірка проходить."}]}]}, {"id": "screenshot-workflow", "heading": "Робочий процес «референс — UI»", "blocks": [{"kind": "p", "text": "Найбільш важелевий дизайн-цикл з Qoder CLI — це перетворення референсу на робочий адаптивний UI та ітерування, доки воно не співпаде — спираючись на контекст репозиторію агента й справжній цикл перевірки для порівняння результату з референсом."}, {"kind": "ol", "items": ["Починайте з найчіткіших візуальних референсів, які у вас є — і додавайте кілька станів (десктоп і мобільний, наведення, порожній, завантаження), а не лише один головний кадр.", "Будьте конкретні в підказці; розпливчасті підказки дають шаблонний UI навіть зі спроможним агентом.", "Спрямуйте Qoder на свою дизайн-систему та конвенції й скажіть йому, де знаходяться токени й канонічні примітиви.", "Запустіть dev-сервер і нехай Qoder відрендерить у справжньому браузері, змінюючи розмір під точки перелому для перевірки результату.", "Ітеруйте, змушуючи Qoder порівнювати свою реалізацію з референсами — а не просто підтверджувати, що вона збирається."]}, {"kind": "p", "text": "Запишіть завдання як чітку специфікацію й дайте quest'у провести його, надаючи конкретні обмеження:"}, {"kind": "code", "lang": "bash", "code": "qodercli\n# in the prompt:\n> Implement this design from reference-desktop.png and\n  reference-mobile.png in React + Vite + Tailwind + TypeScript.\n  Reuse my existing design-system components and tokens.\n  Match spacing, layout, and hierarchy; make it responsive.\n  Render it in the browser and iterate until it matches the references\n  across breakpoints."}, {"kind": "p", "text": "Тримайте підказки малими та сфокусованими, комітьте вдалі ітерації та відкочуйте невдалі (повідомляючи Qoder, коли ви відкочуєте), тож кожен прохід будується на чистій основі."}]}, {"id": "extend", "heading": "Правила, MCP та repo wiki", "blocks": [{"kind": "p", "text": "Три точки розширення роблять Qoder CLI практичним для тривалої дизайнерської роботи, і всі три чітко лягають на відкритий дизайн-процес."}, {"kind": "steps", "items": [{"label": "Правила проєкту", "body": "Закодуйте свої дизайн-конвенції як довговічні правила проєкту, які агент читає в кожному запуску — дім для токенів, примітивів і контрольних списків рев'ю."}, {"label": "MCP-сервери", "body": "MCP — це переносний спосіб внести дизайн-контекст і зовнішні інструменти, найбільш релевантно Figma MCP-сервер, і він працює в різних агентів, а не лише в Qoder."}, {"label": "Repo wiki", "body": "Вікі репозиторію Qoder автоматично дистилює архітектуру й конвенції, тож агент продовжує повторно використовувати ваші справжні компоненти замість того, щоб перевчати кодову базу в кожному завданні."}]}, {"kind": "p", "text": "Це переносні, мультиагентні можливості — саме те, що Open Design створений оркеструвати, а не відтворювати в кожному проєкті."}]}, {"id": "vs", "heading": "Qoder CLI проти Codex, Claude Code, Cursor і Gemini CLI для дизайну", "blocks": [{"kind": "p", "text": "Немає єдиного переможця для дизайнерської роботи — кожен агент має різну сильну сторону, і досвідчені команди поєднують їх. Чесне зведення:"}, {"kind": "table", "columns": ["Агент", "Дизайнерська сила", "Найкраще для"], "rows": [["Qoder CLI", "Глибоке розуміння репозиторію з repo wiki та автономними quest'ами на основі специфікацій; рівні Lite/Efficient/Auto", "Роботи з великим контекстом репозиторію й делегування багатокрокових збірок на основі специфікацій"], ["Codex", "Сильний візуальний полиск із фронтенд-навичкою; ізольовані асинхронні збірки", "Делегованих асинхронних збірок і переносних правил AGENTS.md"], ["Claude Code", "Конкретні дизайн-рішення (hex, відступи, типографіка) і UX з урахуванням кодової бази", "Фронтенд-міркувань і рефакторингів із великим контекстом"], ["Cursor", "Візуальний цикл «збудуй і поглянь» із живим попереднім переглядом та інлайн-правками", "Щільної роботи над UI в режимі «ітеруй і спостерігай» усередині IDE"], ["Gemini CLI", "Сильне мультимодальне розуміння зображень і контекст на 1 млн токенів; безкоштовний рівень", "Роботи з великою кількістю скриншотів і утримання цілої дизайн-системи в контексті"]]}, {"kind": "p", "text": "Повторюваний вердикт спільноти: смак походить від людей — усі вони за замовчуванням переходять до шаблонної естетики без навичок, референсів та обмежень. Це і є справжня проблема, яку треба вирішити — і вона має форму інструмента дизайну, а не моделі."}]}, {"id": "pitfalls", "heading": "Пастки та як уникнути вигляду «AI-шаблону»", "blocks": [{"kind": "p", "text": "Найпоширеніша скарга на згенерований AI дизайн — що він виглядає шаблонно: м'які градієнти, плаваючі панелі, надмірно округлені кути, драматичні тіні, вайб «Inter-і-фіолетовий», який «кричить, що це зробив AI». Серед інших повідомлених проблем — зламані мобільні макети та інструкції, що просочуються в текст UI. Жодна з цих проблем не унікальна для Qoder CLI; так трапляється, коли будь-який агент працює без кураторського дизайн-контексту."}, {"kind": "steps", "items": [{"label": "Додайте естетичну навичку", "body": "Кураторська дизайн-навичка змушує агента зобов'язатися до реального напрямку замість вигляду за замовчуванням."}, {"label": "Перевіряйте у справжньому браузері", "body": "Рендерте й самоперевіряйте на різних точках перелому, щоб макети не ламалися мовчки на мобільному."}, {"label": "Надайте токени та референси", "body": "Справжні дизайн-токени та референсні скриншоти — це найбільший важіль якості результату."}, {"label": "Закодуйте правила, які читає агент", "body": "Розмістіть правила стилю на кшталт «без головних карток, максимум два шрифти, ієрархія від бренду» у правилах проєкту та repo wiki, де агент читає їх щоразу."}]}, {"kind": "p", "text": "Зверніть увагу: кожне пом'якшення стосується надання агенту кураторського дизайн-контексту. Підтримувати цей контекст вручну для кожного проєкту — саме та рутина, яку усуває Open Design."}]}, {"id": "open-design", "heading": "Дизайн з Qoder CLI всередині Open Design", "blocks": [{"kind": "p", "text": "Open Design — це відкритий дизайн-шар, якого постійно потребує наведений вище процес. Він розглядає Qoder CLI як адаптер першої сторони й огортає його кураторською бібліотекою навичок і дизайн-систем, структурованим конвеєром рендерингу та локальним десктопним UI — тож дизайн-контекст, що робить Qoder хорошим, є з першого запуску, а не збирається вручну щоразу. Open Design локальний передусім, тож ваша робота залишається на вашій власній машині."}, {"kind": "ol", "items": ["Встановіть Open Design і виберіть Qoder CLI як свого агента.", "Автентифікуйтеся своїм обліковим записом Qoder — облікові дані залишаються на вашій машині й ніколи не проксіюються через нас.", "Виберіть дизайн-систему та навичку, а потім генеруйте презентації, прототипи й лендінги з послідовним смаком.", "Кожен артефакт і файл DESIGN.md живе у вашому власному репозиторії, а не в хостингованій хмарі."]}, {"kind": "p", "text": "Той самий агент Qoder CLI, той самий обліковий запис — плюс справжній, переносний, відкритий дизайн-процес навколо нього. Він локальний передусім і під ліцензією Apache-2.0, тож ніщо з вашої роботи чи облікових даних не залишає вашу машину."}]}], "faqTitle": "Часті запитання", "faq": [{"name": "Чи може Qoder CLI справді робити дизайнерську роботу?", "text": "Так — з естетичною навичкою, дизайн-системою та реальними референсними зображеннями в контексті Qoder CLI створює адаптивний UI продакшн-якості, а його глибоке розуміння репозиторію допомагає йому повторно використовувати ваші справжні компоненти. Без цього контексту він схильний за замовчуванням переходити до шаблонного вигляду — це і є прогалина, яку заповнює Open Design."}, {"name": "Як автентифікувати Qoder CLI?", "text": "Запустіть qodercli і використайте /login, щоб увійти з обліковим записом Qoder через браузер, або надайте персональний токен доступу Qoder для неінтерактивних середовищ. Open Design ніколи не проксіює ваші облікові дані — агент використовує їх безпосередньо."}, {"name": "Що робить Qoder CLI хорошим саме для дизайну?", "text": "Дві речі: він будує глибокий контекст вашого репозиторію — архітектуру, конвенції та repo wiki — тож повторно використовує ваші справжні примітиви, а його quest'и на основі специфікацій виконують дизайн-завдання від початку до кінця. Обидва допомагають, але смак усе одно походить від дизайн-системи, навички та референсів, які ви надаєте."}, {"name": "Що таке рівні моделей Lite, Efficient і Auto?", "text": "Qoder CLI дозволяє обрати рівень моделі: Lite, Efficient чи Auto. Auto дозволяє планувальнику Qoder обирати модель під завдання, тож ви не керуєте вибором моделі вручну. Виберіть рівень, що пасує задачі; Auto — розумний варіант за замовчуванням."}, {"name": "Як підключити Qoder CLI до Figma?", "text": "Додайте Figma MCP-сервер до конфігурації MCP Qoder. Тоді Qoder може витягувати справжній дизайн-контекст — компоненти, змінні, дані макета — тож згенерований код відповідає джерелу, а не наближається до нього."}, {"name": "Чи пов'язаний Open Design з Qoder або Alibaba?", "text": "Ні. Qoder — продукт Alibaba; Open Design — незалежний відкритий проєкт, що підтримує його як адаптер першої сторони. Qoder є торговельною маркою свого відповідного власника."}, {"name": "Чи безпечні мої файли та облікові дані?", "text": "Так — Open Design локальний передусім і під ліцензією Apache-2.0. Ваші файли, артефакти та DESIGN.md залишаються у вашому власному репозиторії, а ваші облікові дані Qoder використовуються безпосередньо вашим агентом, ніколи не маршрутизуючись через сервери Open Design."}], "ctaTitle": "Проєктуйте з Qoder CLI відкритим способом.", "ctaBody": "Підключіть власний обліковий запис Qoder, тримайте кожен файл локально й отримайте кураторську дизайн-бібліотеку навколо агента, яким ви вже користуєтеся.", "ctaActions": [{"label": "Використовуйте Qoder CLI в Open Design", "href": "/quickstart/", "variant": "primary"}, {"label": "Зірка на GitHub", "href": "https://github.com/nexu-io/open-design", "variant": "ghost", "external": true}, {"label": "Завантажити десктопний застосунок", "href": "https://github.com/nexu-io/open-design/releases", "variant": "ghost", "external": true}], "hubLinkLabel": "Переглянути всіх підтримуваних агентів"},
      },
    },
  };
}
